import type { PublicCard } from '../../../types';

export const anatomyCards: PublicCard[] = [
  { id: 'dc-anatomy-0001', deck_id: 'deck-anatomy', front: 'Femur', back: 'The thigh bone; the longest and strongest bone in the human body, connecting the hip to the knee.', sort_order: 1 , front_translations: {"es":"Fémur","de":"Femur","fr":"Fémur","tr":"Femur","nl":"Femur","ru":"Бедренная кость","zh":"股骨","pt_BR":"Fêmur","pt_PT":"Fémur"}, back_translations: {"es":"El hueso de la muslo; el más ancho y fuerte del cuerpo humano, conectando el cadera al rodilla.","de":"Der Oberschenkelknochen; der längste und stärkste Knochen im menschlichen Körper, der die Hüfte mit dem Knie verbindet.","fr":"L'os de la cuisse ; le plus long et le plus solide de l'organisme, reliant la hanche au genou.","tr":"Uyluk kemiği; vücudun en uzun ve en güçlü kemiği olup kalçayı dize bağlar.","nl":"Het dijbeen; het langste en sterkste bot in het menselijk lichaam, dat de heup met de knie verbindt.","ru":"Бедренная кость; самая длинная и крепкая кость тела, соединяющая тазобедренный сустав с коленом.","zh":"大腿骨；人体最长、最强壮的骨骼，连接髋部与膝盖。","pt_BR":"O osso da coxa; o mais longo e forte do corpo humano, conectando o quadril ao joelho.","pt_PT":"O osso da coxa; o mais longo e resistente do corpo humano, ligando a anca ao joelho."}},
  { id: 'dc-anatomy-0002', deck_id: 'deck-anatomy', front: 'Tibia', back: 'The larger of the two lower leg bones, commonly called the shin bone; it bears most of the body\'s weight.', sort_order: 2 , front_translations: {"es":"Tíbia","de":"Tibia","fr":"Tibia","tr":"Tibia","nl":"Tibia","ru":"Большеберцовая кость","zh":"胫骨","pt_BR":"Tíbia","pt_PT":"Tíbia"}, back_translations: {"es":"El mayor de los de los huesos de la pierna, comúnmente llamado de tíbia; suporta a mayor parte del peso corporal.","de":"Der größere der beiden Unterschenkelknochen, auch Schienbein genannt; trägt den Großteil des Körpergewichts.","fr":"Le plus grand des deux os de la jambe, communément appelé tibia ; il supporte la majeure partie du poids du corps.","tr":"Alt bacağın iki kemiğinden büyük olanı, kaval kemiği olarak bilinir; vücut ağırlığının büyük bölümünü taşır.","nl":"Het grotere van de twee onderbeen botten, ook wel het scheenbeen genoemd; het draagt het grootste deel van het lichaamsgewicht.","ru":"Большая из двух костей голени, называемая большеберцовой; несёт основную нагрузку тела.","zh":"小腿两块骨骼中较大的一块，俗称胫骨；承载身体大部分重量。","pt_BR":"O maior dos dois ossos da perna, comumente chamado de tíbia; suporta a maior parte do peso corporal.","pt_PT":"O maior dos dois ossos da perna, comumente chamado de tíbia; suporta a maior parte do peso corporal."}},
  { id: 'dc-anatomy-0003', deck_id: 'deck-anatomy', front: 'Humerus', back: 'The upper arm bone, running from the shoulder to the elbow; articulates with the scapula and radius/ulna.', sort_order: 3 , front_translations: {"es":"Úmero","de":"Humerus","fr":"Humérus","tr":"Humerus","nl":"Humerus","ru":"Плечевая кость","zh":"肱骨","pt_BR":"Úmero","pt_PT":"Úmero"}, back_translations: {"es":"El hueso del brazo superior, que vai del hombro al codo; articula-se con a escápula y el rádio/ulna.","de":"Der Oberarmknochen, der von der Schulter bis zum Ellenbogen verläuft; artikuliert mit dem Schulterblatt sowie Speiche und Elle.","fr":"L'os du bras supérieur, reliant l'épaule au coude ; il s'articule avec l'omoplate, le radius et l'ulna.","tr":"Omuzdan dirsege kadar uzanan üst kol kemiği; skapula ve radius/ulna ile eklem yapar.","nl":"Het bovenarmbot, dat van de schouder naar de elleboog loopt; articuleert met het schouderblad en het spaakbeen/ellepijp.","ru":"Кость плеча, идущая от плечевого сустава до локтя; сочленяется с лопаткой, лучевой и локтевой костями.","zh":"上臂骨，从肩部延伸至肘部；与肩胛骨及桡骨/尺骨形成关节。","pt_BR":"O osso do braço superior, que vai do ombro ao cotovelo; articula-se com a escápula e o rádio/ulna.","pt_PT":"O osso do braço superior, que vai do ombro ao cotovelo; articula-se com a omoplata e o rádio/cúbito."}},
  { id: 'dc-anatomy-0004', deck_id: 'deck-anatomy', front: 'Patella', back: 'The kneecap; a small, flat, triangular sesamoid bone embedded in the quadriceps tendon, protecting the knee joint.', sort_order: 4 , front_translations: {"es":"Patela","de":"Patella","fr":"Rotule","tr":"Patella","nl":"Patella","ru":"Надколенник","zh":"髌骨","pt_BR":"Patela","pt_PT":"Rótula"}, back_translations: {"es":"La rótula; un pequeño hueso sesamoide triangular y plano incrustado en el tendón del quadríceps, protegiendo a articulación del rodilla.","de":"Die Kniescheibe; ein kleiner, flacher, dreieckiger Sesambein, der in die Quadrizepssehne eingebettet ist und das Kniegelenk schützt.","fr":"Le genou ; un petit os sésamoïde triangulaire et plat enchâssé dans le tendon quadricipital, protégeant l'articulation du genou.","tr":"Diz kapağı; kuadriseps tendonuna gömülü küçük, düz, üçgen biçimli bir sesamoid kemik olup diz eklemini korur.","nl":"De knieschijf; een klein, plat, driehoekig sesambeentje dat in de quadricepspees is ingebed en het kniegewricht beschermt.","ru":"Коленная чашечка; небольшая плоская треугольная сесамовидная кость в сухожилии четырёхглавой мышцы, защищающая коленный сустав.","zh":"膝盖骨；嵌入股四头肌腱中的小型扁平三角形籽骨，保护膝关节。","pt_BR":"A rótula; um pequeno osso sesamoide triangular e plano embutido no tendão do quadríceps, protegendo a articulação do joelho.","pt_PT":"A rótula; um pequeno osso sesamoide triangular e plano embutido no tendão do quadríceps, protegendo a articulação do joelho."}},
  { id: 'dc-anatomy-0005', deck_id: 'deck-anatomy', front: 'Clavicle', back: 'The collarbone; an S-shaped bone that connects the shoulder blade to the sternum and stabilizes the shoulder girdle.', sort_order: 5 , front_translations: {"es":"Clavícula","de":"Klavikula","fr":"Clavicule","tr":"Klavikula","nl":"Sleutelbeen","ru":"Ключица","zh":"锁骨","pt_BR":"Clavícula","pt_PT":"Clavícula"}, back_translations: {"es":"La clavícula; un hueso en forma de S que conecta a escápula al esterno y estabiliza a cintura escapular.","de":"Das Schlüsselbein; ein S-förmiger Knochen, der das Schulterblatt mit dem Brustbein verbindet und den Schultergürtel stabilisiert.","fr":"La clavicule ; un os en forme de S reliant l'omoplate au sternum et stabilisant la ceinture scapulaire.","tr":"Köprücük kemiği; omuz bıçağını sternuma bağlayan ve omuz kuşağını stabilize eden S şeklinde bir kemik.","nl":"Het sleutelbeen; een S-vormig bot dat het schouderblad met het borstbeen verbindt en de schoudergordel stabiliseert.","ru":"Ключица; S-образная кость, соединяющая лопатку с грудиной и стабилизирующая плечевой пояс.","zh":"锁骨；S形骨骼，连接肩胛骨与胸骨，稳定肩带。","pt_BR":"A clavícula; um osso em forma de S que conecta a escápula ao esterno e estabiliza a cintura escapular.","pt_PT":"A clavícula; um osso em forma de S que liga a omoplata ao esterno e estabiliza a cintura escapular."}},
  { id: 'dc-anatomy-0006', deck_id: 'deck-anatomy', front: 'Sternum', back: 'The breastbone; a flat bone in the center of the chest that connects the ribs via cartilage to form the rib cage.', sort_order: 6 , front_translations: {"es":"Esterno","de":"Sternum","fr":"Sternum","tr":"Sternum","nl":"Borstbeen","ru":"Грудина","zh":"胸骨","pt_BR":"Esterno","pt_PT":"Esterno"}, back_translations: {"es":"El esterno; un hueso plano en el centro del tórax que conecta las costillas via cartílago para formar a caixa torácica.","de":"Das Brustbein; ein flacher Knochen in der Mitte der Brust, der die Rippen über Knorpel verbindet und den Brustkorb bildet.","fr":"Le sternum ; un os plat au centre de la poitrine qui relie les côtes par du cartilage pour former la cage thoracique.","tr":"Göğüs kemiği; göğsün ortasında yer alan düz bir kemik olup kaburgaları kıkırdak aracılığıyla bağlayarak göğüs kafesini oluşturur.","nl":"Het borstbeen; een plat bot in het midden van de borst dat de ribben via kraakbeen verbindt om de ribbenkast te vormen.","ru":"Грудина; плоская кость в центре грудной клетки, соединяющая рёбра через хрящи и образующая грудную клетку.","zh":"胸骨；位于胸部中央的扁平骨骼，通过软骨连接肋骨，构成胸腔。","pt_BR":"O esterno; um osso plano no centro do tórax que conecta as costelas via cartilagem para formar a caixa torácica.","pt_PT":"O esterno; um osso plano no centro do tórax que conecta as costelas via cartilagem para formar a caixa torácica."}},
  { id: 'dc-anatomy-0007', deck_id: 'deck-anatomy', front: 'Scapula', back: 'The shoulder blade; a triangular flat bone on the posterior thorax connecting the upper arm to the clavicle.', sort_order: 7 , front_translations: {"es":"Escápula","de":"Skapula","fr":"Omoplate","tr":"Skapula","nl":"Schouderblad","ru":"Лопатка","zh":"肩胛骨","pt_BR":"Escápula","pt_PT":"Omoplata"}, back_translations: {"es":"La escápula; un hueso plano triangular en la parte posterior del tórax que conecta el brazo superior a la clavícula.","de":"Das Schulterblatt; ein dreieckiger flacher Knochen am hinteren Brustkorb, der den Oberarm mit dem Schlüsselbein verbindet.","fr":"L'omoplate ; un os plat triangulaire sur la face postérieure du thorax reliant le bras supérieur à la clavicule.","tr":"Kürek kemiği; arka toraks üzerinde yer alan üçgen biçimli düz bir kemik olup üst kolu klavikula ile bağlar.","nl":"Het schouderblad; een driehoekig plat bot op de achterste borstkas dat de bovenarm verbindt met het sleutelbeen.","ru":"Лопатка; треугольная плоская кость на задней поверхности грудной клетки, соединяющая плечо с ключицей.","zh":"肩胛骨；位于后胸壁的三角形扁平骨骼，连接上臂与锁骨。","pt_BR":"A escápula; um osso plano triangular na parte posterior do tórax que conecta o braço superior à clavícula.","pt_PT":"A omoplata; um osso plano triangular na parte posterior do tórax que liga o braço superior à clavícula."}},
  { id: 'dc-anatomy-0008', deck_id: 'deck-anatomy', front: 'Radius', back: 'The shorter forearm bone on the thumb side, running from elbow to wrist; rotates to allow pronation and supination.', sort_order: 8 , front_translations: {"es":"Rádio","de":"Radius","fr":"Radius","tr":"Radius","nl":"Spaakbeen","ru":"Лучевая кость","zh":"桡骨","pt_BR":"Rádio","pt_PT":"Rádio"}, back_translations: {"es":"El hueso más corto del antebraço, en el lado del polegar, indo del codo al muñeca; gira para permitir pronación y supinación.","de":"Der kürzere Unterarmknochen auf der Daumenseite, der vom Ellenbogen bis zum Handgelenk verläuft; ermöglicht durch Rotation Pro- und Supination.","fr":"Le plus court des os de l'avant-bras, côté pouce, allant du coude au poignet ; il pivote pour permettre la pronation et la supination.","tr":"Dirsekten bileğe kadar uzanan, baş parmak tarafındaki daha kısa önkol kemiği; pronasyon ve supinasyona olanak sağlamak için döner.","nl":"Het kortere onderarmbeen aan de duimzijde, lopend van elleboog naar pols; roteert om pronatie en supinatie mogelijk te maken.","ru":"Короткая кость предплечья на стороне большого пальца, идущая от локтя до запястья; вращается, обеспечивая пронацию и супинацию.","zh":"前臂较短的骨骼，位于拇指侧，从肘部延伸至腕部；旋转以实现旋前和旋后运动。","pt_BR":"O osso mais curto do antebraço, no lado do polegar, indo do cotovelo ao pulso; gira para permitir pronação e supinação.","pt_PT":"O osso mais curto do antebraço, no lado do polegar, indo do cotovelo ao pulso; roda para permitir a pronação e supinação."}},
  { id: 'dc-anatomy-0009', deck_id: 'deck-anatomy', front: 'Ulna', back: 'The longer forearm bone on the pinky side that forms the point of the elbow; articulates with the humerus at the olecranon.', sort_order: 9 , front_translations: {"es":"Ulna","de":"Ulna","fr":"Ulna","tr":"Ulna","nl":"Ellepijp","ru":"Локтевая кость","zh":"尺骨","pt_BR":"Ulna","pt_PT":"Cúbito"}, back_translations: {"es":"El hueso más ancho del antebraço, en el lado del dedo mínimo, que forma a ponta del codo; articula-se con el úmero en el olécrano.","de":"Der längere Unterarmknochen auf der Kleinfingerseeite, der die Ellenbogenspitze bildet; artikuliert mit dem Humerus am Olekranon.","fr":"Le plus long des os de l'avant-bras, côté auriculaire, formant la pointe du coude ; il s'articule avec l'humérus au niveau de l'olécrâne.","tr":"Serçe parmak tarafındaki daha uzun önkol kemiği olup dirseğin ucunu oluşturur; olekranon üzerinden humerus ile eklem yapar.","nl":"Het langere onderarmbeen aan de pinkkant dat de elleboogpunt vormt; articuleert met de humerus ter hoogte van het olecranon.","ru":"Длинная кость предплечья на стороне мизинца, образующая локтевой отросток; сочленяется с плечевой костью в области олекранона.","zh":"前臂较长的骨骼，位于小指侧，形成肘部尖端；通过鹰嘴与肱骨形成关节。","pt_BR":"O osso mais longo do antebraço, no lado do dedo mínimo, que forma a ponta do cotovelo; articula-se com o úmero no olécrano.","pt_PT":"O osso mais longo do antebraço, no lado do dedo mínimo, que forma a ponta do cotovelo; articula-se com o úmero no olecrânio."}},
  { id: 'dc-anatomy-0010', deck_id: 'deck-anatomy', front: 'Fibula', back: 'The slender outer bone of the lower leg, running alongside the tibia; it does not bear body weight but provides ankle stability.', sort_order: 10 , front_translations: {"es":"Fíbula","de":"Fibula","fr":"Fibula","tr":"Fibula","nl":"Kuitbeen","ru":"Малоберцовая кость","zh":"腓骨","pt_BR":"Fíbula","pt_PT":"Fíbula"}, back_translations: {"es":"El hueso delgado y externo de la pierna, correndo al lado de la tíbia; no suporta peso corporal, pero proporciona estabilidad al tobillo.","de":"Der schlanke äußere Knochen des Unterschenkels, der neben der Tibia verläuft; trägt kein Körpergewicht, sorgt aber für Knöchelstabilität.","fr":"Le fin os externe de la jambe, courant le long du tibia ; il ne supporte pas le poids du corps mais assure la stabilité de la cheville.","tr":"Tibianın yanında seyreden ince dış bacak kemiği; vücut ağırlığı taşımaz ancak ayak bileği stabilitesini sağlar.","nl":"Het slanke buitenste bot van het onderbeen, naast de tibia; het draagt geen lichaamsgewicht maar zorgt voor enkels stabiliteit.","ru":"Тонкая наружная кость голени, проходящая рядом с большеберцовой; не несёт нагрузки тела, но обеспечивает стабильность голеностопного сустава.","zh":"小腿细长的外侧骨骼，与胫骨平行；不承重，但为踝关节提供稳定性。","pt_BR":"O osso fino e externo da perna, correndo ao lado da tíbia; não suporta peso corporal, mas fornece estabilidade ao tornozelo.","pt_PT":"O osso fino e externo da perna, a correr ao lado da tíbia; não suporta peso corporal, mas proporciona estabilidade ao tornozelo."}},
  { id: 'dc-anatomy-0011', deck_id: 'deck-anatomy', front: 'Cranium', back: 'The skull bones that encase and protect the brain; comprised of eight fused bones including the frontal, parietal, and occipital bones.', sort_order: 11 , front_translations: {"es":"Cráneo","de":"Kranium","fr":"Crâne","tr":"Kranium","nl":"Schedel","ru":"Череп","zh":"颅骨","pt_BR":"Crânio","pt_PT":"Crânio"}, back_translations: {"es":"Los huesos del cráneo que involucran y protegen el cerebro; compuesto por ocho huesos fusionados, incluyendo el frontal, parietais y occipital.","de":"Die Schädelknochen, die das Gehirn umhüllen und schützen; bestehen aus acht verwachsenen Knochen, darunter Stirn-, Scheitel- und Hinterhauptbein.","fr":"Les os du crâne qui encaissent et protègent le cerveau ; composés de huit os fusionnés dont le frontal, les pariétaux et l'occipital.","tr":"Beyni çevreleyen ve koruyan kafatası kemikleri; frontal, parietal ve oksipital kemikler dahil sekiz kaynaşmış kemikten oluşur.","nl":"De schedelbeenderen die de hersenen omhullen en beschermen; bestaande uit acht versmolten botten waaronder het voor-, wandel- en achterhoofdsbeen.","ru":"Кости черепа, окружающие и защищающие мозг; состоят из восьми сросшихся костей, включая лобную, теменные и затылочную.","zh":"包围并保护大脑的颅骨；由八块融合骨骼组成，包括额骨、顶骨和枕骨。","pt_BR":"Os ossos do crânio que envolvem e protegem o cérebro; composto por oito ossos fundidos, incluindo o frontal, parietais e occipital.","pt_PT":"Os ossos do crânio que envolvem e protegem o cérebro; composto por oito ossos fundidos, incluindo o frontal, parietais e occipital."}},
  { id: 'dc-anatomy-0012', deck_id: 'deck-anatomy', front: 'Mandible', back: 'The lower jaw bone; the only movable bone of the skull, forming the chin and housing the lower teeth.', sort_order: 12 , front_translations: {"es":"Mandíbula","de":"Mandibula","fr":"Mandibule","tr":"Mandibula","nl":"Onderkaak","ru":"Нижняя челюсть","zh":"下颌骨","pt_BR":"Mandíbula","pt_PT":"Mandíbula"}, back_translations: {"es":"El hueso de la mandíbula inferior; el único hueso móvel del cráneo, formando el mentón y alojando los dentes inferiores.","de":"Der Unterkieferknochen; der einzige bewegliche Knochen des Schädels, der das Kinn bildet und die unteren Zähne trägt.","fr":"L'os de la mâchoire inférieure ; le seul os mobile du crâne, formant le menton et logeant les dents inférieures.","tr":"Alt çene kemiği; kafatasının tek hareketli kemiği olup çeneyi oluşturur ve alt dişleri barındırır.","nl":"Het onderkaakbeen; het enige beweeglijke bot van de schedel, dat de kin vormt en de onderste tanden herbergt.","ru":"Нижняя челюсть; единственная подвижная кость черепа, образующая подбородок и несущая нижние зубы.","zh":"下颌骨；颅骨中唯一可活动的骨骼，构成下巴并容纳下排牙齿。","pt_BR":"O osso da mandíbula inferior; o único osso móvel do crânio, formando o queixo e alojando os dentes inferiores.","pt_PT":"O osso da mandíbula inferior; o único osso móvel do crânio, formando o queixo e alojando os dentes inferiores."}},
  { id: 'dc-anatomy-0013', deck_id: 'deck-anatomy', front: 'Maxilla', back: 'The upper jaw bone; forms the hard palate, holds the upper teeth, and contributes to the nasal cavity floor.', sort_order: 13 , front_translations: {"es":"Maxila","de":"Maxilla","fr":"Maxillaire","tr":"Maksilla","nl":"Bovenkaak","ru":"Верхняя челюсть","zh":"上颌骨","pt_BR":"Maxila","pt_PT":"Maxila"}, back_translations: {"es":"El hueso de la maxila superior; forma el palato duro, sustenta los dentes superiores y contribuye para el assoalho de la cavidad nasal.","de":"Der Oberkieferknochen; bildet den harten Gaumen, trägt die oberen Zähne und bildet den Boden der Nasenhöhle.","fr":"L'os de la mâchoire supérieure ; il forme le palais dur, porte les dents supérieures et contribue au plancher de la cavité nasale.","tr":"Üst çene kemiği; sert damağı oluşturur, üst dişleri taşır ve burun boşluğunun tabanına katkıda bulunur.","nl":"Het bovenkaakbeen; vormt het harde gehemelte, herbergt de boventanden en draagt bij aan de bodem van de neusholte.","ru":"Верхняя челюсть; образует твёрдое нёбо, удерживает верхние зубы и участвует в формировании дна носовой полости.","zh":"上颌骨；构成硬腭，承载上排牙齿，并参与构成鼻腔底部。","pt_BR":"O osso da maxila superior; forma o palato duro, sustenta os dentes superiores e contribui para o assoalho da cavidade nasal.","pt_PT":"O osso da maxila superior; forma o palato duro, sustenta os dentes superiores e contribui para o pavimento da cavidade nasal."}},
  { id: 'dc-anatomy-0014', deck_id: 'deck-anatomy', front: 'Frontal Bone', back: 'The bone forming the forehead and the upper part of the eye sockets; it contains the frontal sinuses.', sort_order: 14 , front_translations: {"es":"Hueso Frontal","de":"Stirnbein","fr":"Os frontal","tr":"Frontal Kemik","nl":"Voorhoofdsbeen","ru":"Лобная кость","zh":"额骨","pt_BR":"Osso Frontal","pt_PT":"Osso Frontal"}, back_translations: {"es":"El hueso que forma a testa y a parte superior de las órbitas oculares; contiene los seios frontais.","de":"Der Knochen, der die Stirn und den oberen Teil der Augenhöhlen bildet; enthält die Stirnhöhlen.","fr":"L'os formant le front et la partie supérieure des orbites ; il contient les sinus frontaux.","tr":"Alın ve göz yuvalarının üst kısmını oluşturan kemik; frontal sinüsleri içerir.","nl":"Het bot dat het voorhoofd en de bovenste oogkassen vormt; het bevat de voorhoofdsbijholten.","ru":"Кость, образующая лоб и верхнюю часть глазниц; содержит лобные пазухи.","zh":"构成额头和眼眶上部的骨骼；含有额窦。","pt_BR":"O osso que forma a testa e a parte superior das órbitas oculares; contém os seios frontais.","pt_PT":"O osso que forma a testa e a parte superior das órbitas oculares; contém os seios frontais."}},
  { id: 'dc-anatomy-0015', deck_id: 'deck-anatomy', front: 'Occipital Bone', back: 'The bone forming the back and base of the skull; it contains the foramen magnum through which the spinal cord passes.', sort_order: 15 , front_translations: {"es":"Hueso Occipital","de":"Hinterhauptbein","fr":"Os occipital","tr":"Oksipital Kemik","nl":"Achterhoofdsbeen","ru":"Затылочная кость","zh":"枕骨","pt_BR":"Osso Occipital","pt_PT":"Osso Occipital"}, back_translations: {"es":"El hueso que forma a parte posterior y a base del cráneo; contiene el forame magno por el qual passa a medula espinal.","de":"Der Knochen, der die Rückseite und die Basis des Schädels bildet; enthält das Foramen magnum, durch das das Rückenmark verläuft.","fr":"L'os formant l'arrière et la base du crâne ; il contient le foramen magnum par lequel passe la moelle épinière.","tr":"Kafatasının arka ve tabanını oluşturan kemik; omurilik kanalının geçtiği foramen magnumu içerir.","nl":"Het bot dat de achterkant en basis van de schedel vormt; het bevat het foramen magnum waardoor het ruggenmerg loopt.","ru":"Кость, образующая заднюю и нижнюю часть черепа; содержит большое затылочное отверстие, через которое проходит спинной мозг.","zh":"构成颅骨后部和底部的骨骼；含有枕骨大孔，脊髓由此穿过。","pt_BR":"O osso que forma a parte posterior e a base do crânio; contém o forame magno pelo qual passa a medula espinal.","pt_PT":"O osso que forma a parte posterior e a base do crânio; contém o forame magno pelo qual passa a medula espinal."}},
  { id: 'dc-anatomy-0016', deck_id: 'deck-anatomy', front: 'Parietal Bone', back: 'One of two bones forming the top and sides of the skull; they meet at the sagittal suture along the midline.', sort_order: 16 , front_translations: {"es":"Hueso Parietal","de":"Scheitelbein","fr":"Os pariétal","tr":"Parietal Kemik","nl":"Wandbeen","ru":"Теменная кость","zh":"顶骨","pt_BR":"Osso Parietal","pt_PT":"Osso Parietal"}, back_translations: {"es":"Un de los de los huesos que forman a parte superior y las laterais del cráneo; encontram-se en la sutura sagital a lo ancho de la línea média.","de":"Einer von zwei Knochen, die die Oberseite und die Seiten des Schädels bilden; sie treffen sich an der Sagittalnaht in der Mittellinie.","fr":"L'un des deux os formant le sommet et les côtés du crâne ; ils se rejoignent à la suture sagittale sur la ligne médiane.","tr":"Kafatasının üst ve yanlarını oluşturan iki kemikten biri; orta hatta sagital sütürde birleşirler.","nl":"Een van twee botten die de bovenkant en zijkanten van de schedel vormen; ze komen samen bij de sagittale sutuur langs de middenlijn.","ru":"Одна из двух костей, образующих верхнюю и боковые части черепа; они соединяются по сагиттальному шву по средней линии.","zh":"构成颅顶和两侧的两块骨骼之一；在正中线处经矢状缝相连。","pt_BR":"Um dos dois ossos que formam a parte superior e as laterais do crânio; encontram-se na sutura sagital ao longo da linha média.","pt_PT":"Um dos dois ossos que formam a parte superior e os lados do crânio; encontram-se na sutura sagital ao longo da linha média."}},
  { id: 'dc-anatomy-0017', deck_id: 'deck-anatomy', front: 'Temporal Bone', back: 'The bone forming the lower sides and base of the skull; it houses the middle and inner ear structures.', sort_order: 17 , front_translations: {"es":"Hueso Temporal","de":"Schläfenbein","fr":"Os temporal","tr":"Temporal Kemik","nl":"Slaapbeen","ru":"Височная кость","zh":"颞骨","pt_BR":"Osso Temporal","pt_PT":"Osso Temporal"}, back_translations: {"es":"El hueso que forma las faces inferiores y a base del cráneo; abriga las estructuras del ouvido médio y interno.","de":"Der Knochen, der die untere Seite und die Basis des Schädels bildet; beherbergt die Strukturen des Mittel- und Innenohrs.","fr":"L'os formant les faces inférieures et la base du crâne ; il abrite les structures de l'oreille moyenne et interne.","tr":"Kafatasının alt yanlarını ve tabanını oluşturan kemik; orta ve iç kulak yapılarını barındırır.","nl":"Het bot dat de onderzijden en basis van de schedel vormt; het herbergt de structuren van het midden- en binnenoor.","ru":"Кость, образующая нижние боковые поверхности и основание черепа; содержит структуры среднего и внутреннего уха.","zh":"构成颅骨下侧面和底部的骨骼；容纳中耳和内耳结构。","pt_BR":"O osso que forma as faces inferiores e a base do crânio; abriga as estruturas do ouvido médio e interno.","pt_PT":"O osso que forma as faces inferiores e a base do crânio; aloja as estruturas do ouvido médio e interno."}},
  { id: 'dc-anatomy-0018', deck_id: 'deck-anatomy', front: 'Sphenoid Bone', back: 'A butterfly-shaped bone at the base of the skull that articulates with all other cranial bones; it forms part of the eye socket.', sort_order: 18 , front_translations: {"es":"Hueso Esfenoide","de":"Keilbein","fr":"Os sphénoïde","tr":"Sfenoid Kemik","nl":"Wiggebeen","ru":"Клиновидная кость","zh":"蝶骨","pt_BR":"Osso Esfenoide","pt_PT":"Osso Esfenóide"}, back_translations: {"es":"Un hueso en forma de borboleta en la base del cráneo que se articula con todos los outros huesos cranianos; forma parte de la órbita ocular.","de":"Ein schmetterlingsförmiger Knochen an der Schädelbasis, der mit allen anderen Schädelknochen artikuliert und Teil der Augenhöhle bildet.","fr":"Un os en forme de papillon à la base du crâne qui s'articule avec tous les autres os crâniens ; il forme une partie de l'orbite.","tr":"Kafatası tabanındaki kelebek şeklinde bir kemik olup diğer tüm kranial kemiklerle eklem yapar; göz çukurunun bir bölümünü oluşturur.","nl":"Een vlindervormig bot aan de schedelbasis dat articuleert met alle andere schedelbeenderen; het vormt een deel van de oogkas.","ru":"Клиновидная кость в основании черепа, сочленяющаяся со всеми остальными костями черепа; участвует в формировании глазницы.","zh":"颅底的蝶形骨骼，与所有其他颅骨形成关节；构成眼眶的一部分。","pt_BR":"Um osso em forma de borboleta na base do crânio que se articula com todos os outros ossos cranianos; forma parte da órbita ocular.","pt_PT":"Um osso em forma de borboleta na base do crânio que se articula com todos os outros ossos cranianos; forma parte da órbita ocular."}},
  { id: 'dc-anatomy-0019', deck_id: 'deck-anatomy', front: 'Cervical Vertebrae', back: 'The seven vertebrae of the neck (C1–C7); they support the skull and allow a wide range of head movement.', sort_order: 19 , front_translations: {"es":"Vértebras Cervicais","de":"Halswirbel","fr":"Vertèbres cervicales","tr":"Servikal Vertebralar","nl":"Halswervels","ru":"Шейные позвонки","zh":"颈椎","pt_BR":"Vértebras Cervicais","pt_PT":"Vértebras Cervicais"}, back_translations: {"es":"As siete vértebras del cuello (C1–C7); suportam el cráneo y permiten una grande amplitude de movimiento de la cabeza.","de":"Die sieben Halswirbel (C1–C7); sie stützen den Schädel und ermöglichen einen großen Bewegungsumfang des Kopfes.","fr":"Les sept vertèbres du cou (C1–C7) ; elles soutiennent le crâne et permettent une grande amplitude de mouvement de la tête.","tr":"Boyundaki yedi vertebra (C1–C7); kafatasını destekler ve başın geniş hareket açıklığına izin verir.","nl":"De zeven wervels van de nek (C1–C7); ze ondersteunen de schedel en staan een grote bewegingsvrijheid van het hoofd toe.","ru":"Семь позвонков шеи (C1–C7); поддерживают череп и обеспечивают широкий диапазон движений головы.","zh":"颈部七块椎骨（C1–C7）；支撑颅骨并允许头部大范围活动。","pt_BR":"As sete vértebras do pescoço (C1–C7); suportam o crânio e permitem uma grande amplitude de movimento da cabeça.","pt_PT":"As sete vértebras do pescoço (C1–C7); suportam o crânio e permitem uma grande amplitude de movimento da cabeça."}},
  { id: 'dc-anatomy-0020', deck_id: 'deck-anatomy', front: 'Thoracic Vertebrae', back: 'The twelve vertebrae of the mid-back (T1–T12) that articulate with the ribs to form the posterior rib cage.', sort_order: 20 , front_translations: {"es":"Vértebras Torácicas","de":"Brustwirbel","fr":"Vertèbres thoraciques","tr":"Torasik Vertebralar","nl":"Borstwervels","ru":"Грудные позвонки","zh":"胸椎","pt_BR":"Vértebras Torácicas","pt_PT":"Vértebras Torácicas"}, back_translations: {"es":"As doze vértebras del medio de las costas (T1–T12) que se articulam con las costillas para formar a parte posterior de la caixa torácica.","de":"Die zwölf Wirbel des mittleren Rückens (T1–T12), die mit den Rippen artikulieren und den hinteren Brustkorb bilden.","fr":"Les douze vertèbres du milieu du dos (T1–T12) qui s'articulent avec les côtes pour former la cage thoracique postérieure.","tr":"Kaburgalarla eklem yaparak arka göğüs kafesini oluşturan orta sırtın on iki vertebrası (T1–T12).","nl":"De twaalf wervels van de middenrug (T1–T12) die articuleren met de ribben om de achterste ribbenkast te vormen.","ru":"Двенадцать позвонков среднего отдела позвоночника (T1–T12), сочленяющихся с рёбрами и образующих заднюю часть грудной клетки.","zh":"中背部十二块椎骨（T1–T12），与肋骨形成关节，构成后胸廓。","pt_BR":"As doze vértebras do meio das costas (T1–T12) que se articulam com as costelas para formar a parte posterior da caixa torácica.","pt_PT":"As doze vértebras do meio das costas (T1–T12) que se articulam com as costelas para formar a parte posterior da grelha costal."}},
  { id: 'dc-anatomy-0021', deck_id: 'deck-anatomy', front: 'Lumbar Vertebrae', back: 'The five large vertebrae of the lower back (L1–L5); they bear the most spinal load and allow flexion and extension.', sort_order: 21 , front_translations: {"es":"Vértebras Lombares","de":"Lendenwirbel","fr":"Vertèbres lombaires","tr":"Lomber Vertebralar","nl":"Lendenwervels","ru":"Поясничные позвонки","zh":"腰椎","pt_BR":"Vértebras Lombares","pt_PT":"Vértebras Lombares"}, back_translations: {"es":"As cinco grandes vértebras de la región lombar (L1–L5); suportam a mayor carga espinal y permiten flexão y extensão.","de":"Die fünf großen Wirbel des unteren Rückens (L1–L5); sie tragen die größte Wirbelsäulenlast und ermöglichen Flexion und Extension.","fr":"Les cinq grandes vertèbres du bas du dos (L1–L5) ; elles supportent la plus grande charge vertébrale et permettent flexion et extension.","tr":"Alt sırtın beş büyük vertebrası (L1–L5); en fazla omurga yükünü taşır ve fleksiyon ile ekstansiyona olanak sağlar.","nl":"De vijf grote wervels van de onderrug (L1–L5); ze dragen de meeste wervelkolombelasting en staan flexie en extensie toe.","ru":"Пять крупных позвонков поясничного отдела (L1–L5); несут наибольшую нагрузку на позвоночник и обеспечивают сгибание и разгибание.","zh":"下背部五块大型椎骨（L1–L5）；承受最大脊柱载荷，允许屈伸运动。","pt_BR":"As cinco grandes vértebras da região lombar (L1–L5); suportam a maior carga espinal e permitem flexão e extensão.","pt_PT":"As cinco grandes vértebras da região lombar (L1–L5); suportam a maior carga espinal e permitem flexão e extensão."}},
  { id: 'dc-anatomy-0022', deck_id: 'deck-anatomy', front: 'Sacrum', back: 'A triangular bone formed by five fused vertebrae at the base of the spine; it connects the spine to the pelvis.', sort_order: 22 , front_translations: {"es":"Sacro","de":"Kreuzbein","fr":"Sacrum","tr":"Sakrum","nl":"Heiligbeen","ru":"Крестец","zh":"骶骨","pt_BR":"Sacro","pt_PT":"Sacro"}, back_translations: {"es":"Un hueso triangular formado por cinco vértebras fusionadas en la base de la columna; conecta a columna vertebral a la pelve.","de":"Ein dreieckiger Knochen, der aus fünf verwachsenen Wirbeln an der Basis der Wirbelsäule besteht; verbindet die Wirbelsäule mit dem Becken.","fr":"Un os triangulaire formé de cinq vertèbres fusionnées à la base de la colonne ; il relie la colonne vertébrale au bassin.","tr":"Omurganın tabanında beş kaynaşmış vertebradan oluşan üçgen biçimli bir kemik; omurgayı pelvis ile birleştirir.","nl":"Een driehoekig bot gevormd door vijf versmolten wervels aan de basis van de wervelkolom; het verbindt de wervelkolom met het bekken.","ru":"Треугольная кость, образованная пятью сросшимися позвонками в основании позвоночника; соединяет позвоночник с тазом.","zh":"由脊柱底部五块融合椎骨构成的三角形骨骼；连接脊柱与骨盆。","pt_BR":"Um osso triangular formado por cinco vértebras fundidas na base da coluna; conecta a coluna vertebral à pelve.","pt_PT":"Um osso triangular formado por cinco vértebras fundidas na base da coluna; liga a coluna vertebral à bacia."}},
  { id: 'dc-anatomy-0023', deck_id: 'deck-anatomy', front: 'Coccyx', back: 'The tailbone; four fused vertebrae at the very base of the spine that serve as an attachment point for pelvic floor muscles.', sort_order: 23 , front_translations: {"es":"Cóccix","de":"Steißbein","fr":"Coccyx","tr":"Kuyruk Sokumu","nl":"Staartbeen","ru":"Копчик","zh":"尾骨","pt_BR":"Cóccix","pt_PT":"Cóccix"}, back_translations: {"es":"El cóccix; cuatro vértebras fusionadas en la base de la columna que servem como punto de fixación para los músculos del assoalho pélvico.","de":"Das Steißbein; vier verwachsene Wirbel an der untersten Basis der Wirbelsäule, die als Ansatzpunkt für Beckenbodenmuskeln dienen.","fr":"Le coccyx ; quatre vertèbres fusionnées tout au bas de la colonne vertébrale servant de point d'attache aux muscles du plancher pelvien.","tr":"Kuyruk sokumu; omurganın en alt tabanındaki dört kaynaşmış vertebra olup pelvik taban kasları için yapışma noktası görevi görür.","nl":"Het staartbeen; vier versmolten wervels helemaal onderaan de wervelkolom die als aanhechtingspunt dienen voor bekkenbodemspierstelling.","ru":"Копчик; четыре сросшихся позвонка в самом основании позвоночника, служащих местом прикрепления мышц тазового дна.","zh":"尾骨；位于脊柱最底端的四块融合椎骨，作为盆底肌的附着点。","pt_BR":"O cóccix; quatro vértebras fundidas na base da coluna que servem como ponto de fixação para os músculos do assoalho pélvico.","pt_PT":"O cóccix; quatro vértebras fundidas na base da coluna que servem como ponto de inserção para os músculos do pavimento pélvico."}},
  { id: 'dc-anatomy-0024', deck_id: 'deck-anatomy', front: 'Atlas (C1)', back: 'The first cervical vertebra; ring-shaped and supports the skull, allowing the nodding motion of the head.', sort_order: 24 , front_translations: {"es":"Atlas (C1)","de":"Atlas (C1)","fr":"Atlas (C1)","tr":"Atlas (C1)","nl":"Atlas (C1)","ru":"Атлант (C1)","zh":"寰椎（C1）","pt_BR":"Atlas (C1)","pt_PT":"Atlas (C1)"}, back_translations: {"es":"La primera vértebra cervical; en forma de anel y suporta el cráneo, permitiendo el movimiento de aceno de la cabeza.","de":"Der erste Halswirbel; ringförmig und stützt den Schädel, ermöglicht die Nickbewegung des Kopfes.","fr":"La première vertèbre cervicale ; en forme d'anneau, elle supporte le crâne et permet le mouvement de hochement de tête.","tr":"Birinci servikal vertebra; halka şeklinde olup kafatasını destekler ve başın öne-arkaya sallanma hareketine olanak tanır.","nl":"De eerste halswervel; ringvormig en ondersteunt de schedel, waardoor de knikbeweging van het hoofd mogelijk is.","ru":"Первый шейный позвонок; кольцеобразный, поддерживает череп и обеспечивает кивательное движение головы.","zh":"第一颈椎；环形结构，支撑颅骨，实现头部点头动作。","pt_BR":"A primeira vértebra cervical; em forma de anel e suporta o crânio, permitindo o movimento de aceno da cabeça.","pt_PT":"A primeira vértebra cervical; em forma de anel e suporta o crânio, permitindo o movimento de aceno da cabeça."}},
  { id: 'dc-anatomy-0025', deck_id: 'deck-anatomy', front: 'Axis (C2)', back: 'The second cervical vertebra; has a peg-like dens (odontoid process) around which the atlas rotates to allow head turning.', sort_order: 25 , front_translations: {"es":"Áxis (C2)","de":"Axis (C2)","fr":"Axis (C2)","tr":"Aksis (C2)","nl":"Axis (C2)","ru":"Осевой позвонок (C2)","zh":"枢椎（C2）","pt_BR":"Áxis (C2)","pt_PT":"Áxis (C2)"}, back_translations: {"es":"La segunda vértebra cervical; tiene un proceso odontóide (dens) en torno del qual el atlas gira para permitir a rotación de la cabeza.","de":"Der zweite Halswirbel; besitzt einen zapfenartigen Dens (Zahnfortsatz), um den sich der Atlas dreht, um Kopfdrehungen zu ermöglichen.","fr":"La deuxième vertèbre cervicale ; elle possède un processus odontoïde (dens) en forme de cheville autour duquel l'atlas tourne pour permettre la rotation de la tête.","tr":"İkinci servikal vertebra; atlasın başı döndürmek için etrafında döndüğü peg benzeri bir dens (odontoid çıkıntı) içerir.","nl":"De tweede halswervel; heeft een penachtig dens (odontoid uitsteeksel) waaromheen de atlas draait om hoofdrotatie mogelijk te maken.","ru":"Второй шейный позвонок; имеет зубовидный отросток (dens), вокруг которого вращается атлант, обеспечивая повороты головы.","zh":"第二颈椎；具有桩状齿突（枢椎齿突），寰椎围绕其旋转，实现头部转动。","pt_BR":"A segunda vértebra cervical; tem um processo odontóide (dens) em torno do qual o atlas gira para permitir a rotação da cabeça.","pt_PT":"A segunda vértebra cervical; tem um processo odontóide (dens) em torno do qual o atlas roda para permitir a rotação da cabeça."}},
  { id: 'dc-anatomy-0026', deck_id: 'deck-anatomy', front: 'Ribs', back: 'Twenty-four curved bones (12 pairs) forming the rib cage that protects the heart and lungs; the upper seven pairs are true ribs attaching directly to the sternum.', sort_order: 26 , front_translations: {"es":"Costillas","de":"Rippen","fr":"Côtes","tr":"Kaburgalar","nl":"Ribben","ru":"Рёбра","zh":"肋骨","pt_BR":"Costelas","pt_PT":"Costelas"}, back_translations: {"es":"Vinte y cuatro huesos curvos (12 pares) formando a caixa torácica que protege el corazón y los pulmones; los siete pares superiores son costillas verdaderas, fixadas directamente al esterno.","de":"Vierundzwanzig gebogene Knochen (12 Paare), die den Brustkorb bilden und Herz und Lungen schützen; die oberen sieben Paare sind echte Rippen, die direkt am Brustbein befestigt sind.","fr":"Vingt-quatre os courbés (12 paires) formant la cage thoracique qui protège le cœur et les poumons ; les sept paires supérieures sont de vraies côtes s'attachant directement au sternum.","tr":"Kalp ve akciğerleri koruyan göğüs kafesini oluşturan yirmi dört kavisli kemik (12 çift); üst yedi çift doğrudan sternuma bağlanan gerçek kaburgalardır.","nl":"Vierentwintig gebogen botten (12 paar) die de ribbenkast vormen en hart en longen beschermen; de bovenste zeven paren zijn echte ribben die direct aan het borstbeen vastzitten.","ru":"Двадцать четыре изогнутые кости (12 пар), образующие грудную клетку и защищающие сердце и лёгкие; верхние семь пар — истинные рёбра, прикреплённые непосредственно к грудине.","zh":"二十四根弯曲骨骼（12对），构成保护心脏和肺部的胸廓；上方七对为真肋，直接附着于胸骨。","pt_BR":"Vinte e quatro ossos curvos (12 pares) formando a caixa torácica que protege o coração e os pulmões; os sete pares superiores são costelas verdadeiras, fixadas diretamente ao esterno.","pt_PT":"Vinte e quatro ossos curvos (12 pares) que formam a grelha costal, protegendo o coração e os pulmões; os sete pares superiores são costelas verdadeiras, fixadas diretamente ao esterno."}},
  { id: 'dc-anatomy-0027', deck_id: 'deck-anatomy', front: 'Floating Ribs', back: 'The 11th and 12th rib pairs that do not attach to the sternum anteriorly; they attach only to the thoracic vertebrae posteriorly.', sort_order: 27 , front_translations: {"es":"Costillas Flutuantes","de":"Freie Rippen","fr":"Côtes flottantes","tr":"Serbest Kaburgalar","nl":"Zwevende ribben","ru":"Плавающие рёбра","zh":"浮肋","pt_BR":"Costelas Flutuantes","pt_PT":"Costelas Flutuantes"}, back_translations: {"es":"Los 11º y 12º pares de costillas que no se fixam al esterno anteriormente; fixam-se solo a las vértebras torácicas posteriormente.","de":"Das 11. und 12. Rippenpaar, das sich vorne nicht am Brustbein befestigt; sie sind nur hinten an den Brustwirbeln befestigt.","fr":"Les 11e et 12e paires de côtes qui ne s'attachent pas au sternum en avant ; elles ne s'attachent qu'aux vertèbres thoraciques en arrière.","tr":"Önden sternuma bağlanmayan 11. ve 12. kaburga çiftleri; yalnızca arkadan torasik vertebralara bağlanırlar.","nl":"De 11e en 12e ribbenparen die vooraan niet aan het borstbeen vastzitten; ze hechten alleen achteraan vast aan de borstwervels.","ru":"11-я и 12-я пары рёбер, не прикреплённые к грудине спереди; они крепятся только к грудным позвонкам сзади.","zh":"第11和第12对肋骨，前端不附着于胸骨；仅后端与胸椎相连。","pt_BR":"Os 11º e 12º pares de costelas que não se fixam ao esterno anteriormente; fixam-se apenas às vértebras torácicas posteriormente.","pt_PT":"Os 11.º e 12.º pares de costelas que não se fixam ao esterno anteriormente; fixam-se apenas às vértebras torácicas posteriormente."}},
  { id: 'dc-anatomy-0028', deck_id: 'deck-anatomy', front: 'Ilium', back: 'The large, wing-shaped upper portion of the hip bone; the crest of the ilium is the prominent bony ridge felt at the side of the hip.', sort_order: 28 , front_translations: {"es":"Ílio","de":"Ilium","fr":"Ilion","tr":"İlium","nl":"Darmbeen","ru":"Подвздошная кость","zh":"髂骨","pt_BR":"Ílio","pt_PT":"Ílio"}, back_translations: {"es":"La grande parte superior en forma de asa del hueso del cadera; a crista ilíaca es a proeminencia ósea palpable en la lateral del cadera.","de":"Der große, flügelförmige obere Teil des Hüftknochens; der Beckenkamm ist der prominente Knochenkamm, der an der Hüftseite zu fühlen ist.","fr":"La grande partie supérieure en forme d'aile de l'os coxal ; la crête iliaque est la saillie osseuse proéminente palpable sur le côté de la hanche.","tr":"Kalça kemiğinin büyük, kanat şeklindeki üst kısmı; iliak krest, kalçanın yanında hissedilen belirgin kemik sırtıdır.","nl":"Het grote, vleugelvormige bovenste deel van het heupbeen; de iliumkam is de prominente botrand die aan de zijkant van de heup voelbaar is.","ru":"Большая крылообразная верхняя часть тазовой кости; гребень подвздошной кости — выступающий костный край, ощущаемый сбоку таза.","zh":"髋骨大而翼状的上部；髂嵴是可在髋部侧面触及的突出骨嵴。","pt_BR":"A grande parte superior em forma de asa do osso do quadril; a crista ilíaca é a proeminência óssea palpável na lateral do quadril.","pt_PT":"A grande parte superior em forma de asa do osso do quadril; a crista ilíaca é a proeminência óssea palpável na lateral da anca."}},
  { id: 'dc-anatomy-0029', deck_id: 'deck-anatomy', front: 'Ischium', back: 'The lower and back part of the hip bone; the ischial tuberosities are the bony prominences we sit on.', sort_order: 29 , front_translations: {"es":"Ísquio","de":"Ischium","fr":"Ischion","tr":"İskium","nl":"Zitbeen","ru":"Седалищная кость","zh":"坐骨","pt_BR":"Ísquio","pt_PT":"Ísquio"}, back_translations: {"es":"La parte inferior y posterior del hueso del cadera; las tuberosidades isquiáticas son las proeminencias ósseas sobre las quais en los sentamos.","de":"Der untere und hintere Teil des Hüftknochens; die Sitzbeinhöcker sind die knöchernen Vorsprünge, auf denen wir sitzen.","fr":"La partie inférieure et postérieure de l'os coxal ; les tubérosités ischiatiques sont les saillies osseuses sur lesquelles nous nous asseyons.","tr":"Kalça kemiğinin alt ve arka kısmı; iskial tüberoziteler üzerinde oturduğumuz kemik çıkıntılardır.","nl":"Het onderste en achterste deel van het heupbeen; de zitbeenknobbels zijn de botuitsteeksels waarop we zitten.","ru":"Нижняя и задняя часть тазовой кости; седалищные бугры — костные выступы, на которых мы сидим.","zh":"髋骨的下后部；坐骨结节是我们坐下时接触的骨性突起。","pt_BR":"A parte inferior e posterior do osso do quadril; as tuberosidades isquiáticas são as proeminências ósseas sobre as quais nos sentamos.","pt_PT":"A parte inferior e posterior do osso do quadril; as tuberosidades isquiáticas são as proeminências ósseas sobre as quais nos sentamos."}},
  { id: 'dc-anatomy-0030', deck_id: 'deck-anatomy', front: 'Pubis', back: 'The anterior lower portion of the hip bone; the two pubic bones meet at the pubic symphysis in the midline.', sort_order: 30 , front_translations: {"es":"Púbis","de":"Schambein","fr":"Pubis","tr":"Pubis","nl":"Schaambeen","ru":"Лобковая кость","zh":"耻骨","pt_BR":"Púbis","pt_PT":"Púbis"}, back_translations: {"es":"La parte anterior inferior del hueso del cadera; los de los huesos púbicos se encontram en la sínfise púbica en la línea média.","de":"Der vordere untere Teil des Hüftknochens; die beiden Schambeine treffen sich an der Schambeinfuge in der Mittellinie.","fr":"La partie antérieure inférieure de l'os coxal ; les deux os pubiens se rejoignent à la symphyse pubienne sur la ligne médiane.","tr":"Kalça kemiğinin ön alt kısmı; iki pubik kemik orta hatta pubik simfizde birleşir.","nl":"Het voorste onderste deel van het heupbeen; de twee schaambenen komen samen bij de schaamsymphysis in de middenlijn.","ru":"Передняя нижняя часть тазовой кости; две лобковые кости соединяются по лобковому симфизу по средней линии.","zh":"髋骨的前下部；两块耻骨在正中线处于耻骨联合处相接。","pt_BR":"A parte anterior inferior do osso do quadril; os dois ossos púbicos se encontram na sínfise púbica na linha média.","pt_PT":"A parte anterior inferior do osso do quadril; os dois ossos púbicos encontram-se na sínfise púbica na linha média."}},
  { id: 'dc-anatomy-0031', deck_id: 'deck-anatomy', front: 'Talus', back: 'The ankle bone that sits atop the calcaneus; it transmits body weight from the leg to the foot.', sort_order: 31 , front_translations: {"es":"Tálus","de":"Talus","fr":"Talus","tr":"Talus","nl":"Sprongbeen","ru":"Таранная кость","zh":"距骨","pt_BR":"Tálus","pt_PT":"Tálus"}, back_translations: {"es":"El hueso del tobillo que fica sobre el calcaneo; transmite el peso corporal de la pierna para el pie.","de":"Der Sprungbeinknochen, der auf dem Fersenbein sitzt; überträgt das Körpergewicht vom Bein auf den Fuß.","fr":"L'os de la cheville situé au sommet du calcanéus ; il transmet le poids du corps de la jambe au pied.","tr":"Kalkaneusun üzerinde oturan ayak bileği kemiği; vücut ağırlığını bacaktan ayağa iletir.","nl":"Het sprongbeen dat boven op het hielbeen zit; het overdraagt het lichaamsgewicht van het been naar de voet.","ru":"Надпяточная кость, расположенная на пяточной кости; передаёт нагрузку тела с голени на стопу.","zh":"位于跟骨上方的踝骨；将体重从腿部传递到足部。","pt_BR":"O osso do tornozelo que fica sobre o calcâneo; transmite o peso corporal da perna para o pé.","pt_PT":"O osso do tornozelo que assenta sobre o calcâneo; transmite o peso corporal da perna para o pé."}},
  { id: 'dc-anatomy-0032', deck_id: 'deck-anatomy', front: 'Calcaneus', back: 'The heel bone; the largest bone in the foot that absorbs impact when walking and running.', sort_order: 32 , front_translations: {"es":"Calcaneo","de":"Kalkaneus","fr":"Calcanéus","tr":"Kalkaneus","nl":"Hielbeen","ru":"Пяточная кость","zh":"跟骨","pt_BR":"Calcâneo","pt_PT":"Calcâneo"}, back_translations: {"es":"El hueso del calcanhar; el mayor hueso del pie que absorbe el impacto al caminhar y correr.","de":"Das Fersenbein; der größte Knochen des Fußes, der beim Gehen und Laufen Stöße absorbiert.","fr":"L'os du talon ; le plus grand os du pied, qui absorbe les chocs lors de la marche et de la course.","tr":"Topuk kemiği; yürüme ve koşma sırasında darbeyi absorbe eden ayağın en büyük kemiği.","nl":"Het hielbeen; het grootste bot in de voet dat schokken absorbeert bij lopen en rennen.","ru":"Пяточная кость; самая крупная кость стопы, поглощающая удары при ходьбе и беге.","zh":"跟骨；足部最大的骨骼，在行走和跑步时吸收冲击力。","pt_BR":"O osso do calcanhar; o maior osso do pé que absorve o impacto ao caminhar e correr.","pt_PT":"O osso do calcanhar; o maior osso do pé que absorve o impacto ao caminhar e correr."}},
  { id: 'dc-anatomy-0033', deck_id: 'deck-anatomy', front: 'Metatarsals', back: 'The five long bones of the mid-foot connecting the ankle bones to the toes; they form the arch of the foot.', sort_order: 33 , front_translations: {"es":"Metatarsos","de":"Mittelfußknochen","fr":"Métatarses","tr":"Metatarslar","nl":"Middenvoetsbeentjes","ru":"Плюсневые кости","zh":"跖骨","pt_BR":"Metatarsos","pt_PT":"Metatarsos"}, back_translations: {"es":"Los cinco huesos largos del médio-pie que conectan los huesos del tarso a los dedos; forman el arco del pie.","de":"Die fünf langen Knochen des Mittelfußes, die die Fußwurzelknochen mit den Zehen verbinden; sie bilden das Fußgewölbe.","fr":"Les cinq longs os du milieu du pied reliant les os du tarse aux orteils ; ils forment la voûte plantaire.","tr":"Ayak bileği kemiklerini parmaklara bağlayan ve ayak kemerini oluşturan orta ayaktaki beş uzun kemik.","nl":"De vijf lange botten van de middenvoet die de enkelbotten verbinden met de tenen; ze vormen de voetboog.","ru":"Пять длинных костей средней части стопы, соединяющих кости предплюсны с пальцами; образуют свод стопы.","zh":"足部中段的五块长骨，连接踝骨与足趾；构成足弓。","pt_BR":"Os cinco ossos longos do médio-pé que conectam os ossos do tarso aos dedos; formam o arco do pé.","pt_PT":"Os cinco ossos longos do médio-pé que ligam os ossos do tarso aos dedos; formam a abóbada plantar."}},
  { id: 'dc-anatomy-0034', deck_id: 'deck-anatomy', front: 'Phalanges (foot)', back: 'The fourteen small bones of the toes (three in each toe except the big toe, which has two); they assist in balance and locomotion.', sort_order: 34 , front_translations: {"es":"Falanges (pie)","de":"Zehenknochen (Fuß)","fr":"Phalanges (pied)","tr":"Falankslar (ayak)","nl":"Teenkootjes","ru":"Фаланги (стопа)","zh":"趾骨（足）","pt_BR":"Falanges (pé)","pt_PT":"Falanges (pé)"}, back_translations: {"es":"Los quatorze pequeños huesos de los dedos del pie (tres en cada dedo, excepto el hálux que tiene de los); auxiliam en el equilíbrio y en la locomoción.","de":"Die vierzehn kleinen Zehenknochen (drei je Zehe, außer dem großen Zeh, der zwei hat); sie helfen beim Gleichgewicht und bei der Fortbewegung.","fr":"Les quatorze petits os des orteils (trois par orteil sauf le gros qui en a deux) ; ils aident à l'équilibre et à la locomotion.","tr":"Ayak parmaklarının on dört küçük kemiği (büyük parmak hariç her parmakta üç kemik, büyük parmakta iki); denge ve yürüyüşe yardımcı olurlar.","nl":"De veertien kleine teenkootjes (drie per teen behalve de grote teen die er twee heeft); ze helpen bij evenwicht en voortbeweging.","ru":"Четырнадцать небольших костей пальцев стопы (три в каждом пальце, кроме большого, у которого два); участвуют в балансировании и движении.","zh":"足趾的十四块小骨（除大趾有两块外，每趾各三块）；辅助平衡与运动。","pt_BR":"Os quatorze pequenos ossos dos dedos do pé (três em cada dedo, exceto o hálux que tem dois); auxiliam no equilíbrio e na locomoção.","pt_PT":"Os catorze pequenos ossos dos dedos do pé (três em cada dedo, exceto o hálux que tem dois); auxiliam no equilíbrio e na locomoção."}},
  { id: 'dc-anatomy-0035', deck_id: 'deck-anatomy', front: 'Metacarpals', back: 'The five long bones of the palm connecting the wrist bones to the fingers; they form the framework of the hand.', sort_order: 35 , front_translations: {"es":"Metacarpos","de":"Mittelhandknochen","fr":"Métacarpes","tr":"Metakarplar","nl":"Middenhandsbeentjes","ru":"Пястные кости","zh":"掌骨","pt_BR":"Metacarpos","pt_PT":"Metacarpos"}, back_translations: {"es":"Los cinco huesos largos de la palma de la mano que conectan los huesos del carpo a los dedos; forman a estructura de la mano.","de":"Die fünf langen Knochen der Handfläche, die die Handwurzelknochen mit den Fingern verbinden; sie bilden das Gerüst der Hand.","fr":"Les cinq longs os de la paume reliant les os du carpe aux doigts ; ils constituent la charpente de la main.","tr":"Bilek kemiklerini parmaklara bağlayan ve elin iskeletini oluşturan avuç içinin beş uzun kemiği.","nl":"De vijf lange botten van de palm die de polsbeentjes verbinden met de vingers; ze vormen het geraamte van de hand.","ru":"Пять длинных костей ладони, соединяющих кости запястья с пальцами; образуют основу кисти.","zh":"手掌的五块长骨，连接腕骨与手指；构成手部框架。","pt_BR":"Os cinco ossos longos da palma da mão que conectam os ossos do carpo aos dedos; formam a estrutura da mão.","pt_PT":"Os cinco ossos longos da palma da mão que ligam os ossos do carpo aos dedos; formam a estrutura da mão."}},
  { id: 'dc-anatomy-0036', deck_id: 'deck-anatomy', front: 'Carpals', back: 'The eight small bones of the wrist arranged in two rows; they allow the complex range of motion of the wrist joint.', sort_order: 36 , front_translations: {"es":"Huesos del Carpo","de":"Handwurzelknochen","fr":"Carpes","tr":"Karpal Kemikler","nl":"Polsbeentjes","ru":"Кости запястья","zh":"腕骨","pt_BR":"Ossos do Carpo","pt_PT":"Ossos do Carpo"}, back_translations: {"es":"Los ocho pequeños huesos del punho dispostos en de los fileras; permiten a ampla gama de movimientos de la articulación del muñeca.","de":"Die acht kleinen Knochen des Handgelenks in zwei Reihen angeordnet; sie ermöglichen den komplexen Bewegungsumfang des Handgelenks.","fr":"Les huit petits os du poignet disposés en deux rangées ; ils permettent la grande amplitude de mouvement du poignet.","tr":"İki sıra halinde düzenlenmiş sekiz küçük bilek kemiği; bileğin karmaşık hareket açıklığına olanak tanırlar.","nl":"De acht kleine polsbeentjes gerangschikt in twee rijen; ze staan het complexe bewegingsbereik van het polsgewricht toe.","ru":"Восемь небольших костей запястья, расположенных в два ряда; обеспечивают сложный диапазон движений запястного сустава.","zh":"腕部八块小骨，排列为两排；实现腕关节的复杂运动范围。","pt_BR":"Os oito pequenos ossos do punho dispostos em duas fileiras; permitem a ampla gama de movimentos da articulação do pulso.","pt_PT":"Os oito pequenos ossos do pulso dispostos em duas filas; permitem a ampla gama de movimentos da articulação do pulso."}},
  { id: 'dc-anatomy-0037', deck_id: 'deck-anatomy', front: 'Quadriceps Femoris', back: 'A group of four muscles on the front of the thigh (rectus femoris, vastus lateralis, medialis, intermedius) that extend the knee.', sort_order: 37 , front_translations: {"es":"Quadríceps Femoral","de":"Musculus quadriceps femoris","fr":"Quadriceps fémoral","tr":"Quadriceps Femoris","nl":"Quadriceps femoris","ru":"Четырёхглавая мышца бедра","zh":"股四头肌","pt_BR":"Quadríceps Femoral","pt_PT":"Quadricípite Femoral"}, back_translations: {"es":"Un grupo de cuatro músculos en la parte frontal de la muslo (reto femoral, vasto lateral, medial y intermédio) que estendem el rodilla.","de":"Eine Gruppe von vier Muskeln an der Vorderseite des Oberschenkels (Rectus femoris, Vastus lateralis, medialis, intermedius), die das Knie strecken.","fr":"Un groupe de quatre muscles à l'avant de la cuisse (droit fémoral, vaste latéral, médial, intermédiaire) qui étend le genou.","tr":"Dizi uzatan uyluk ön yüzündeki dört kasdan oluşan grup (rectus femoris, vastus lateralis, medialis, intermedius).","nl":"Een groep van vier spieren aan de voorzijde van de dij (rectus femoris, vastus lateralis, medialis, intermedius) die de knie strekken.","ru":"Группа из четырёх мышц на передней поверхности бедра (прямая мышца бедра, латеральная, медиальная и промежуточная широкие мышцы), разгибающих колено.","zh":"大腿前侧的四块肌肉组合（股直肌、股外侧肌、股内侧肌、股中间肌），负责伸展膝关节。","pt_BR":"Um grupo de quatro músculos na parte frontal da coxa (reto femoral, vasto lateral, medial e intermédio) que estendem o joelho.","pt_PT":"Um grupo de quatro músculos na parte frontal da coxa (reto femoral, vasto lateral, medial e intermédio) que estendem o joelho."}},
  { id: 'dc-anatomy-0038', deck_id: 'deck-anatomy', front: 'Hamstrings', back: 'Three muscles on the back of the thigh (biceps femoris, semitendinosus, semimembranosus) that flex the knee and extend the hip.', sort_order: 38 , front_translations: {"es":"Isquiotibiais","de":"Ischiokrurale Muskeln","fr":"Ischio-jambiers","tr":"Hamstring Kasları","nl":"Hamstrings","ru":"Мышцы задней поверхности бедра","zh":"腘绳肌","pt_BR":"Isquiotibiais","pt_PT":"Isquiotibiais"}, back_translations: {"es":"Tres músculos en la parte posterior de la muslo (bíceps femoral, semitendíneo, semimembranoso) que flexionam el rodilla y estendem el cadera.","de":"Drei Muskeln auf der Rückseite des Oberschenkels (Biceps femoris, Semitendinosus, Semimembranosus), die das Knie beugen und die Hüfte strecken.","fr":"Trois muscles à l'arrière de la cuisse (biceps fémoral, semi-tendineux, semi-membraneux) qui fléchissent le genou et étendent la hanche.","tr":"Dizi büken ve kalçayı uzatan uyluk arkasındaki üç kas (biceps femoris, semitendinosus, semimembranosus).","nl":"Drie spieren aan de achterkant van de dij (biceps femoris, semitendinosus, semimembranosus) die de knie buigen en de heup strekken.","ru":"Три мышцы задней поверхности бедра (двуглавая мышца бедра, полусухожильная и полуперепончатая), сгибающие колено и разгибающие тазобедренный сустав.","zh":"大腿后侧的三块肌肉（股二头肌、半腱肌、半膜肌），负责屈曲膝关节和伸展髋关节。","pt_BR":"Três músculos na parte posterior da coxa (bíceps femoral, semitendíneo, semimembranoso) que flexionam o joelho e estendem o quadril.","pt_PT":"Três músculos na parte posterior da coxa (bíceps femoral, semitendíneo, semimembranoso) que flectem o joelho e estendem a anca."}},
  { id: 'dc-anatomy-0039', deck_id: 'deck-anatomy', front: 'Gluteus Maximus', back: 'The largest muscle of the buttocks; the primary extensor of the hip, important for climbing, running, and rising from a seated position.', sort_order: 39 , front_translations: {"es":"Glúteo Máximo","de":"Musculus gluteus maximus","fr":"Grand fessier","tr":"Gluteus Maksimus","nl":"Grote bilspier","ru":"Большая ягодичная мышца","zh":"臀大肌","pt_BR":"Glúteo Máximo","pt_PT":"Grande Glúteo"}, back_translations: {"es":"El mayor músculo de los glúteos; el principal extensor del cadera, importante para subir escadas, correr y levantar de una posición sentada.","de":"Der größte Gesäßmuskel; der primäre Hüftstrecker, wichtig beim Treppensteigen, Laufen und dem Aufstehen aus dem Sitzen.","fr":"Le plus grand muscle des fesses ; il est le principal extenseur de la hanche, essentiel pour monter, courir et se lever d'une position assise.","tr":"Kalçanın en büyük kası; kalçanın birincil ekstansörü olup merdiven çıkma, koşma ve oturma pozisyonundan kalkma için önemlidir.","nl":"De grootste spier van de billen; de primaire strekker van de heup, belangrijk bij klimmen, rennen en opstaan vanuit een zittende positie.","ru":"Крупнейшая мышца ягодицы; основной разгибатель тазобедренного сустава, необходимый при подъёме по лестнице, беге и вставании.","zh":"臀部最大的肌肉；髋关节的主要伸肌，在爬楼梯、跑步和从坐姿起立时发挥重要作用。","pt_BR":"O maior músculo dos glúteos; o principal extensor do quadril, importante para subir escadas, correr e levantar de uma posição sentada.","pt_PT":"O maior músculo dos glúteos; o principal extensor da anca, importante para subir escadas, correr e levantar de uma posição sentada."}},
  { id: 'dc-anatomy-0040', deck_id: 'deck-anatomy', front: 'Deltoid', back: 'A triangular muscle covering the shoulder joint; it abducts the arm and assists in flexion and extension of the shoulder.', sort_order: 40 , front_translations: {"es":"Deltóide","de":"Deltamuskel","fr":"Deltoïde","tr":"Deltoid","nl":"Deltaspier","ru":"Дельтовидная мышца","zh":"三角肌","pt_BR":"Deltóide","pt_PT":"Deltóide"}, back_translations: {"es":"Un músculo triangular que cobre a articulación del hombro; abduz el brazo y auxilia en la flexão y extensão del hombro.","de":"Ein dreieckiger Muskel, der das Schultergelenk bedeckt; er abduziert den Arm und unterstützt die Flexion und Extension der Schulter.","fr":"Un muscle triangulaire recouvrant l'articulation de l'épaule ; il abducte le bras et participe à la flexion et l'extension de l'épaule.","tr":"Omuz eklemini örten üçgen şeklindeki kas; kolu abdükte eder ve omuz fleksiyonu ile ekstansiyonuna yardımcı olur.","nl":"Een driehoekige spier die het schoudergewricht bedekt; hij abduceert de arm en helpt bij flexie en extensie van de schouder.","ru":"Треугольная мышца, покрывающая плечевой сустав; отводит руку и участвует в сгибании и разгибании плеча.","zh":"覆盖肩关节的三角形肌肉；外展手臂，辅助肩部屈伸运动。","pt_BR":"Um músculo triangular que cobre a articulação do ombro; abduz o braço e auxilia na flexão e extensão do ombro.","pt_PT":"Um músculo triangular que cobre a articulação do ombro; abduz o braço e auxilia na flexão e extensão do ombro."}},
  { id: 'dc-anatomy-0041', deck_id: 'deck-anatomy', front: 'Trapezius', back: 'A large triangular back muscle extending from the skull to the mid-back; it moves and stabilizes the scapula and supports the arm.', sort_order: 41 , front_translations: {"es":"Trapézio","de":"Trapezmuskel","fr":"Trapèze","tr":"Trapezius","nl":"Trapezius","ru":"Трапециевидная мышца","zh":"斜方肌","pt_BR":"Trapézio","pt_PT":"Trapézio"}, back_translations: {"es":"Un grande músculo triangular de las costas que se estende del cráneo a la región média de las costas; move y estabiliza a escápula y suporta el brazo.","de":"Ein großer dreieckiger Rückenmuskel, der vom Schädel bis zur Mitte des Rückens reicht; er bewegt und stabilisiert das Schulterblatt und stützt den Arm.","fr":"Un grand muscle dorsal triangulaire s'étendant du crâne au milieu du dos ; il déplace et stabilise l'omoplate et soutient le bras.","tr":"Kafatasından orta sırtına kadar uzanan büyük üçgen sırt kası; skapulayı hareket ettirir, stabilize eder ve kolu destekler.","nl":"Een grote driehoekige rugspier die zich uitstrekt van de schedel tot de middenrug; hij beweegt en stabiliseert het schouderblad en ondersteunt de arm.","ru":"Большая треугольная мышца спины, простирающаяся от черепа до средней части спины; двигает и стабилизирует лопатку, поддерживает руку.","zh":"从颅骨延伸至中背部的大型三角形背肌；移动和稳定肩胛骨，支撑手臂。","pt_BR":"Um grande músculo triangular das costas que se estende do crânio à região média das costas; move e estabiliza a escápula e suporta o braço.","pt_PT":"Um grande músculo triangular das costas que se estende do crânio à região média das costas; move e estabiliza a omoplata e suporta o braço."}},
  { id: 'dc-anatomy-0042', deck_id: 'deck-anatomy', front: 'Latissimus Dorsi', back: 'The broad, flat muscle of the back that adducts, extends, and internally rotates the arm; important for pulling movements.', sort_order: 42 , front_translations: {"es":"Grande Dorsal","de":"Latissimus dorsi","fr":"Grand dorsal","tr":"Latissimus Dorsi","nl":"Brede rugspier","ru":"Широчайшая мышца спины","zh":"背阔肌","pt_BR":"Grande Dorsal","pt_PT":"Grande Dorsal"}, back_translations: {"es":"El amplo músculo plano de las costas que aduz, estende y roda internamente el brazo; importante para movimientos de puxar.","de":"Der breite, flache Rückenmuskel, der den Arm adduziert, streckt und nach innen dreht; wichtig für Zugbewegungen.","fr":"Le muscle dorsal large et plat qui adduit, étend et fait pivoter le bras en dedans ; essentiel pour les mouvements de traction.","tr":"Kolu addükte eden, uzatan ve içe döndüren geniş, düz sırt kası; çekme hareketleri için önemlidir.","nl":"De brede, platte rugspier die de arm adduceert, strekt en naar binnen roteert; belangrijk voor trekbewegingen.","ru":"Широкая плоская мышца спины, приводящая, разгибающая и внутренне вращающая руку; важна для тяговых движений.","zh":"宽阔扁平的背部肌肉，内收、伸展并内旋手臂；对拉伸动作至关重要。","pt_BR":"O amplo músculo plano das costas que aduz, estende e roda internamente o braço; importante para movimentos de puxar.","pt_PT":"O amplo músculo plano das costas que aduz, estende e roda internamente o braço; importante para movimentos de puxar."}},
  { id: 'dc-anatomy-0043', deck_id: 'deck-anatomy', front: 'Pectoralis Major', back: 'The large chest muscle that flexes, adducts, and internally rotates the arm; it is the primary muscle used in pushing movements.', sort_order: 43 , front_translations: {"es":"Peitoral Mayor","de":"Musculus pectoralis major","fr":"Grand pectoral","tr":"Pektoralis Majör","nl":"Grote borstspier","ru":"Большая грудная мышца","zh":"胸大肌","pt_BR":"Peitoral Maior","pt_PT":"Grande Peitoral"}, back_translations: {"es":"El grande músculo del pecho que flexiona, aduz y roda internamente el brazo; el músculo primário usado en movimientos de empurrar.","de":"Der große Brustmuskel, der den Arm beugt, adduziert und nach innen dreht; der primäre Muskel bei Druckbewegungen.","fr":"Le grand muscle thoracique qui fléchit, adduit et fait pivoter le bras en dedans ; c'est le muscle principal utilisé dans les mouvements de poussée.","tr":"Kolu büken, addükte eden ve içe döndüren büyük göğüs kası; itme hareketlerinde kullanılan birincil kastır.","nl":"De grote borstspier die de arm buigt, adduceert en naar binnen roteert; de primaire spier bij duwbewegingen.","ru":"Большая грудная мышца, сгибающая, приводящая и внутренне вращающая руку; основная мышца при толчковых движениях.","zh":"大型胸部肌肉，屈曲、内收并内旋手臂；推举动作的主要肌肉。","pt_BR":"O grande músculo do peito que flexiona, aduz e roda internamente o braço; o músculo primário usado em movimentos de empurrar.","pt_PT":"O grande músculo do peito que flexiona, aduz e roda internamente o braço; o músculo primário utilizado em movimentos de empurrar."}},
  { id: 'dc-anatomy-0044', deck_id: 'deck-anatomy', front: 'Biceps Brachii', back: 'The two-headed muscle on the front of the upper arm; it flexes the elbow and supinates the forearm.', sort_order: 44 , front_translations: {"es":"Bíceps Braquial","de":"Musculus biceps brachii","fr":"Biceps brachial","tr":"Biceps Brachii","nl":"Biceps brachii","ru":"Двуглавая мышца плеча","zh":"肱二头肌","pt_BR":"Bíceps Braquial","pt_PT":"Bicípete Braquial"}, back_translations: {"es":"El músculo de de los cabeças en la parte frontal del brazo superior; flexiona el codo y supina el antebraço.","de":"Der zweiköpfige Muskel auf der Vorderseite des Oberarms; er beugt den Ellenbogen und supiniert den Unterarm.","fr":"Le muscle à deux têtes situé à l'avant du bras supérieur ; il fléchit le coude et supine l'avant-bras.","tr":"Üst kolun ön yüzündeki iki başlı kas; dirseği büker ve önkolu supine eder.","nl":"De tweekoppige spier aan de voorzijde van de bovenarm; hij buigt de elleboog en supineert de onderarm.","ru":"Двуглавая мышца на передней поверхности плеча; сгибает локоть и супинирует предплечье.","zh":"上臂前侧的双头肌肉；屈曲肘关节并旋后前臂。","pt_BR":"O músculo de duas cabeças na parte frontal do braço superior; flexiona o cotovelo e supina o antebraço.","pt_PT":"O músculo de duas cabeças na parte frontal do braço superior; flexiona o cotovelo e supina o antebraço."}},
  { id: 'dc-anatomy-0045', deck_id: 'deck-anatomy', front: 'Triceps Brachii', back: 'The three-headed muscle on the back of the upper arm; the primary extensor of the elbow joint.', sort_order: 45 , front_translations: {"es":"Tríceps Braquial","de":"Musculus triceps brachii","fr":"Triceps brachial","tr":"Triceps Brachii","nl":"Triceps brachii","ru":"Трёхглавая мышца плеча","zh":"肱三头肌","pt_BR":"Tríceps Braquial","pt_PT":"Tricípete Braquial"}, back_translations: {"es":"El músculo de tres cabeças en la parte posterior del brazo superior; el principal extensor de la articulación del codo.","de":"Der dreiköpfige Muskel auf der Rückseite des Oberarms; der primäre Strecker des Ellenbogengelenks.","fr":"Le muscle à trois têtes situé à l'arrière du bras supérieur ; il est le principal extenseur de l'articulation du coude.","tr":"Üst kolun arka yüzündeki üç başlı kas; dirsek ekleminin birincil ekstansörü.","nl":"De driekoppige spier aan de achterzijde van de bovenarm; de primaire strekker van het ellebooggewricht.","ru":"Трёхглавая мышца на задней поверхности плеча; основной разгибатель локтевого сустава.","zh":"上臂后侧的三头肌肉；肘关节的主要伸肌。","pt_BR":"O músculo de três cabeças na parte posterior do braço superior; o principal extensor da articulação do cotovelo.","pt_PT":"O músculo de três cabeças na parte posterior do braço superior; o principal extensor da articulação do cotovelo."}},
  { id: 'dc-anatomy-0046', deck_id: 'deck-anatomy', front: 'Gastrocnemius', back: 'The large, two-headed calf muscle that plantar flexes the foot and assists in knee flexion; it forms the visible bulk of the calf.', sort_order: 46 , front_translations: {"es":"Gastrocnemio","de":"Musculus gastrocnemius","fr":"Gastrocnémien","tr":"Gastroknemius","nl":"Tweekoppige kuitspier","ru":"Икроножная мышца","zh":"腓肠肌","pt_BR":"Gastrocnêmio","pt_PT":"Gastrocnémio"}, back_translations: {"es":"El grande músculo de la panturrilha de de los cabeças que plantiflexiona el pie y auxilia en la flexão del rodilla; forma el volumen visible de la panturrilha.","de":"Der große, zweiköpfige Wadenmuskel, der den Fuß plantarflektiert und bei der Kniebeugung hilft; er bildet das sichtbare Wadenvolumen.","fr":"Le grand muscle du mollet à deux têtes qui fléchit plantairement le pied et aide à la flexion du genou ; il forme le volume visible du mollet.","tr":"Ayağı plantar fleksiyona getiren ve diz fleksiyonuna yardımcı olan büyük iki başlı baldır kası; baldırın görünür kitlesini oluşturur.","nl":"De grote, tweekoppige kuitspier die de voet plantairflecteert en helpt bij knieflexie; hij vormt het zichtbare volume van de kuit.","ru":"Большая двуглавая икроножная мышца, выполняющая подошвенное сгибание стопы и участвующая в сгибании колена; образует видимый рельеф икры.","zh":"大型双头小腿肌肉，使足部跖屈并辅助膝关节屈曲；构成小腿可见的隆起部分。","pt_BR":"O grande músculo da panturrilha de duas cabeças que plantiflexiona o pé e auxilia na flexão do joelho; forma o volume visível da panturrilha.","pt_PT":"O grande músculo da barriga da perna de duas cabeças que faz a flexão plantar do pé e auxilia na flexão do joelho; forma o volume visível da barriga da perna."}},
  { id: 'dc-anatomy-0047', deck_id: 'deck-anatomy', front: 'Soleus', back: 'A flat calf muscle lying beneath the gastrocnemius; it plantar flexes the foot and is crucial for standing posture.', sort_order: 47 , front_translations: {"es":"Sóleo","de":"Musculus soleus","fr":"Soléaire","tr":"Soleus","nl":"Diepliggende kuitspier","ru":"Камбаловидная мышца","zh":"比目鱼肌","pt_BR":"Sóleo","pt_PT":"Sóleo"}, back_translations: {"es":"Un músculo plano de la panturrilha situado debajo del gastrocnemio; hace a flexão plantar del pie y es crucial para a postura en pie.","de":"Ein flacher Wadenmuskel unter dem Gastrocnemius; er plantarflektiert den Fuß und ist entscheidend für die Standposition.","fr":"Un muscle plat du mollet situé sous le gastrocnémien ; il fléchit plantairement le pied et est essentiel pour la posture debout.","tr":"Gastroknemiusun altında yatan düz baldır kası; ayağı plantar fleksiyona getirir ve duruş postürü için kritik öneme sahiptir.","nl":"Een platte kuitspier onder de gastrocnemius; hij plantairflecteert de voet en is cruciaal voor de staande houding.","ru":"Плоская мышца голени под икроножной мышцей; выполняет подошвенное сгибание стопы и играет ключевую роль в поддержании вертикальной позы.","zh":"位于腓肠肌下方的扁平小腿肌肉；使足部跖屈，对站立姿势至关重要。","pt_BR":"Um músculo plano da panturrilha situado abaixo do gastrocnêmio; faz a flexão plantar do pé e é crucial para a postura em pé.","pt_PT":"Um músculo plano da barriga da perna situado abaixo do gastrocnémio; faz a flexão plantar do pé e é fundamental para a postura em pé."}},
  { id: 'dc-anatomy-0048', deck_id: 'deck-anatomy', front: 'Diaphragm', back: 'The dome-shaped muscle separating the thorax from the abdomen; it is the primary muscle of respiration, contracting to draw air into the lungs.', sort_order: 48 , front_translations: {"es":"Diafragma","de":"Zwerchfell","fr":"Diaphragme","tr":"Diyafram","nl":"Middenrif","ru":"Диафрагма","zh":"膈肌","pt_BR":"Diafragma","pt_PT":"Diafragma"}, back_translations: {"es":"El músculo en forma de cúpula que separa el tórax del abdomen; es el principal músculo de la respiración, contraindo-se para puxar aire para los pulmones.","de":"Der kuppelförmige Muskel, der den Brustkorb vom Bauch trennt; er ist der primäre Atemmuskel und zieht sich zusammen, um Luft in die Lungen zu ziehen.","fr":"Le muscle en forme de dôme séparant le thorax de l'abdomen ; c'est le muscle respiratoire principal qui se contracte pour aspirer l'air dans les poumons.","tr":"Göğüs boşluğunu karından ayıran kubbe şeklindeki kas; birincil solunum kasıdır ve hava çekmek için kasılır.","nl":"De koepelvormige spier die de borstholte van de buik scheidt; het is de primaire ademhalingsspier die samentrekt om lucht in de longen te trekken.","ru":"Куполообразная мышца, разделяющая грудную и брюшную полости; главная дыхательная мышца, сокращение которой обеспечивает вдох.","zh":"将胸腔与腹腔分隔的穹顶形肌肉；是主要的呼吸肌，收缩时将空气吸入肺部。","pt_BR":"O músculo em forma de cúpula que separa o tórax do abdômen; é o principal músculo da respiração, contraindo-se para puxar ar para os pulmões.","pt_PT":"O músculo em forma de cúpula que separa o tórax do abdómen; é o principal músculo da respiração, contraindo-se para puxar ar para os pulmões."}},
  { id: 'dc-anatomy-0049', deck_id: 'deck-anatomy', front: 'Rectus Abdominis', back: 'The paired vertical abdominal muscles forming the "six-pack"; they flex the spine and compress abdominal contents.', sort_order: 49 , front_translations: {"es":"Reto Abdominal","de":"Musculus rectus abdominis","fr":"Muscle droit de l'abdomen","tr":"Rektus Abdominis","nl":"Rechte buikspier","ru":"Прямая мышца живота","zh":"腹直肌","pt_BR":"Reto Abdominal","pt_PT":"Reto Abdominal"}, back_translations: {"es":"Los músculos abdominais verticais emparelhados que forman el \"six-pack\"; eles flexionam a columna y comprimem el conteúdo abdominal.","de":"Die paarigen vertikalen Bauchmuskeln, die das \"Sixpack\" bilden; sie beugen die Wirbelsäule und komprimieren den Bauchinhalt.","fr":"Les muscles abdominaux verticaux appariés formant les \"tablettes de chocolat\" ; ils fléchissent la colonne vertébrale et compriment les viscères abdominaux.","tr":"\"Altılı paketi\" oluşturan çift dikey karın kasları; omurgayı büker ve karın içeriğini sıkıştırırlar.","nl":"De gepaarde verticale buikspieren die de \"sixpack\" vormen; ze buigen de wervelkolom en compressen de buikinhoud.","ru":"Парные вертикальные мышцы живота, образующие «кубики»; сгибают позвоночник и сжимают брюшную полость.","zh":"构成『六块腹肌』的成对垂直腹部肌肉；屈曲脊柱并压缩腹腔内容物。","pt_BR":"Os músculos abdominais verticais emparelhados que formam o \"six-pack\"; eles flexionam a coluna e comprimem o conteúdo abdominal.","pt_PT":"Os músculos abdominais verticais emparelhados que formam o \"six-pack\"; flexionam a coluna e comprimem o conteúdo abdominal."}},
  { id: 'dc-anatomy-0050', deck_id: 'deck-anatomy', front: 'Intercostal Muscles', back: 'Muscles running between the ribs; the external intercostals assist inhalation while internal intercostals assist forced exhalation.', sort_order: 50 , front_translations: {"es":"Músculos Intercostais","de":"Zwischenrippenmuskeln","fr":"Muscles intercostaux","tr":"İnterkostal Kaslar","nl":"Tussenribspieren","ru":"Межрёберные мышцы","zh":"肋间肌","pt_BR":"Músculos Intercostais","pt_PT":"Músculos Intercostais"}, back_translations: {"es":"Músculos que correm entre las costillas; los intercostais externos auxiliam en la inspiración mientras los internos auxiliam en la expiración forçada.","de":"Muskeln, die zwischen den Rippen verlaufen; die äußeren Zwischenrippenmuskeln unterstützen die Einatmung, während die inneren die forcierte Ausatmung unterstützen.","fr":"Muscles courant entre les côtes ; les intercostaux externes aident à l'inspiration tandis que les intercostaux internes aident à l'expiration forcée.","tr":"Kaburgalar arasında seyreden kaslar; dış interkostaller inspirasyona yardımcı olurken iç interkostaller zorlu ekspirasyona yardımcı olur.","nl":"Spieren die tussen de ribben lopen; de externe intercostalen helpen bij inademing terwijl de interne intercostalen bij geforceerde uitademing helpen.","ru":"Мышцы, проходящие между рёбрами; внешние межрёберные мышцы участвуют во вдохе, а внутренние — в форсированном выдохе.","zh":"在肋骨之间走行的肌肉；肋间外肌辅助吸气，肋间内肌辅助用力呼气。","pt_BR":"Músculos que correm entre as costelas; os intercostais externos auxiliam na inspiração enquanto os internos auxiliam na expiração forçada.","pt_PT":"Músculos que percorrem entre as costelas; os intercostais externos auxiliam na inspiração enquanto os internos auxiliam na expiração forçada."}},
  { id: 'dc-anatomy-0051', deck_id: 'deck-anatomy', front: 'Heart', back: 'A muscular organ roughly the size of a fist located in the mediastinum; it pumps oxygenated blood to the body and deoxygenated blood to the lungs via four chambers.', sort_order: 51 , front_translations: {"es":"Corazón","de":"Herz","fr":"Cœur","tr":"Kalp","nl":"Hart","ru":"Сердце","zh":"心脏","pt_BR":"Coração","pt_PT":"Coração"}, back_translations: {"es":"Un órgano muscular aproximadamente del tamaño de un punho, localizado en el mediastino; bombeia sangre oxigenado para el cuerpo y sangre desoxigenado para los pulmones por medio de cuatro camaras.","de":"Ein muskuläres Organ ungefähr in der Größe einer Faust, das im Mediastinum liegt; es pumpt sauerstoffreiches Blut in den Körper und sauerstoffarmes Blut in die Lungen über vier Kammern.","fr":"Un organe musculaire à peu près de la taille d'un poing, situé dans le médiastin ; il pompe le sang oxygéné vers le corps et le sang désoxygéné vers les poumons via quatre cavités.","tr":"Mediastinumda yer alan yaklaşık bir yumruk büyüklüğünde kassal bir organ; dört kamara aracılığıyla oksijenli kanı vücuda ve oksijensiz kanı akciğerlere pompalar.","nl":"Een spierachtig orgaan ter grootte van een vuist in het mediastinum; het pompt zuurstofrijk bloed naar het lichaam en zuurstofarme bloed naar de longen via vier kamers.","ru":"Мышечный орган размером примерно с кулак, расположенный в средостении; прокачивает насыщенную кислородом кровь по телу и венозную кровь в лёгкие через четыре камеры.","zh":"位于纵隔内约拳头大小的肌性器官；通过四个腔室将含氧血液泵送至全身，将脱氧血液泵送至肺部。","pt_BR":"Um órgão muscular aproximadamente do tamanho de um punho, localizado no mediastino; bombeia sangue oxigenado para o corpo e sangue desoxigenado para os pulmões por meio de quatro câmaras.","pt_PT":"Um órgão muscular aproximadamente do tamanho de um punho, localizado no mediastino; bombeia sangue oxigenado para o corpo e sangue desoxigenado para os pulmões através de quatro câmaras."}},
  { id: 'dc-anatomy-0052', deck_id: 'deck-anatomy', front: 'Left Ventricle', back: 'The most muscular chamber of the heart; it pumps oxygenated blood into the aorta and out to the systemic circulation.', sort_order: 52 , front_translations: {"es":"Ventrículo esquerdo","de":"Linke Herzkammer","fr":"Ventricule gauche","tr":"Sol Ventrikül","nl":"Linker hartkamer","ru":"Левый желудочек","zh":"左心室","pt_BR":"Ventrículo esquerdo","pt_PT":"Ventrículo esquerdo"}, back_translations: {"es":"La camara más muscular del corazón; bombeia sangre oxigenado para a aorta y para a circulación sistemica.","de":"Die muskulöseste Kammer des Herzens; sie pumpt sauerstoffreiches Blut in die Aorta und in den systemischen Kreislauf.","fr":"La chambre la plus musclée du cœur ; elle pompe le sang oxygéné dans l'aorte et vers la circulation systémique.","tr":"Kalbin en kassal odacığı; oksijenli kanı aortaya ve sistemik dolaşıma pompalar.","nl":"De meest gespierde kamer van het hart; het pompt zuurstofrijk bloed in de aorta en naar de systemische circulatie.","ru":"Наиболее мышечная камера сердца; прокачивает насыщенную кислородом кровь в аорту и в большой круг кровообращения.","zh":"心脏最有力的腔室；将含氧血液泵入主动脉并输送至体循环。","pt_BR":"A câmara mais muscular do coração; bombeia sangue oxigenado para a aorta e para a circulação sistêmica.","pt_PT":"A câmara mais muscular do coração; bombeia sangue oxigenado para a aorta e para a circulação sistémica."}},
  { id: 'dc-anatomy-0053', deck_id: 'deck-anatomy', front: 'Right Ventricle', back: 'The heart chamber that pumps deoxygenated blood into the pulmonary artery toward the lungs for oxygenation.', sort_order: 53 , front_translations: {"es":"Ventrículo derecho","de":"Rechte Herzkammer","fr":"Ventricule droit","tr":"Sağ Ventrikül","nl":"Rechter hartkamer","ru":"Правый желудочек","zh":"右心室","pt_BR":"Ventrículo direito","pt_PT":"Ventrículo direito"}, back_translations: {"es":"La camara cardíaca que bombeia sangre desoxigenado para a arteria pulmonar en dirección a los pulmones para oxigenación.","de":"Die Herzkammer, die sauerstoffarmes Blut in die Pulmonalarterie in Richtung Lungen zur Sauerstoffanreicherung pumpt.","fr":"La chambre cardiaque qui pompe le sang désoxygéné dans l'artère pulmonaire vers les poumons pour l'oxygénation.","tr":"Oksijensiz kanı oksijenasyon için akciğerlere doğru pulmoner artere pompalan kalp odacığı.","nl":"De hartkamer die zuurstofarme bloed in de longslagader naar de longen pompt voor oxygenatie.","ru":"Камера сердца, которая прокачивает венозную кровь в лёгочную артерию к лёгким для оксигенации.","zh":"将脱氧血液泵入肺动脉送往肺部进行氧合的心腔。","pt_BR":"A câmara cardíaca que bombeia sangue desoxigenado para a artéria pulmonar em direção aos pulmões para oxigenação.","pt_PT":"A câmara cardíaca que bombeia sangue desoxigenado para a artéria pulmonar em direção aos pulmões para oxigenação."}},
  { id: 'dc-anatomy-0054', deck_id: 'deck-anatomy', front: 'Aorta', back: 'The largest artery in the body; it arises from the left ventricle and distributes oxygenated blood to the entire systemic circulation.', sort_order: 54 , front_translations: {"es":"Aorta","de":"Aorta","fr":"Aorte","tr":"Aort","nl":"Aorta","ru":"Аорта","zh":"主动脉","pt_BR":"Aorta","pt_PT":"Aorta"}, back_translations: {"es":"La mayor arteria del cuerpo; se origina en el ventrículo esquerdo y distribuye sangre oxigenado para toda a circulación sistemica.","de":"Die größte Arterie im Körper; sie entspringt aus dem linken Ventrikel und verteilt sauerstoffreiches Blut in den gesamten systemischen Kreislauf.","fr":"La plus grande artère du corps ; elle naît du ventricule gauche et distribue le sang oxygéné à toute la circulation systémique.","tr":"Vücuttaki en büyük arter; sol ventrikülden çıkar ve oksijenli kanı tüm sistemik dolaşıma dağıtır.","nl":"De grootste slagader in het lichaam; het ontspringt uit de linker hartkamer en verdeelt zuurstofrijk bloed naar de gehele systemische circulatie.","ru":"Самая крупная артерия тела; берёт начало от левого желудочка и распределяет насыщенную кислородом кровь по всему большому кругу кровообращения.","zh":"人体最大的动脉；起源于左心室，将含氧血液分配至整个体循环。","pt_BR":"A maior artéria do corpo; origina-se no ventrículo esquerdo e distribui sangue oxigenado para toda a circulação sistêmica.","pt_PT":"A maior artéria do corpo; tem origem no ventrículo esquerdo e distribui sangue oxigenado para toda a circulação sistémica."}},
  { id: 'dc-anatomy-0055', deck_id: 'deck-anatomy', front: 'Pulmonary Artery', back: 'The artery carrying deoxygenated blood from the right ventricle to the lungs; unique among arteries in carrying deoxygenated blood.', sort_order: 55 , front_translations: {"es":"Arteria pulmonar","de":"Lungenarterie","fr":"Artère pulmonaire","tr":"Pulmoner Arter","nl":"Longslagader","ru":"Лёгочная артерия","zh":"肺动脉","pt_BR":"Artéria pulmonar","pt_PT":"Artéria pulmonar"}, back_translations: {"es":"La arteria que transporta sangre desoxigenado del ventrículo derecho para los pulmones; única entre las arterias por transportar sangre desoxigenado.","de":"Die Arterie, die sauerstoffarmes Blut vom rechten Ventrikel zu den Lungen transportiert; einzigartig unter den Arterien, da sie sauerstoffarmes Blut führt.","fr":"L'artère transportant le sang désoxygéné du ventricule droit vers les poumons ; unique parmi les artères en transportant du sang désoxygéné.","tr":"Oksijensiz kanı sağ ventrikülden akciğerlere taşıyan arter; oksijensiz kan taşıması nedeniyle arterler arasında benzersizdir.","nl":"De slagader die zuurstofarme bloed van de rechter hartkamer naar de longen vervoert; uniek onder slagaders doordat het zuurstofarme bloed transporteert.","ru":"Артерия, несущая венозную кровь от правого желудочка к лёгким; уникальна среди артерий тем, что транспортирует венозную кровь.","zh":"将脱氧血液从右心室输送到肺部的动脉；在动脉中独特之处在于运输脱氧血液。","pt_BR":"A artéria que transporta sangue desoxigenado do ventrículo direito para os pulmões; única entre as artérias por transportar sangue desoxigenado.","pt_PT":"A artéria que transporta sangue desoxigenado do ventrículo direito para os pulmões; única entre as artérias por transportar sangue desoxigenado."}},
  { id: 'dc-anatomy-0056', deck_id: 'deck-anatomy', front: 'Mitral Valve', back: 'The bicuspid valve between the left atrium and left ventricle; it prevents backflow of blood into the atrium during ventricular contraction.', sort_order: 56 , front_translations: {"es":"Válvula mitral","de":"Mitralklappe","fr":"Valve mitrale","tr":"Mitral Kapak","nl":"Mitralisklep","ru":"Митральный клапан","zh":"二尖瓣","pt_BR":"Válvula mitral","pt_PT":"Válvula mitral"}, back_translations: {"es":"La válvula bicúspide entre el átrio esquerdo y el ventrículo esquerdo; impide el refluxo de sangre para el átrio durante a contración ventricular.","de":"Die bikuspide Klappe zwischen dem linken Vorhof und dem linken Ventrikel; sie verhindert den Rückfluss von Blut in den Vorhof während der Ventrikelkontraktion.","fr":"La valve bicuspide entre l'oreillette gauche et le ventricule gauche ; elle prévient le reflux sanguin vers l'oreillette lors de la contraction ventriculaire.","tr":"Sol atrium ile sol ventrikül arasındaki bikuspid kapak; ventrikül kasılması sırasında kanın atriuma geri akışını önler.","nl":"De bicuspide klep tussen de linker boezem en linker kamer; het voorkomt terugstroom van bloed in de boezem tijdens ventriculaire contractie.","ru":"Двустворчатый клапан между левым предсердием и левым желудочком; препятствует обратному забросу крови в предсердие при сокращении желудочка.","zh":"位于左心房与左心室之间的二叶瓣；在心室收缩时防止血液回流至心房。","pt_BR":"A válvula bicúspide entre o átrio esquerdo e o ventrículo esquerdo; impede o refluxo de sangue para o átrio durante a contração ventricular.","pt_PT":"A válvula bicúspide entre o átrio esquerdo e o ventrículo esquerdo; impede o refluxo de sangue para o átrio durante a contração ventricular."}},
  { id: 'dc-anatomy-0057', deck_id: 'deck-anatomy', front: 'Lungs', back: 'The paired respiratory organs in the thorax where gas exchange occurs; the right lung has three lobes and the left has two to accommodate the heart.', sort_order: 57 , front_translations: {"es":"Pulmones","de":"Lungen","fr":"Poumons","tr":"Akciğerler","nl":"Longen","ru":"Лёгкие","zh":"肺","pt_BR":"Pulmões","pt_PT":"Pulmões"}, back_translations: {"es":"Los órganos respiratórios pareados en el tórax donde ocurre a troca gaseosa; el pulmón derecho tiene tres lobos y el esquerdo tiene de los para acomodar el corazón.","de":"Die paarigen Atmungsorgane im Thorax, in denen der Gasaustausch stattfindet; die rechte Lunge hat drei Lappen und die linke zwei, um Platz für das Herz zu schaffen.","fr":"Les organes respiratoires pairs dans le thorax où se produit l'échange gazeux ; le poumon droit a trois lobes et le gauche en a deux pour accommoder le cœur.","tr":"Gaz değişiminin gerçekleştiği göğüs kafesindeki çift solunum organları; sağ akciğerin üç lobu, sol akciğerin ise kalp için yer bırakmak amacıyla iki lobu vardır.","nl":"De gepaarde ademhalingsorganen in de borstkas waar gasuitwisseling plaatsvindt; de rechter long heeft drie lobben en de linker twee om ruimte te maken voor het hart.","ru":"Парные органы дыхания в грудной клетке, где происходит газообмен; правое лёгкое имеет три доли, левое — две, чтобы оставить место для сердца.","zh":"位于胸腔内的成对呼吸器官，是气体交换发生的场所；右肺有三叶，左肺有两叶，以容纳心脏。","pt_BR":"Os órgãos respiratórios pareados no tórax onde ocorre a troca gasosa; o pulmão direito tem três lobos e o esquerdo tem dois para acomodar o coração.","pt_PT":"Os órgãos respiratórios pareados no tórax onde ocorre a troca gasosa; o pulmão direito tem três lobos e o esquerdo tem dois para acomodar o coração."}},
  { id: 'dc-anatomy-0058', deck_id: 'deck-anatomy', front: 'Alveoli', back: 'Tiny air sacs at the end of bronchioles in the lungs where oxygen diffuses into the blood and carbon dioxide diffuses out.', sort_order: 58 , front_translations: {"es":"Alvéolos","de":"Lungenbläschen (Alveolen)","fr":"Alvéoles","tr":"Alveoller","nl":"Longblaasjes (alveoli)","ru":"Альвеолы","zh":"肺泡","pt_BR":"Alvéolos","pt_PT":"Alvéolos"}, back_translations: {"es":"Pequeños sacos de aire en el final de los bronquíolos en los pulmones, donde el oxígeno se difunde para el sangre y el dióxido de carbono sai.","de":"Winzige Luftsäcke am Ende der Bronchiolen in der Lunge, wo Sauerstoff ins Blut diffundiert und Kohlendioxid herausdiffundiert.","fr":"Petits sacs aériens situés à l'extrémité des bronchioles dans les poumons, où l'oxygène diffuse dans le sang et le dioxyde de carbone en sort.","tr":"Akciğerlerdeki bronkiyollerin sonundaki küçük hava keseleri; oksijen kana difüze olurken karbondioksit dışarı difüze olur.","nl":"Kleine luchtzakjes aan het einde van bronchiolen in de longen waar zuurstof het bloed in diffundeert en kooldioxide eruit diffundeert.","ru":"Крошечные воздушные мешочки на концах бронхиол в лёгких, где кислород диффундирует в кровь, а углекислый газ — наружу.","zh":"肺部细支气管末端的微小气囊，是氧气向血液弥散和二氧化碳向外弥散的场所。","pt_BR":"Pequenos sacos de ar no final dos bronquíolos nos pulmões, onde o oxigênio se difunde para o sangue e o dióxido de carbono sai.","pt_PT":"Pequenos sacos de ar no final dos bronquíolos nos pulmões, onde o oxigénio se difunde para o sangue e o dióxido de carbono sai."}},
  { id: 'dc-anatomy-0059', deck_id: 'deck-anatomy', front: 'Trachea', back: 'The windpipe; a cartilage-reinforced tube connecting the larynx to the bronchi, conducting air to the lungs.', sort_order: 59 , front_translations: {"es":"Traqueia","de":"Luftröhre (Trachea)","fr":"Trachée","tr":"Trakea (Soluk Borusu)","nl":"Luchtpijp (trachea)","ru":"Трахея","zh":"气管","pt_BR":"Traqueia","pt_PT":"Traqueia"}, back_translations: {"es":"La traqueia; un tubo reforçado por cartílago que conecta a laringe a los bronquios, conduciendo el aire para los pulmones.","de":"Die Luftröhre; ein knorpelverstärkter Schlauch, der den Kehlkopf mit den Bronchien verbindet und Luft in die Lungen leitet.","fr":"La trachée artère ; un tube renforcé par du cartilage reliant le larynx aux bronches, conduisant l'air vers les poumons.","tr":"Soluk borusu; laringeksi bronşlara bağlayan, akciğerlere hava ileten kıkırdakla desteklenmiş bir tüp.","nl":"De luchtpijp; een kraakbeen-versterkte buis die de strottenhoofd verbindt met de bronchiën en lucht naar de longen geleidt.","ru":"Дыхательное горло; трубка, укреплённая хрящевыми кольцами, соединяющая гортань с бронхами и проводящая воздух в лёгкие.","zh":"气管；软骨加固的管道，连接喉部与支气管，将空气导入肺部。","pt_BR":"A traqueia; um tubo reforçado por cartilagem que conecta a laringe aos brônquios, conduzindo o ar para os pulmões.","pt_PT":"A traqueia; um tubo reforçado por cartilagem que liga a laringe aos brônquios, conduzindo o ar para os pulmões."}},
  { id: 'dc-anatomy-0060', deck_id: 'deck-anatomy', front: 'Bronchi', back: 'The two main airways branching from the trachea into each lung; they further divide into smaller bronchioles.', sort_order: 60 , front_translations: {"es":"Bronquios","de":"Bronchien","fr":"Bronches","tr":"Bronşlar","nl":"Bronchiën","ru":"Бронхи","zh":"支气管","pt_BR":"Brônquios","pt_PT":"Brônquios"}, back_translations: {"es":"As de los vias aéreas principales que se ramificam de la traqueia para cada pulmón; elas se dividem aún en bronquios menores.","de":"Die zwei Hauptatemwege, die sich von der Trachea in jede Lunge verzweigen; sie unterteilen sich weiter in kleinere Bronchiolen.","fr":"Les deux voies aériennes principales se ramifiant de la trachée dans chaque poumon ; elles se divisent ensuite en bronchioles plus petites.","tr":"Trakeadan her akciğere dallanarak giden iki ana hava yolu; daha küçük bronkiyollere bölünmeye devam ederler.","nl":"De twee hoofdluchtwegen die vanuit de luchtpijp in elke long vertakken; ze verdelen zich verder in kleinere bronchiolen.","ru":"Два главных дыхательных пути, ответвляющихся от трахеи в каждое лёгкое; они далее делятся на более мелкие бронхиолы.","zh":"从气管分出进入每侧肺部的两条主气道；进一步分支形成更小的细支气管。","pt_BR":"As duas vias aéreas principais que se ramificam da traqueia para cada pulmão; elas se dividem ainda em brônquios menores.","pt_PT":"As duas vias aéreas principais que se ramificam da traqueia para cada pulmão; dividem-se posteriormente em bronquíolos mais pequenos."}},
  { id: 'dc-anatomy-0061', deck_id: 'deck-anatomy', front: 'Liver', back: 'The largest internal organ, located in the upper right abdomen; it metabolizes nutrients, detoxifies the blood, produces bile, and synthesizes proteins.', sort_order: 61 , front_translations: {"es":"Hígado","de":"Leber","fr":"Foie","tr":"Karaciğer","nl":"Lever","ru":"Печень","zh":"肝脏","pt_BR":"Fígado","pt_PT":"Fígado"}, back_translations: {"es":"El mayor órgano interno, localizado en el abdomen superior derecho; metaboliza nutrientes, desintoxica el sangre, produce bile y sintetiza proteínas.","de":"Das größte innere Organ, im rechten Oberbauch gelegen; es metabolisiert Nährstoffe, entgiftet das Blut, produziert Galle und synthetisiert Proteine.","fr":"Le plus grand organe interne, situé dans l'abdomen supérieur droit ; il métabolise les nutriments, détoxifie le sang, produit la bile et synthétise des protéines.","tr":"Sağ üst karında yer alan en büyük iç organ; besinleri metabolize eder, kanı detoksifiye eder, safra üretir ve protein sentezler.","nl":"Het grootste interne orgaan, gelegen in de rechter bovenbuik; het metaboliseert voedingsstoffen, ontgift het bloed, produceert gal en synthetiseert eiwitten.","ru":"Крупнейший внутренний орган, расположенный в правом верхнем отделе живота; метаболизирует питательные вещества, детоксицирует кровь, производит желчь и синтезирует белки.","zh":"位于右上腹的最大内脏器官；负责代谢营养物质、解毒血液、产生胆汁和合成蛋白质。","pt_BR":"O maior órgão interno, localizado no abdômen superior direito; metaboliza nutrientes, desintoxica o sangue, produz bile e sintetiza proteínas.","pt_PT":"O maior órgão interno, localizado no abdómen superior direito; metaboliza nutrientes, desintoxica o sangue, produz bílis e sintetiza proteínas."}},
  { id: 'dc-anatomy-0062', deck_id: 'deck-anatomy', front: 'Gallbladder', back: 'A small organ beneath the liver that stores and concentrates bile produced by the liver; it releases bile into the small intestine to aid fat digestion.', sort_order: 62 , front_translations: {"es":"Vesícula biliar","de":"Gallenblase","fr":"Vésicule biliaire","tr":"Safra Kesesi","nl":"Galblaas","ru":"Желчный пузырь","zh":"胆囊","pt_BR":"Vesícula biliar","pt_PT":"Vesícula biliar"}, back_translations: {"es":"Un pequeño órgano debajo del hígado que almacena y concentra a bile producida por el hígado; libera bile en el intestino delgado para auxiliar en la digestión de gorduras.","de":"Ein kleines Organ unter der Leber, das die von der Leber produzierte Galle speichert und konzentriert; es gibt Galle in den Dünndarm ab, um die Fettverdauung zu unterstützen.","fr":"Un petit organe sous le foie qui stocke et concentre la bile produite par le foie ; il libère la bile dans l'intestin grêle pour aider à la digestion des graisses.","tr":"Karaciğerin altında yer alan ve karaciğer tarafından üretilen safrayı depolayan ve yoğunlaştıran küçük bir organ; yağ sindirimini desteklemek için safrayı ince bağırsağa salar.","nl":"Een klein orgaan onder de lever dat gal opslaat en concentreert die door de lever wordt geproduceerd; het geeft gal af aan de dunne darm om vetspijsvertering te helpen.","ru":"Небольшой орган под печенью, хранящий и концентрирующий желчь, вырабатываемую печенью; выделяет желчь в тонкую кишку для содействия перевариванию жиров.","zh":"位于肝脏下方的小型器官，储存并浓缩肝脏产生的胆汁；将胆汁释放至小肠以辅助脂肪消化。","pt_BR":"Um pequeno órgão abaixo do fígado que armazena e concentra a bile produzida pelo fígado; libera bile no intestino delgado para auxiliar na digestão de gorduras.","pt_PT":"Um pequeno órgão abaixo do fígado que armazena e concentra a bílis produzida pelo fígado; liberta bílis no intestino delgado para auxiliar na digestão de gorduras."}},
  { id: 'dc-anatomy-0063', deck_id: 'deck-anatomy', front: 'Pancreas', back: 'A glandular organ with both endocrine functions (producing insulin and glucagon) and exocrine functions (secreting digestive enzymes into the small intestine).', sort_order: 63 , front_translations: {"es":"Pancreas","de":"Bauchspeicheldrüse (Pankreas)","fr":"Pancréas","tr":"Pankreas","nl":"Alvleesklier (pancreas)","ru":"Поджелудочная железа","zh":"胰腺","pt_BR":"Pâncreas","pt_PT":"Pâncreas"}, back_translations: {"es":"Un órgano glandular con funciones endócrinas (producción de insulina y glucagon) y funciones exócrinas (secreción de enzimas digestivas en el intestino delgado).","de":"Ein drüsiges Organ mit endokrinen Funktionen (Produktion von Insulin und Glukagon) und exokrinen Funktionen (Sekretion von Verdauungsenzymen in den Dünndarm).","fr":"Un organe glandulaire avec des fonctions endocrines (production d'insuline et de glucagon) et des fonctions exocrines (sécrétion d'enzymes digestives dans l'intestin grêle).","tr":"Hem endokrin fonksiyonları (insülin ve glukagon üretimi) hem de ekzokrin fonksiyonları (ince bağırsağa sindirim enzimleri salgılama) olan glandüler bir organ.","nl":"Een klierachtig orgaan met zowel endocriene functies (productie van insuline en glucagon) als exocriene functies (secretie van spijsverteringsenzymen in de dunne darm).","ru":"Железистый орган, выполняющий эндокринные функции (выработка инсулина и глюкагона) и экзокринные функции (секреция пищеварительных ферментов в тонкую кишку).","zh":"兼具内分泌功能（产生胰岛素和胰高血糖素）和外分泌功能（向小肠分泌消化酶）的腺体器官。","pt_BR":"Um órgão glandular com funções endócrinas (produção de insulina e glucagon) e funções exócrinas (secreção de enzimas digestivas no intestino delgado).","pt_PT":"Um órgão glandular com funções endócrinas (produção de insulina e glucagão) e funções exócrinas (secreção de enzimas digestivas no intestino delgado)."}},
  { id: 'dc-anatomy-0064', deck_id: 'deck-anatomy', front: 'Kidneys', back: 'Paired bean-shaped organs in the retroperitoneum that filter blood, produce urine, regulate electrolytes, and control blood pressure via renin secretion.', sort_order: 64 , front_translations: {"es":"Riñones","de":"Nieren","fr":"Reins","tr":"Böbrekler","nl":"Nieren","ru":"Почки","zh":"肾脏","pt_BR":"Rins","pt_PT":"Rins"}, back_translations: {"es":"Órganos pareados en forma de feijão en el retroperitonio que filtram el sangre, producen urina, regulan eletrólitos y controlan a presión arterial via secreción de renina.","de":"Paarige bohnenförmige Organe im Retroperitoneum, die das Blut filtern, Urin produzieren, Elektrolyte regulieren und den Blutdruck über die Reninsekretion kontrollieren.","fr":"Organes pairs en forme de haricot dans le rétropéritoine qui filtrent le sang, produisent l'urine, régulent les électrolytes et contrôlent la pression artérielle via la sécrétion de rénine.","tr":"Kanı filtreleyen, idrar üreten, elektrolitleri düzenleyen ve renin salgılanması yoluyla kan basıncını kontrol eden retroperitoneumdaki çift fasulye şekilli organlar.","nl":"Gepaarde boonvormige organen in het retroperitoneum die bloed filteren, urine produceren, elektrolyten reguleren en de bloeddruk regelen via reninesecretie.","ru":"Парные бобовидные органы в забрюшинном пространстве, фильтрующие кровь, вырабатывающие мочу, регулирующие электролиты и контролирующие артериальное давление посредством секреции ренина.","zh":"位于腹膜后的成对豆形器官，负责过滤血液、产生尿液、调节电解质并通过分泌肾素控制血压。","pt_BR":"Órgãos pareados em forma de feijão no retroperitônio que filtram o sangue, produzem urina, regulam eletrólitos e controlam a pressão arterial via secreção de renina.","pt_PT":"Órgãos pares em forma de feijão no retroperitoneu que filtram o sangue, produzem urina, regulam eletrólitos e controlam a pressão arterial através da secreção de renina."}},
  { id: 'dc-anatomy-0065', deck_id: 'deck-anatomy', front: 'Nephron', back: 'The functional unit of the kidney; each kidney contains about one million nephrons that filter blood and produce urine through filtration, reabsorption, and secretion.', sort_order: 65 , front_translations: {"es":"Néfron","de":"Nephron","fr":"Néphron","tr":"Nefron","nl":"Nefron","ru":"Нефрон","zh":"肾单位","pt_BR":"Néfron","pt_PT":"Nefrão"}, back_translations: {"es":"La unidad funcional del riñón; cada riñón contiene cerca de un milhão de néfrons que filtram el sangre y producen urina por medio de filtración, reabsorción y secreción.","de":"Die funktionelle Einheit der Niere; jede Niere enthält etwa eine Million Nephrone, die Blut filtern und Urin durch Filtration, Reabsorption und Sekretion produzieren.","fr":"L'unité fonctionnelle du rein ; chaque rein contient environ un million de néphrons qui filtrent le sang et produisent l'urine par filtration, réabsorption et sécrétion.","tr":"Böbreğin fonksiyonel birimi; her böbrek, filtrasyon, reabsorpsiyon ve sekresyon yoluyla kanı filtreleyen ve idrar üreten yaklaşık bir milyon nefron içerir.","nl":"De functionele eenheid van de nier; elke nier bevat ongeveer een miljoen nefronen die bloed filteren en urine produceren door filtratie, reabsorptie en secretie.","ru":"Функциональная единица почки; каждая почка содержит около одного миллиона нефронов, которые фильтруют кровь и вырабатывают мочу путём фильтрации, реабсорбции и секреции.","zh":"肾脏的功能单位；每个肾脏含有约一百万个肾单位，通过滤过、重吸收和分泌来过滤血液并产生尿液。","pt_BR":"A unidade funcional do rim; cada rim contém cerca de um milhão de néfrons que filtram o sangue e produzem urina por meio de filtração, reabsorção e secreção.","pt_PT":"A unidade funcional do rim; cada rim contém cerca de um milhão de nefrões que filtram o sangue e produzem urina através de filtração, reabsorção e secreção."}},
  { id: 'dc-anatomy-0066', deck_id: 'deck-anatomy', front: 'Ureter', back: 'The muscular tube that transports urine from the kidney to the urinary bladder via peristaltic contractions.', sort_order: 66 , front_translations: {"es":"Ureter","de":"Harnleiter (Ureter)","fr":"Uretère","tr":"Üreter","nl":"Ureter","ru":"Мочеточник","zh":"输尿管","pt_BR":"Ureter","pt_PT":"Ureter"}, back_translations: {"es":"El tubo muscular que transporta a urina del riñón para a bexiga urinária por medio de contraciones peristálticas.","de":"Der Muskelschlauch, der Urin von der Niere zur Harnblase durch peristaltische Kontraktionen transportiert.","fr":"Le tube musculaire qui transporte l'urine du rein à la vessie par des contractions péristaltiques.","tr":"Peristaltik kasılmalar aracılığıyla idrarı böbrekten idrar kesesine taşıyan kassal tüp.","nl":"De spierbuis die urine van de nier naar de urineblaas transporteert via peristaltische contracties.","ru":"Мышечная трубка, транспортирующая мочу от почки к мочевому пузырю посредством перистальтических сокращений.","zh":"通过蠕动收缩将尿液从肾脏输送至膀胱的肌性管道。","pt_BR":"O tubo muscular que transporta a urina do rim para a bexiga urinária por meio de contrações peristálticas.","pt_PT":"O tubo muscular que transporta a urina do rim para a bexiga urinária através de contrações peristálticas."}},
  { id: 'dc-anatomy-0067', deck_id: 'deck-anatomy', front: 'Spleen', back: 'An organ in the upper left abdomen that filters blood, destroys old red blood cells, and plays a role in immune function by housing lymphocytes.', sort_order: 67 , front_translations: {"es":"Baço","de":"Milz","fr":"Rate","tr":"Dalak","nl":"Milt","ru":"Селезёнка","zh":"脾脏","pt_BR":"Baço","pt_PT":"Baço"}, back_translations: {"es":"Un órgano en el abdomen superior esquerdo que filtra el sangre, destruye glóbulos vermelhos velhos y desempenha papel en la función imune abrigando linfócitos.","de":"Ein Organ im linken Oberbauch, das Blut filtert, alte rote Blutkörperchen abbaut und durch Beherbergung von Lymphozyten eine Rolle bei der Immunfunktion spielt.","fr":"Un organe dans l'abdomen supérieur gauche qui filtre le sang, détruit les vieux globules rouges et joue un rôle dans la fonction immunitaire en hébergeant des lymphocytes.","tr":"Kanı filtreleyen, eski kırmızı kan hücrelerini yok eden ve lenfositleri barındırarak bağışıklık fonksiyonunda rol oynayan sol üst karın organı.","nl":"Een orgaan in de linker bovenbuik dat bloed filtert, oude rode bloedcellen vernietigt en een rol speelt in de immuunfunctie door lymfocyten te huisvesten.","ru":"Орган в левом верхнем отделе живота, фильтрующий кровь, разрушающий старые эритроциты и участвующий в иммунной функции, депонируя лимфоциты.","zh":"位于左上腹的器官，负责过滤血液、破坏衰老红细胞，并通过容纳淋巴细胞参与免疫功能。","pt_BR":"Um órgão no abdômen superior esquerdo que filtra o sangue, destrói glóbulos vermelhos velhos e desempenha papel na função imune abrigando linfócitos.","pt_PT":"Um órgão no abdómen superior esquerdo que filtra o sangue, destrói glóbulos vermelhos velhos e desempenha um papel na função imune albergando linfócitos."}},
  { id: 'dc-anatomy-0068', deck_id: 'deck-anatomy', front: 'Stomach', back: 'A muscular sac in the upper abdomen that receives food from the esophagus, churns it with acid and enzymes, and produces chyme for delivery to the small intestine.', sort_order: 68 , front_translations: {"es":"Estomago","de":"Magen","fr":"Estomac","tr":"Mide","nl":"Maag","ru":"Желудок","zh":"胃","pt_BR":"Estômago","pt_PT":"Estômago"}, back_translations: {"es":"Un saco muscular en el abdomen superior que recibe alimentos del esofago, agita-los con ácido y enzimas, y produce quimo para entrega al intestino delgado.","de":"Ein Muskelbeutel im Oberbauch, der Nahrung aus der Speiseröhre aufnimmt, sie mit Säure und Enzymen vermengt und Chymus zur Abgabe an den Dünndarm produziert.","fr":"Un sac musculaire dans l'abdomen supérieur qui reçoit les aliments de l'œsophage, les malaxe avec des acides et des enzymes, et produit le chyme pour l'envoyer dans l'intestin grêle.","tr":"Yemek borusundan besin alan, onu asit ve enzimlerle yoğuran ve ince bağırsağa iletmek için kimus üreten üst karındaki kassal kese.","nl":"Een spierkuil in de bovenbuik die voedsel van de slokdarm ontvangt, het mengt met zuur en enzymen, en chyme produceert voor afgifte aan de dunne darm.","ru":"Мышечный мешок в верхней части живота, принимающий пищу из пищевода, перемешивающий её с кислотой и ферментами и образующий химус для передачи в тонкую кишку.","zh":"位于上腹部的肌性囊袋，接收来自食管的食物，通过酸和酶将其搅拌，并产生食糜以输送至小肠。","pt_BR":"Um saco muscular no abdômen superior que recebe alimentos do esôfago, agita-os com ácido e enzimas, e produz quimo para entrega ao intestino delgado.","pt_PT":"Um saco muscular no abdómen superior que recebe alimentos do esófago, mistura-os com ácido e enzimas, e produz quimo para entrega ao intestino delgado."}},
  { id: 'dc-anatomy-0069', deck_id: 'deck-anatomy', front: 'Small Intestine', back: 'A ~6-meter tube comprising the duodenum, jejunum, and ileum; the primary site of digestion and nutrient absorption.', sort_order: 69 , front_translations: {"es":"Intestino delgado","de":"Dünndarm","fr":"Intestin grêle","tr":"İnce Bağırsak","nl":"Dunne darm","ru":"Тонкая кишка","zh":"小肠","pt_BR":"Intestino delgado","pt_PT":"Intestino delgado"}, back_translations: {"es":"Un tubo de ~6 metros compuesto por el duodeno, jejuno y íleo; el principal local de digestión y absorción de nutrientes.","de":"Ein ca. 6 Meter langer Schlauch, der aus Duodenum, Jejunum und Ileum besteht; der primäre Ort für Verdauung und Nährstoffabsorption.","fr":"Un tube d'environ 6 mètres comprenant le duodénum, le jéjunum et l'iléon ; principal site de digestion et d'absorption des nutriments.","tr":"Duodenum, jejunum ve ileumdan oluşan yaklaşık 6 metrelik tüp; sindirim ve besin emiliminin birincil yeri.","nl":"Een buis van ~6 meter bestaande uit het duodenum, jejunum en ileum; de primaire locatie voor spijsvertering en voedselopname.","ru":"Трубка длиной около 6 метров, состоящая из двенадцатиперстной, тощей и подвздошной кишок; основное место переваривания и всасывания питательных веществ.","zh":"由十二指肠、空肠和回肠组成的约6米长管道；是消化和营养物质吸收的主要场所。","pt_BR":"Um tubo de ~6 metros composto pelo duodeno, jejuno e íleo; o principal local de digestão e absorção de nutrientes.","pt_PT":"Um tubo de ~6 metros composto pelo duodeno, jejuno e íleo; o principal local de digestão e absorção de nutrientes."}},
  { id: 'dc-anatomy-0070', deck_id: 'deck-anatomy', front: 'Large Intestine', back: 'The colon and rectum; it absorbs water and electrolytes from indigestible food matter and forms and stores feces before elimination.', sort_order: 70 , front_translations: {"es":"Intestino grueso","de":"Dickdarm","fr":"Gros intestin","tr":"Kalın Bağırsak","nl":"Dikke darm","ru":"Толстая кишка","zh":"大肠","pt_BR":"Intestino grosso","pt_PT":"Intestino grosso"}, back_translations: {"es":"El cólon y el reto; absorben agua y eletrólitos de resíduos alimentares indigestibles y forman y almacenan fezes antes de la eliminación.","de":"Kolon und Rektum; sie resorbieren Wasser und Elektrolyte aus unverdaulichen Nahrungsresten und formen und speichern Fäkalien vor der Ausscheidung.","fr":"Le côlon et le rectum ; il absorbe l'eau et les électrolytes des matières alimentaires indigestes, et forme et stocke les fèces avant l'élimination.","tr":"Kolon ve rektum; sindirilemeyen gıda maddelerinden su ve elektrolit emer, dışkıyı oluşturur ve atılmadan önce depolar.","nl":"Het colon en rectum; het absorbeert water en elektrolyten uit onverteerbaar voedselmateriaal en vormt en bewaart feces voor eliminatie.","ru":"Ободочная и прямая кишки; всасывают воду и электролиты из неперевариваемых пищевых остатков, формируют и хранят кал перед выведением.","zh":"结肠和直肠；从不可消化的食物残渣中吸收水分和电解质，并在排泄前形成和储存粪便。","pt_BR":"O cólon e o reto; absorvem água e eletrólitos de resíduos alimentares indigestíveis e formam e armazenam fezes antes da eliminação.","pt_PT":"O cólon e o reto; absorvem água e eletrólitos de resíduos alimentares indigeríveis e formam e armazenam fezes antes da eliminação."}},
  { id: 'dc-anatomy-0071', deck_id: 'deck-anatomy', front: 'Appendix', back: 'A small finger-shaped pouch attached to the cecum of the large intestine; its function is debated but it may play a role in gut immunity.', sort_order: 71 , front_translations: {"es":"Apéndice","de":"Blinddarm (Appendix)","fr":"Appendice","tr":"Apandis","nl":"Blindedarm (appendix)","ru":"Аппендикс","zh":"阑尾","pt_BR":"Apêndice","pt_PT":"Apêndice"}, back_translations: {"es":"Una pequeña bolsa en forma de dedo ligada al ceco del intestino grueso; su función es debatida, pero puede desempenhar un papel en la imunidad intestinal.","de":"Ein kleiner fingerförmiger Beutel, der am Zökum des Dickdarms befestigt ist; seine Funktion ist umstritten, aber er könnte eine Rolle bei der Darmimmunität spielen.","fr":"Une petite poche en forme de doigt attachée au caecum du gros intestin ; sa fonction est débattue mais elle pourrait jouer un rôle dans l'immunité intestinale.","tr":"Kalın bağırsağın çekumuna bağlı küçük parmak şekilli bir kese; fonksiyonu tartışmalı olmakla birlikte bağırsak bağışıklığında rol oynayabilir.","nl":"Een kleine vingervormige uitstulping bevestigd aan het caecum van de dikke darm; zijn functie wordt betwist maar het kan een rol spelen in darmimmuniteit.","ru":"Небольшой пальцеобразный отросток, прикреплённый к слепой кишке; его функция остаётся предметом дискуссий, однако он может играть роль в кишечном иммунитете.","zh":"附着于大肠盲肠的小型指状突起；其功能尚有争议，但可能在肠道免疫中发挥作用。","pt_BR":"Uma pequena bolsa em forma de dedo ligada ao ceco do intestino grosso; sua função é debatida, mas pode desempenhar um papel na imunidade intestinal.","pt_PT":"Uma pequena bolsa em forma de dedo ligada ao ceco do intestino grosso; a sua função é debatida, mas pode desempenhar um papel na imunidade intestinal."}},
  { id: 'dc-anatomy-0072', deck_id: 'deck-anatomy', front: 'Esophagus', back: 'The muscular tube connecting the pharynx to the stomach; it transports food via peristalsis and is about 25 cm long in adults.', sort_order: 72 , front_translations: {"es":"Esofago","de":"Speiseröhre (Ösophagus)","fr":"Œsophage","tr":"Yemek Borusu (Özofagus)","nl":"Slokdarm (oesofagus)","ru":"Пищевод","zh":"食管","pt_BR":"Esôfago","pt_PT":"Esófago"}, back_translations: {"es":"El tubo muscular que conecta a faringe al estomago; transporta alimentos por peristaltismo y tiene cerca de 25 cm de comprimento en adultos.","de":"Der Muskelschlauch, der den Rachen mit dem Magen verbindet; er transportiert Nahrung durch Peristaltik und ist bei Erwachsenen etwa 25 cm lang.","fr":"Le tube musculaire reliant le pharynx à l'estomac ; il transporte les aliments par péristaltisme et mesure environ 25 cm chez l'adulte.","tr":"Farinksi mideye bağlayan kassal tüp; besinleri peristaltizm yoluyla taşır ve yetişkinlerde yaklaşık 25 cm uzunluğundadır.","nl":"De spierbuis die de keel met de maag verbindt; het transporteert voedsel via peristaltiek en is bij volwassenen ongeveer 25 cm lang.","ru":"Мышечная трубка, соединяющая глотку с желудком; транспортирует пищу посредством перистальтики и имеет длину около 25 см у взрослых.","zh":"连接咽部与胃部的肌性管道；通过蠕动运输食物，成人食管长约25厘米。","pt_BR":"O tubo muscular que conecta a faringe ao estômago; transporta alimentos por peristaltismo e tem cerca de 25 cm de comprimento em adultos.","pt_PT":"O tubo muscular que liga a faringe ao estômago; transporta alimentos por peristaltismo e tem cerca de 25 cm de comprimento em adultos."}},
  { id: 'dc-anatomy-0073', deck_id: 'deck-anatomy', front: 'Cerebrum', back: 'The largest part of the brain, divided into two hemispheres; it controls voluntary movement, sensory processing, language, and higher cognitive functions.', sort_order: 73 , front_translations: {"es":"Cerebro","de":"Großhirn (Zerebrum)","fr":"Cerveau","tr":"Serebrum (Büyük Beyin)","nl":"Grote hersenen (cerebrum)","ru":"Большой мозг (церебрум)","zh":"大脑","pt_BR":"Cérebro","pt_PT":"Cérebro"}, back_translations: {"es":"La mayor parte del encéfalo, dividida en de los hemisférios; controla movimientos voluntários, procesamiento sensorial, linguaje y funciones cognitivas superiores.","de":"Der größte Teil des Gehirns, in zwei Hemisphären unterteilt; er steuert willkürliche Bewegungen, Sinnesverarbeitung, Sprache und höhere kognitive Funktionen.","fr":"La plus grande partie du cerveau, divisée en deux hémisphères ; il contrôle les mouvements volontaires, le traitement sensoriel, le langage et les fonctions cognitives supérieures.","tr":"Beynin en büyük kısmı, iki yarımküreye bölünmüştür; istemli hareketi, duyusal işlemeyi, dili ve yüksek bilişsel fonksiyonları kontrol eder.","nl":"Het grootste deel van de hersenen, verdeeld in twee hemisferen; het regelt vrijwillige beweging, zintuiglijke verwerking, taal en hogere cognitieve functies.","ru":"Наибольшая часть головного мозга, разделённая на два полушария; управляет произвольными движениями, сенсорной обработкой, речью и высшими когнитивными функциями.","zh":"大脑最大的部分，分为两个半球；控制随意运动、感觉处理、语言和高级认知功能。","pt_BR":"A maior parte do encéfalo, dividida em dois hemisférios; controla movimentos voluntários, processamento sensorial, linguagem e funções cognitivas superiores.","pt_PT":"A maior parte do encéfalo, dividida em dois hemisférios; controla movimentos voluntários, processamento sensorial, linguagem e funções cognitivas superiores."}},
  { id: 'dc-anatomy-0074', deck_id: 'deck-anatomy', front: 'Cerebellum', back: 'The "little brain" at the back of the skull; it coordinates voluntary movements, balance, and fine motor control.', sort_order: 74 , front_translations: {"es":"Cerebelo","de":"Kleinhirn (Zerebellum)","fr":"Cervelet","tr":"Serebellum (Beyincik)","nl":"Kleine hersenen (cerebellum)","ru":"Мозжечок","zh":"小脑","pt_BR":"Cerebelo","pt_PT":"Cerebelo"}, back_translations: {"es":"El \"pequeño cerebro\" en la parte posterior del cráneo; coordena movimientos voluntários, equilíbrio y controle motor delgado.","de":"Das „kleine Gehirn“ an der Rückseite des Schädels; es koordiniert willkürliche Bewegungen, Gleichgewicht und Feinmotorik.","fr":"Le « petit cerveau » à l'arrière du crâne ; il coordonne les mouvements volontaires, l'équilibre et la motricité fine.","tr":"Kafatasının arka kısmındaki \"küçük beyin\"; istemli hareketleri, dengeyi ve ince motor kontrolü koordine eder.","nl":"De 'kleine hersenen' aan de achterkant van de schedel; het coördineert vrijwillige bewegingen, evenwicht en fijne motoriek.","ru":"«Маленький мозг» в задней части черепа; координирует произвольные движения, равновесие и тонкую моторику.","zh":"位于颅骨后部的\"小脑\"；协调随意运动、平衡和精细运动控制。","pt_BR":"O \"pequeno cérebro\" na parte posterior do crânio; coordena movimentos voluntários, equilíbrio e controle motor fino.","pt_PT":"O \"pequeno cérebro\" na parte posterior do crânio; coordena movimentos voluntários, equilíbrio e controlo motor fino."}},
  { id: 'dc-anatomy-0075', deck_id: 'deck-anatomy', front: 'Brain Stem', back: 'The posterior part of the brain connecting the cerebrum to the spinal cord; it controls vital functions like breathing, heart rate, and blood pressure.', sort_order: 75 , front_translations: {"es":"Tronco encefálico","de":"Hirnstamm","fr":"Tronc cérébral","tr":"Beyin Sapı","nl":"Hersenstam","ru":"Ствол мозга","zh":"脑干","pt_BR":"Tronco encefálico","pt_PT":"Tronco encefálico"}, back_translations: {"es":"La parte posterior del encéfalo que conecta el cerebro a la médula espinal; controla funciones vitais como respiración, frecuencia cardíaca y presión arterial.","de":"Der hintere Teil des Gehirns, der das Großhirn mit dem Rückenmark verbindet; er kontrolliert lebenswichtige Funktionen wie Atmung, Herzfrequenz und Blutdruck.","fr":"La partie postérieure du cerveau reliant le cerveau à la moelle épinière ; elle contrôle les fonctions vitales comme la respiration, la fréquence cardiaque et la pression artérielle.","tr":"Serebrumu omuriliğe bağlayan beynin arka kısmı; solunum, kalp hızı ve kan basıncı gibi hayati fonksiyonları kontrol eder.","nl":"Het achterste deel van de hersenen dat de grote hersenen verbindt met het ruggenmerg; het regelt vitale functies zoals ademhaling, hartslag en bloeddruk.","ru":"Задняя часть головного мозга, соединяющая большой мозг со спинным; контролирует жизненно важные функции — дыхание, частоту сердечных сокращений и артериальное давление.","zh":"连接大脑与脊髓的后脑部分；控制呼吸、心率和血压等重要生命功能。","pt_BR":"A parte posterior do encéfalo que conecta o cérebro à medula espinhal; controla funções vitais como respiração, frequência cardíaca e pressão arterial.","pt_PT":"A parte posterior do encéfalo que liga o cérebro à medula espinhal; controla funções vitais como a respiração, frequência cardíaca e pressão arterial."}},
  { id: 'dc-anatomy-0076', deck_id: 'deck-anatomy', front: 'Frontal Lobe', back: 'The anterior cerebral lobe responsible for executive functions, voluntary movement (primary motor cortex), personality, and Broca\'s speech area.', sort_order: 76 , front_translations: {"es":"Lobo frontal","de":"Frontallappen","fr":"Lobe frontal","tr":"Frontal Lob","nl":"Frontale kwab","ru":"Лобная доля","zh":"额叶","pt_BR":"Lobo frontal","pt_PT":"Lobo frontal"}, back_translations: {"es":"El lobo cerebral anterior responsable por las funciones executivas, movimientos voluntários (córtex motor primário), personalidad y área de Broca.","de":"Der vordere Hirnlappen, verantwortlich für exekutive Funktionen, willkürliche Bewegung (primärer motorischer Kortex), Persönlichkeit und Brocas Sprachzentrum.","fr":"Le lobe cérébral antérieur responsable des fonctions exécutives, des mouvements volontaires (cortex moteur primaire), de la personnalité et de l'aire de Broca.","tr":"Yürütme fonksiyonlarından, istemli hareketten (birincil motor korteks), kişilikten ve Broca konuşma alanından sorumlu ön serebral lob.","nl":"De voorste hersenkwab verantwoordelijk voor uitvoerende functies, vrijwillige beweging (primaire motorcortex), persoonlijkheid en Broca's spraakgebied.","ru":"Передняя доля мозга, отвечающая за исполнительные функции, произвольные движения (первичная моторная кора), личность и речевой центр Брока.","zh":"大脑前部的脑叶，负责执行功能、随意运动（初级运动皮层）、个性和布罗卡语言区。","pt_BR":"O lobo cerebral anterior responsável pelas funções executivas, movimentos voluntários (córtex motor primário), personalidade e área de Broca.","pt_PT":"O lobo cerebral anterior responsável pelas funções executivas, movimentos voluntários (córtex motor primário), personalidade e área de Broca."}},
  { id: 'dc-anatomy-0077', deck_id: 'deck-anatomy', front: 'Parietal Lobe', back: 'The cerebral lobe behind the frontal lobe; it processes somatosensory information (touch, temperature, pain) and spatial awareness.', sort_order: 77 , front_translations: {"es":"Lobo parietal","de":"Scheitellappen","fr":"Lobe pariétal","tr":"Parietal Lob","nl":"Pariëtale kwab","ru":"Теменная доля","zh":"顶叶","pt_BR":"Lobo parietal","pt_PT":"Lobo parietal"}, back_translations: {"es":"El lobo cerebral atrás del lobo frontal; processa informaciones somatossensoriais (toque, temperatura, dor) y conciencia espacial.","de":"Der Hirnlappen hinter dem Frontallappen; er verarbeitet somatosensorische Informationen (Berührung, Temperatur, Schmerz) und räumliches Bewusstsein.","fr":"Le lobe cérébral derrière le lobe frontal ; il traite les informations somesthésiques (toucher, température, douleur) et la conscience spatiale.","tr":"Frontal lobun arkasındaki serebral lob; somatosensöryal bilgileri (dokunma, sıcaklık, ağrı) ve mekansal farkındalığı işler.","nl":"De hersenkwab achter de frontale kwab; het verwerkt somatosensorische informatie (aanraking, temperatuur, pijn) en ruimtelijk bewustzijn.","ru":"Доля мозга позади лобной доли; обрабатывает соматосенсорную информацию (прикосновение, температуру, боль) и пространственное восприятие.","zh":"位于额叶后方的大脑叶；处理躯体感觉信息（触觉、温度、疼痛）和空间感知。","pt_BR":"O lobo cerebral atrás do lobo frontal; processa informações somatossensoriais (toque, temperatura, dor) e consciência espacial.","pt_PT":"O lobo cerebral atrás do lobo frontal; processa informações somatossensoriais (toque, temperatura, dor) e consciência espacial."}},
  { id: 'dc-anatomy-0078', deck_id: 'deck-anatomy', front: 'Temporal Lobe', back: 'The lateral cerebral lobe that processes auditory information and is involved in memory (hippocampus) and Wernicke\'s language comprehension area.', sort_order: 78 , front_translations: {"es":"Lobo temporal","de":"Schläfenlappen","fr":"Lobe temporal","tr":"Temporal Lob","nl":"Temporale kwab","ru":"Височная доля","zh":"颞叶","pt_BR":"Lobo temporal","pt_PT":"Lobo temporal"}, back_translations: {"es":"El lobo cerebral lateral que processa informaciones auditivas y está involucrado en la memoria (hipocampo) y en la área de compreensão de la linguaje de Wernicke.","de":"Der seitliche Hirnlappen, der auditive Informationen verarbeitet und an Gedächtnis (Hippocampus) und Wernickes Sprachverständniszentrum beteiligt ist.","fr":"Le lobe cérébral latéral qui traite les informations auditives et est impliqué dans la mémoire (hippocampe) et l'aire de compréhension du langage de Wernicke.","tr":"İşitsel bilgileri işleyen ve bellek (hipokampüs) ile Wernicke dil anlama alanına dahil olan lateral serebral lob.","nl":"De laterale hersenkwab die auditieve informatie verwerkt en betrokken is bij geheugen (hippocampus) en Wernicke's taalcomprehensiegebied.","ru":"Боковая доля мозга, обрабатывающая слуховую информацию и участвующая в памяти (гиппокамп) и речевом центре Вернике.","zh":"外侧大脑叶，处理听觉信息，并参与记忆（海马体）和韦尼克语言理解区的功能。","pt_BR":"O lobo cerebral lateral que processa informações auditivas e está envolvido na memória (hipocampo) e na área de compreensão da linguagem de Wernicke.","pt_PT":"O lobo cerebral lateral que processa informações auditivas e está envolvido na memória (hipocampo) e na área de compreensão da linguagem de Wernicke."}},
  { id: 'dc-anatomy-0079', deck_id: 'deck-anatomy', front: 'Occipital Lobe', back: 'The posterior cerebral lobe dedicated to visual processing; it interprets signals from the retinas.', sort_order: 79 , front_translations: {"es":"Lobo occipital","de":"Hinterhauptslappen","fr":"Lobe occipital","tr":"Oksipital Lob","nl":"Occipitale kwab","ru":"Затылочная доля","zh":"枕叶","pt_BR":"Lobo occipital","pt_PT":"Lobo occipital"}, back_translations: {"es":"El lobo cerebral posterior dedicado al procesamiento visual; interpreta señales de las retinas.","de":"Der hintere Hirnlappen, der der visuellen Verarbeitung gewidmet ist; er interpretiert Signale von den Netzhäuten.","fr":"Le lobe cérébral postérieur dédié au traitement visuel ; il interprète les signaux provenant des rétines.","tr":"Görsel işlemeye adanmış posterior serebral lob; retinalardan gelen sinyalleri yorumlar.","nl":"De achterste hersenkwab gewijd aan visuele verwerking; het interpreteert signalen van de netvliezen.","ru":"Задняя доля мозга, отвечающая за зрительную обработку; интерпретирует сигналы от сетчаток.","zh":"专司视觉处理的后部大脑叶；解读来自视网膜的信号。","pt_BR":"O lobo cerebral posterior dedicado ao processamento visual; interpreta sinais das retinas.","pt_PT":"O lobo cerebral posterior dedicado ao processamento visual; interpreta sinais das retinas."}},
  { id: 'dc-anatomy-0080', deck_id: 'deck-anatomy', front: 'Hippocampus', back: 'A seahorse-shaped structure in the temporal lobe; critical for forming new memories and spatial navigation.', sort_order: 80 , front_translations: {"es":"Hipocampo","de":"Hippocampus","fr":"Hippocampe","tr":"Hipokampüs","nl":"Hippocampus","ru":"Гиппокамп","zh":"海马体","pt_BR":"Hipocampo","pt_PT":"Hipocampo"}, back_translations: {"es":"Una estructura en forma de cavalo-marinho en el lobo temporal; crucial para a formación de nuevas memorias y navegación espacial.","de":"Eine seepferdchenförmige Struktur im Schläfenlappen; entscheidend für die Bildung neuer Erinnerungen und räumliche Navigation.","fr":"Une structure en forme de hippocampe dans le lobe temporal ; essentielle pour la formation de nouveaux souvenirs et la navigation spatiale.","tr":"Temporal lobdaki at nalı şekilli yapı; yeni anıların oluşturulması ve uzamsal navigasyon için kritik öneme sahiptir.","nl":"Een zeepaardje-vormige structuur in de temporale kwab; cruciaal voor het vormen van nieuwe herinneringen en ruimtelijke navigatie.","ru":"Структура в форме морского конька в височной доле; критически важна для формирования новых воспоминаний и пространственной навигации.","zh":"颞叶中海马形状的结构；对形成新记忆和空间导航至关重要。","pt_BR":"Uma estrutura em forma de cavalo-marinho no lobo temporal; crucial para a formação de novas memórias e navegação espacial.","pt_PT":"Uma estrutura em forma de cavalo-marinho no lobo temporal; crucial para a formação de novas memórias e navegação espacial."}},
  { id: 'dc-anatomy-0081', deck_id: 'deck-anatomy', front: 'Amygdala', back: 'An almond-shaped structure in the temporal lobe that processes emotions, particularly fear and aggression, and plays a role in emotional memory.', sort_order: 81 , front_translations: {"es":"Amígdala","de":"Amygdala","fr":"Amygdale","tr":"Amigdala","nl":"Amygdala","ru":"Миндалевидное тело","zh":"杏仁核","pt_BR":"Amígdala","pt_PT":"Amígdala"}, back_translations: {"es":"Una estructura en forma de amendoa en el lobo temporal que processa emociones, particularmente medo y agresión, y desempenha papel en la memoria emocional.","de":"Eine mandelförmige Struktur im Schläfenlappen, die Emotionen, insbesondere Angst und Aggression, verarbeitet und eine Rolle im emotionalen Gedächtnis spielt.","fr":"Une structure en forme d'amande dans le lobe temporal qui traite les émotions, notamment la peur et l'agressivité, et joue un rôle dans la mémoire émotionnelle.","tr":"Duyguları, özellikle korku ve saldırganlığı işleyen ve duygusal bellekte rol oynayan temporal lobdaki badem şekilli yapı.","nl":"Een amandelvormige structuur in de temporale kwab die emoties verwerkt, met name angst en agressie, en een rol speelt in emotioneel geheugen.","ru":"Миндалевидная структура в височной доле, обрабатывающая эмоции, особенно страх и агрессию, и участвующая в формировании эмоциональной памяти.","zh":"颞叶中杏仁状结构，处理情绪，尤其是恐惧和攻击性，并在情绪记忆中发挥作用。","pt_BR":"Uma estrutura em forma de amêndoa no lobo temporal que processa emoções, particularmente medo e agressão, e desempenha papel na memória emocional.","pt_PT":"Uma estrutura em forma de amêndoa no lobo temporal que processa emoções, particularmente medo e agressão, e desempenha um papel na memória emocional."}},
  { id: 'dc-anatomy-0082', deck_id: 'deck-anatomy', front: 'Hypothalamus', back: 'A small region at the base of the brain that regulates body temperature, hunger, thirst, sleep, and hormone release via the pituitary gland.', sort_order: 82 , front_translations: {"es":"Hipotálamo","de":"Hypothalamus","fr":"Hypothalamus","tr":"Hipotalamus","nl":"Hypothalamus","ru":"Гипоталамус","zh":"下丘脑","pt_BR":"Hipotálamo","pt_PT":"Hipotálamo"}, back_translations: {"es":"Una pequeña región en la base del cerebro que regula temperatura corporal, fome, sede, sono y liberación hormonal via glándula pituitária.","de":"Eine kleine Region an der Basis des Gehirns, die Körpertemperatur, Hunger, Durst, Schlaf und die Hormonfreisetzung über die Hypophyse reguliert.","fr":"Une petite région à la base du cerveau qui régule la température corporelle, la faim, la soif, le sommeil et la libération d'hormones via l'hypophyse.","tr":"Hipofiz bezi aracılığıyla vücut sıcaklığını, açlığı, susuzluğu, uykuyu ve hormon salınımını düzenleyen beyin tabanındaki küçük bölge.","nl":"Een klein gebied aan de basis van de hersenen dat lichaamstemperatuur, honger, dorst, slaap en hormoonafgifte via de hypofyse reguleert.","ru":"Небольшая область в основании мозга, регулирующая температуру тела, голод, жажду, сон и высвобождение гормонов посредством гипофиза.","zh":"大脑底部的小区域，通过垂体调节体温、饥饿、口渴、睡眠和激素释放。","pt_BR":"Uma pequena região na base do cérebro que regula temperatura corporal, fome, sede, sono e liberação hormonal via glândula pituitária.","pt_PT":"Uma pequena região na base do cérebro que regula a temperatura corporal, a fome, a sede, o sono e a libertação hormonal através da glândula pituitária."}},
  { id: 'dc-anatomy-0083', deck_id: 'deck-anatomy', front: 'Thalamus', back: 'A relay station in the diencephalon that receives sensory signals and routes them to the appropriate cortical areas for processing.', sort_order: 83 , front_translations: {"es":"Tálamo","de":"Thalamus","fr":"Thalamus","tr":"Talamus","nl":"Thalamus","ru":"Таламус","zh":"丘脑","pt_BR":"Tálamo","pt_PT":"Tálamo"}, back_translations: {"es":"Una estación de retransmisión en el diencéfalo que recibe señales sensoriais y los encaminha para las áreas corticais apropriadas para procesamiento.","de":"Eine Relaisstation im Diencephalon, die sensorische Signale empfängt und sie zur Verarbeitung an die entsprechenden kortikalen Bereiche weiterleitet.","fr":"Un centre de relais dans le diencéphale qui reçoit les signaux sensoriels et les achemine vers les zones corticales appropriées pour traitement.","tr":"Duyusal sinyalleri alan ve işleme için uygun kortikal alanlara yönlendiren diensefalondaki aktarma istasyonu.","nl":"Een relaisstation in het diëncephalon dat sensorische signalen ontvangt en ze doorstuurt naar de juiste corticale gebieden voor verwerking.","ru":"Релейная станция в промежуточном мозге, получающая сенсорные сигналы и направляющая их в соответствующие корковые зоны для обработки.","zh":"间脑中的中继站，接收感觉信号并将其传递至相应的皮质区域进行处理。","pt_BR":"Uma estação de retransmissão no diencéfalo que recebe sinais sensoriais e os encaminha para as áreas corticais apropriadas para processamento.","pt_PT":"Uma estação de retransmissão no diencéfalo que recebe sinais sensoriais e os encaminha para as áreas corticais apropriadas para processamento."}},
  { id: 'dc-anatomy-0084', deck_id: 'deck-anatomy', front: 'Medulla Oblongata', back: 'The lowest part of the brain stem; it controls vital autonomic functions including heart rate, blood pressure, and respiratory rhythm.', sort_order: 84 , front_translations: {"es":"Bulbo raquidiano (medula oblonga)","de":"Verlängertes Mark (Medulla oblongata)","fr":"Bulbe rachidien (moelle allongée)","tr":"Medulla Oblongata (Omurilik Soğanı)","nl":"Verlengde merg (medulla oblongata)","ru":"Продолговатый мозг","zh":"延髓","pt_BR":"Bulbo raquidiano (medula oblonga)","pt_PT":"Bulbo raquidiano (medula oblonga)"}, back_translations: {"es":"La parte más baja del tronco encefálico; controla funciones autonomicas vitais incluyendo frecuencia cardíaca, presión arterial y ritmo respiratório.","de":"Der unterste Teil des Hirnstamms; er kontrolliert lebenswichtige autonome Funktionen einschließlich Herzfrequenz, Blutdruck und Atemrhythmus.","fr":"La partie la plus basse du tronc cérébral ; elle contrôle les fonctions autonomes vitales dont la fréquence cardiaque, la pression artérielle et le rythme respiratoire.","tr":"Beyin sapının en alt kısmı; kalp hızı, kan basıncı ve solunum ritmi dahil hayati otonom fonksiyonları kontrol eder.","nl":"Het laagste deel van de hersenstam; het regelt vitale autonome functies waaronder hartslag, bloeddruk en ademhalingsritme.","ru":"Нижняя часть ствола мозга; управляет жизненно важными вегетативными функциями, включая частоту сердечных сокращений, артериальное давление и дыхательный ритм.","zh":"脑干最下部；控制心率、血压和呼吸节律等重要自主神经功能。","pt_BR":"A parte mais baixa do tronco encefálico; controla funções autonômicas vitais incluindo frequência cardíaca, pressão arterial e ritmo respiratório.","pt_PT":"A parte mais baixa do tronco encefálico; controla funções autonómicas vitais incluindo frequência cardíaca, pressão arterial e ritmo respiratório."}},
  { id: 'dc-anatomy-0085', deck_id: 'deck-anatomy', front: 'Corpus Callosum', back: 'A broad band of nerve fibers connecting the left and right cerebral hemispheres, allowing them to communicate with each other.', sort_order: 85 , front_translations: {"es":"Cuerpo caloso","de":"Balken (Corpus callosum)","fr":"Corps calleux","tr":"Korpus Kallozum","nl":"Hersenbalk (corpus callosum)","ru":"Мозолистое тело","zh":"胼胝体","pt_BR":"Corpo caloso","pt_PT":"Corpo caloso"}, back_translations: {"es":"Una ampla franja de fibras nervosas que conecta los hemisférios cerebrais esquerdo y derecho, permitiendo que se comuniquem entre si.","de":"Ein breites Band von Nervenfasern, das die linke und rechte Hirnhemisphäre verbindet und ihnen ermöglicht, miteinander zu kommunizieren.","fr":"Une large bande de fibres nerveuses reliant les hémisphères cérébraux gauche et droit, leur permettant de communiquer entre eux.","tr":"Sol ve sağ serebral hemisferleri birbirine bağlayan ve aralarında iletişimi sağlayan geniş sinir lifi bandı.","nl":"Een breed band van zenuwvezels die de linker en rechter hersenhemisferen verbinden, waardoor ze met elkaar kunnen communiceren.","ru":"Широкая полоса нервных волокон, соединяющая левое и правое полушария головного мозга и обеспечивающая их взаимодействие.","zh":"连接左右大脑半球的宽阔神经纤维束，使两个半球能够相互沟通。","pt_BR":"Uma ampla faixa de fibras nervosas que conecta os hemisférios cerebrais esquerdo e direito, permitindo que se comuniquem entre si.","pt_PT":"Uma ampla faixa de fibras nervosas que liga os hemisférios cerebrais esquerdo e direito, permitindo que se comuniquem entre si."}},
  { id: 'dc-anatomy-0086', deck_id: 'deck-anatomy', front: 'Pituitary Gland', back: 'The "master gland" at the base of the brain; it releases hormones that control other endocrine glands, growth, and bodily functions.', sort_order: 86 , front_translations: {"es":"Glándula pituitária","de":"Hypophyse","fr":"Glande pituitaire","tr":"Hipofiz Bezi","nl":"Hypofyse","ru":"Гипофиз","zh":"垂体","pt_BR":"Glândula pituitária","pt_PT":"Glândula pituitária"}, back_translations: {"es":"La \"glándula mestre\" en la base del cerebro; libera hormonas que controlan outras glándulas endócrinas, crecimiento y funciones corporais.","de":"Die „Masterdrüse\" an der Basis des Gehirns; sie setzt Hormone frei, die andere endokrine Drüsen, das Wachstum und die Körperfunktionen steuern.","fr":"La « glande maîtresse » à la base du cerveau ; elle libère des hormones qui contrôlent les autres glandes endocrines, la croissance et les fonctions corporelles.","tr":"Beyin tabanındaki \"ana bez\"; diğer endokrin bezleri, büyümeyi ve vücut fonksiyonlarını kontrol eden hormonlar salgılar.","nl":"De 'meesterklier' aan de basis van de hersenen; het geeft hormonen vrij die andere endocriene klieren, groei en lichaamsfuncties regelen.","ru":"«Главная железа» у основания мозга; выделяет гормоны, управляющие другими эндокринными железами, ростом и функциями организма.","zh":"位于大脑底部的\"主腺\"；释放控制其他内分泌腺、生长和身体功能的激素。","pt_BR":"A \"glândula mestre\" na base do cérebro; libera hormônios que controlam outras glândulas endócrinas, crescimento e funções corporais.","pt_PT":"A \"glândula mestre\" na base do cérebro; liberta hormonas que controlam outras glândulas endócrinas, o crescimento e as funções corporais."}},
  { id: 'dc-anatomy-0087', deck_id: 'deck-anatomy', front: 'Thyroid Gland', back: 'A butterfly-shaped gland in the neck that produces thyroxine (T4) and triiodothyronine (T3), regulating metabolism, energy, and growth.', sort_order: 87 , front_translations: {"es":"Glándula tireoide","de":"Schilddrüse","fr":"Glande thyroïde","tr":"Tiroid Bezi","nl":"Schildklier","ru":"Щитовидная железа","zh":"甲状腺","pt_BR":"Glândula tireoide","pt_PT":"Glândula tiróide"}, back_translations: {"es":"Una glándula en forma de borboleta en el cuello que produce tiroxina (T4) y tri-iodotironina (T3), regulando el metabolismo, energía y crecimiento.","de":"Eine schmetterlingsförmige Drüse im Nacken, die Thyroxin (T4) und Trijodthyronin (T3) produziert, die Stoffwechsel, Energie und Wachstum regulieren.","fr":"Une glande en forme de papillon dans le cou qui produit la thyroxine (T4) et la triiodothyronine (T3), régulant le métabolisme, l'énergie et la croissance.","tr":"Metabolizmayı, enerjiyi ve büyümeyi düzenleyen tiroksin (T4) ve triiyodotironin (T3) üreten boyundaki kelebek şekilli bez.","nl":"Een vlindervormige klier in de nek die thyroxine (T4) en trijoodthyronine (T3) produceert, die stofwisseling, energie en groei reguleren.","ru":"Железа в форме бабочки на шее, вырабатывающая тироксин (Т4) и трийодтиронин (Т3), регулирующие обмен веществ, энергию и рост.","zh":"颈部蝴蝶形腺体，产生甲状腺素（T4）和三碘甲状腺原氨酸（T3），调节新陈代谢、能量和生长。","pt_BR":"Uma glândula em forma de borboleta no pescoço que produz tiroxina (T4) e tri-iodotironina (T3), regulando o metabolismo, energia e crescimento.","pt_PT":"Uma glândula em forma de borboleta no pescoço que produz tiroxina (T4) e tri-iodotironina (T3), regulando o metabolismo, energia e crescimento."}},
  { id: 'dc-anatomy-0088', deck_id: 'deck-anatomy', front: 'Parathyroid Glands', back: 'Four tiny glands on the posterior thyroid that produce parathyroid hormone (PTH) to regulate blood calcium and phosphate levels.', sort_order: 88 , front_translations: {"es":"Glándulas paratireoides","de":"Nebenschilddrüsen","fr":"Glandes parathyroïdes","tr":"Paratiroid Bezleri","nl":"Bijschildklieren","ru":"Паращитовидные железы","zh":"甲状旁腺","pt_BR":"Glândulas paratireoides","pt_PT":"Glândulas paratireoides"}, back_translations: {"es":"Cuatro pequeñas glándulas en la face posterior de la tireoide que producen paratormonio (PTH) para regular los niveles de cálcio y fosfato en el sangre.","de":"Vier winzige Drüsen an der hinteren Schilddrüse, die Parathormon (PTH) produzieren, um den Kalzium- und Phosphatspiegel im Blut zu regulieren.","fr":"Quatre petites glandes sur la face postérieure de la thyroïde qui produisent la parathormone (PTH) pour réguler les taux de calcium et de phosphate dans le sang.","tr":"Kan kalsiyum ve fosfat düzeylerini düzenlemek için paratiroid hormon (PTH) üreten tiroidin arka yüzündeki dört küçük bez.","nl":"Vier kleine klieren op de achterste schildklier die parathyroïdhormoon (PTH) produceren om calcium- en fosfaatspiegels in het bloed te reguleren.","ru":"Четыре крошечные железы на задней поверхности щитовидной железы, вырабатывающие паратиреоидный гормон (ПТГ) для регуляции уровня кальция и фосфата в крови.","zh":"位于甲状腺后表面的四个微小腺体，产生甲状旁腺激素（PTH）以调节血液中的钙和磷酸盐水平。","pt_BR":"Quatro pequenas glândulas na face posterior da tireoide que produzem paratormônio (PTH) para regular os níveis de cálcio e fosfato no sangue.","pt_PT":"Quatro pequenas glândulas na face posterior da tiróide que produzem paratormona (PTH) para regular os níveis de cálcio e fosfato no sangue."}},
  { id: 'dc-anatomy-0089', deck_id: 'deck-anatomy', front: 'Adrenal Glands', back: 'Paired glands atop each kidney; the cortex produces corticosteroids and the medulla produces adrenaline (epinephrine) and noradrenaline.', sort_order: 89 , front_translations: {"es":"Glándulas adrenais","de":"Nebennieren","fr":"Glandes surrénales","tr":"Böbreküstü Bezleri (Adrenal Bezler)","nl":"Bijnieren","ru":"Надпочечники","zh":"肾上腺","pt_BR":"Glândulas adrenais","pt_PT":"Glândulas suprarrenais"}, back_translations: {"es":"Glándulas pares en el topo de cada riñón; el córtex produce corticosteroides y a medula produce adrenalina (epinefrina) y noradrenalina.","de":"Paarige Drüsen auf jeder Niere; die Rinde produziert Kortikosteroide und das Mark produziert Adrenalin (Epinephrin) und Noradrenalin.","fr":"Glandes paires au-dessus de chaque rein ; le cortex produit des corticostéroïdes et la médullosurrénale produit de l'adrénaline (épinéphrine) et de la noradrénaline.","tr":"Her böbreğin üstündeki çift bezler; korteks kortikosteroidler üretirken medulla adrenalin (epinefrin) ve noradrenalin üretir.","nl":"Gepaarde klieren bovenop elke nier; de cortex produceert corticosteroïden en het merg produceert adrenaline (epinefrine) en noradrenaline.","ru":"Парные железы на верхушке каждой почки; кора производит кортикостероиды, а мозговое вещество — адреналин (эпинефрин) и норадреналин.","zh":"位于每个肾脏顶部的成对腺体；皮质产生皮质类固醇，髓质产生肾上腺素（epinephrine）和去甲肾上腺素。","pt_BR":"Glândulas pares no topo de cada rim; o córtex produz corticosteroides e a medula produz adrenalina (epinefrina) e noradrenalina.","pt_PT":"Glândulas pares no topo de cada rim; o córtex produz corticosteroides e a medula produz adrenalina (epinefrina) e noradrenalina."}},
  { id: 'dc-anatomy-0090', deck_id: 'deck-anatomy', front: 'Pineal Gland', back: 'A small gland in the brain that produces melatonin to regulate sleep-wake cycles (circadian rhythms) in response to light exposure.', sort_order: 90 , front_translations: {"es":"Glándula pineal","de":"Zirbeldrüse","fr":"Glande pinéale","tr":"Pineal Bez","nl":"Pijnappelklier","ru":"Шишковидная железа","zh":"松果体","pt_BR":"Glândula pineal","pt_PT":"Glândula pineal"}, back_translations: {"es":"Una pequeña glándula en el cerebro que produce melatonina para regular los ciclos sono-vigília (ritmos circadianos) en respuesta a la exposición a la luz.","de":"Eine kleine Drüse im Gehirn, die Melatonin produziert, um die Schlaf-Wach-Zyklen (circadiane Rhythmen) als Reaktion auf Lichteinwirkung zu regulieren.","fr":"Une petite glande dans le cerveau qui produit de la mélatonine pour réguler les cycles veille-sommeil (rythmes circadiens) en réponse à l'exposition lumineuse.","tr":"Işık maruziyetine yanıt olarak uyku-uyanıklık döngülerini (sirkadiyen ritimler) düzenlemek için melatonin üreten beyndeki küçük bez.","nl":"Een kleine klier in de hersenen die melatonine produceert om slaap-waakcycli (circadiane ritmen) te reguleren als reactie op lichtblootstelling.","ru":"Небольшая железа в мозге, вырабатывающая мелатонин для регуляции циклов сна и бодрствования (циркадных ритмов) в ответ на световое воздействие.","zh":"大脑中产生褪黑素的小腺体，根据光照情况调节睡眠-觉醒周期（昼夜节律）。","pt_BR":"Uma pequena glândula no cérebro que produz melatonina para regular os ciclos sono-vigília (ritmos circadianos) em resposta à exposição à luz.","pt_PT":"Uma pequena glândula no cérebro que produz melatonina para regular os ciclos sono-vigília (ritmos circadianos) em resposta à exposição à luz."}},
  { id: 'dc-anatomy-0091', deck_id: 'deck-anatomy', front: 'Thymus', back: 'A gland in the upper chest where T-lymphocytes (T cells) mature; it is most active during childhood and gradually shrinks with age.', sort_order: 91 , front_translations: {"es":"Timo","de":"Thymusdrüse","fr":"Thymus","tr":"Timus","nl":"Thymus","ru":"Тимус","zh":"胸腺","pt_BR":"Timo","pt_PT":"Timo"}, back_translations: {"es":"Una glándula en el tórax superior donde los linfócitos T (células T) amadurecem; es más ativa durante a infancia y encolhe gradualmente con a edad.","de":"Eine Drüse im oberen Brustbereich, in der T-Lymphozyten (T-Zellen) reifen; sie ist in der Kindheit am aktivsten und schrumpft mit zunehmendem Alter allmählich.","fr":"Une glande dans le haut de la poitrine où mûrissent les lymphocytes T (cellules T) ; elle est la plus active pendant l'enfance et rétrécit progressivement avec l'âge.","tr":"T-lenfositlerin (T hücreleri) olgunlaştığı üst göğüste yer alan bez; çocuklukta en aktif haldedir ve yaşla birlikte kademeli olarak küçülür.","nl":"Een klier in de bovenste borst waar T-lymfocyten (T-cellen) rijpen; het is het meest actief tijdens de kindertijd en krimpt geleidelijk met de leeftijd.","ru":"Железа в верхней части грудной клетки, где созревают Т-лимфоциты (Т-клетки); наиболее активна в детстве и постепенно уменьшается с возрастом.","zh":"位于上胸部的腺体，是T淋巴细胞（T细胞）成熟的场所；在童年时期最为活跃，随年龄增长逐渐萎缩。","pt_BR":"Uma glândula no tórax superior onde os linfócitos T (células T) amadurecem; é mais ativa durante a infância e encolhe gradualmente com a idade.","pt_PT":"Uma glândula no tórax superior onde os linfócitos T (células T) amadurecem; é mais ativa durante a infância e encolhe gradualmente com a idade."}},
  { id: 'dc-anatomy-0092', deck_id: 'deck-anatomy', front: 'Red Blood Cells (Erythrocytes)', back: 'The most abundant blood cells; they contain hemoglobin to transport oxygen from the lungs to tissues and carbon dioxide back to the lungs.', sort_order: 92 , front_translations: {"es":"Glóbulos vermelhos (eritrócitos)","de":"Rote Blutkörperchen (Erythrozyten)","fr":"Globules rouges (érythrocytes)","tr":"Kırmızı Kan Hücreleri (Eritrositler)","nl":"Rode bloedcellen (erytrocyten)","ru":"Красные кровяные клетки (эритроциты)","zh":"红细胞（红血球）","pt_BR":"Glóbulos vermelhos (eritrócitos)","pt_PT":"Glóbulos vermelhos (eritrócitos)"}, back_translations: {"es":"As células sanguíneas más abundantes; contem hemoglobina para transportar oxígeno de los pulmones para los tejidos y dióxido de carbono de volta para los pulmones.","de":"Die häufigsten Blutzellen; sie enthalten Hämoglobin, um Sauerstoff von den Lungen zu den Geweben und Kohlendioxid zurück zu den Lungen zu transportieren.","fr":"Les cellules sanguines les plus abondantes ; elles contiennent de l'hémoglobine pour transporter l'oxygène des poumons aux tissus et le dioxyde de carbone en retour vers les poumons.","tr":"En bol bulunan kan hücreleri; akciğerlerden dokulara oksijen ve geri dönüşte akciğerlere karbondioksit taşımak için hemoglobin içerirler.","nl":"De meest voorkomende bloedcellen; ze bevatten hemoglobine om zuurstof van de longen naar de weefsels te transporteren en kooldioxide terug naar de longen.","ru":"Наиболее многочисленные клетки крови; содержат гемоглобин для транспортировки кислорода из лёгких к тканям и углекислого газа обратно в лёгкие.","zh":"数量最多的血细胞；含有血红蛋白，将氧气从肺部运输至组织，并将二氧化碳运回肺部。","pt_BR":"As células sanguíneas mais abundantes; contêm hemoglobina para transportar oxigênio dos pulmões para os tecidos e dióxido de carbono de volta para os pulmões.","pt_PT":"As células sanguíneas mais abundantes; contêm hemoglobina para transportar oxigénio dos pulmões para os tecidos e dióxido de carbono de volta para os pulmões."}},
  { id: 'dc-anatomy-0093', deck_id: 'deck-anatomy', front: 'White Blood Cells (Leukocytes)', back: 'Immune cells that defend the body against infection and disease; types include neutrophils, lymphocytes, monocytes, eosinophils, and basophils.', sort_order: 93 , front_translations: {"es":"Glóbulos brancos (leucócitos)","de":"Weiße Blutkörperchen (Leukozyten)","fr":"Globules blancs (leucocytes)","tr":"Beyaz Kan Hücreleri (Lökositler)","nl":"Witte bloedcellen (leukocyten)","ru":"Белые кровяные клетки (лейкоциты)","zh":"白细胞（白血球）","pt_BR":"Glóbulos brancos (leucócitos)","pt_PT":"Glóbulos brancos (leucócitos)"}, back_translations: {"es":"Células imunes que defendem el cuerpo contra infección y enfermedad; los tipos incluyen neutrófilos, linfócitos, monócitos, eosinófilos y basófilos.","de":"Immunzellen, die den Körper gegen Infektionen und Krankheiten schützen; Typen sind Neutrophile, Lymphozyten, Monozyten, Eosinophile und Basophile.","fr":"Cellules immunitaires qui défendent le corps contre les infections et maladies ; les types incluent les neutrophiles, lymphocytes, monocytes, éosinophiles et basophiles.","tr":"Vücudu enfeksiyon ve hastalığa karşı savunan bağışıklık hücreleri; türleri nötrofiller, lenfositler, monositler, eozinofiller ve bazofilleri içerir.","nl":"Immuuncellen die het lichaam verdedigen tegen infectie en ziekte; typen zijn neutrofielen, lymfocyten, monocyten, eosinofielen en basofielen.","ru":"Иммунные клетки, защищающие организм от инфекций и болезней; виды включают нейтрофилы, лимфоциты, моноциты, эозинофилы и базофилы.","zh":"防御机体抵抗感染和疾病的免疫细胞；种类包括中性粒细胞、淋巴细胞、单核细胞、嗜酸性粒细胞和嗜碱性粒细胞。","pt_BR":"Células imunes que defendem o corpo contra infecção e doença; os tipos incluem neutrófilos, linfócitos, monócitos, eosinófilos e basófilos.","pt_PT":"Células imunes que defendem o organismo contra infeção e doença; os tipos incluem neutrófilos, linfócitos, monócitos, eosinófilos e basófilos."}},
  { id: 'dc-anatomy-0094', deck_id: 'deck-anatomy', front: 'Platelets (Thrombocytes)', back: 'Small cell fragments in blood that aggregate at injury sites to form clots and prevent excessive bleeding.', sort_order: 94 , front_translations: {"es":"Plaquetas (trombócitos)","de":"Blutplättchen (Thrombozyten)","fr":"Plaquettes (thrombocytes)","tr":"Trombositler (Kan Pulcukları)","nl":"Bloedplaatjes (trombocyten)","ru":"Тромбоциты","zh":"血小板（血栓细胞）","pt_BR":"Plaquetas (trombócitos)","pt_PT":"Plaquetas (trombócitos)"}, back_translations: {"es":"Pequeños fragmentos celulares en el sangre que se agregam en ubicaciones de lesão para formar coágulos y prevenir sangramento excessivo.","de":"Kleine Zellfragmente im Blut, die sich an Verletzungsstellen ansammeln, um Gerinnsel zu bilden und übermäßige Blutungen zu verhindern.","fr":"Petits fragments cellulaires dans le sang qui s'agrègent aux sites de blessure pour former des caillots et prévenir les saignements excessifs.","tr":"Pıhtı oluşturmak ve aşırı kanamayı önlemek için yaralanma bölgelerinde bir araya gelen kandaki küçük hücre parçaları.","nl":"Kleine celfragmenten in het bloed die zich ophopen op verwondingsplaatsen om stolsels te vormen en overmatig bloeden te voorkomen.","ru":"Небольшие фрагменты клеток в крови, агрегирующие в местах повреждений для образования тромбов и предотвращения избыточного кровотечения.","zh":"血液中在损伤部位聚集形成血栓、防止过度出血的小型细胞碎片。","pt_BR":"Pequenos fragmentos celulares no sangue que se agregam em locais de lesão para formar coágulos e prevenir sangramento excessivo.","pt_PT":"Pequenos fragmentos celulares no sangue que se agregam nos locais de lesão para formar coágulos e prevenir hemorragia excessiva."}},
  { id: 'dc-anatomy-0095', deck_id: 'deck-anatomy', front: 'Hemoglobin', back: 'An iron-containing protein in red blood cells that binds oxygen in the lungs and releases it in body tissues; it also carries some CO2.', sort_order: 95 , front_translations: {"es":"Hemoglobina","de":"Hämoglobin","fr":"Hémoglobine","tr":"Hemoglobin","nl":"Hemoglobine","ru":"Гемоглобин","zh":"血红蛋白","pt_BR":"Hemoglobina","pt_PT":"Hemoglobina"}, back_translations: {"es":"Una proteína conteniendo ferro en los glóbulos vermelhos que liga oxígeno en los pulmones y el libera en los tejidos corporais; también transporta algún CO2.","de":"Ein eisenhaltiges Protein in den roten Blutkörperchen, das in den Lungen Sauerstoff bindet und ihn in den Körpergeweben freisetzt; es transportiert auch etwas CO2.","fr":"Une protéine contenant du fer dans les globules rouges qui se lie à l'oxygène dans les poumons et le libère dans les tissus corporels ; elle transporte aussi du CO2.","tr":"Akciğerlerde oksijen bağlayan ve vücut dokularında serbest bırakan kırmızı kan hücrelerindeki demir içeren protein; aynı zamanda biraz CO2 taşır.","nl":"Een ijzerhoudend eiwit in rode bloedcellen dat zuurstof bindt in de longen en het vrijgeeft in lichaamsweefsels; het transporteert ook wat CO2.","ru":"Железосодержащий белок в красных кровяных клетках, связывающий кислород в лёгких и высвобождающий его в тканях тела; также переносит некоторое количество CO2.","zh":"红细胞中含铁的蛋白质，在肺部结合氧气并在体组织中释放；同时也携带一些二氧化碳。","pt_BR":"Uma proteína contendo ferro nos glóbulos vermelhos que liga oxigênio nos pulmões e o libera nos tecidos corporais; também transporta algum CO2.","pt_PT":"Uma proteína contendo ferro nos glóbulos vermelhos que liga oxigénio nos pulmões e o liberta nos tecidos corporais; também transporta algum CO2."}},
  { id: 'dc-anatomy-0096', deck_id: 'deck-anatomy', front: 'Plasma', back: 'The liquid component of blood (about 55% of blood volume); it transports nutrients, hormones, proteins, and waste products throughout the body.', sort_order: 96 , front_translations: {"es":"Plasma","de":"Blutplasma","fr":"Plasma","tr":"Plazma","nl":"Plasma","ru":"Плазма","zh":"血浆","pt_BR":"Plasma","pt_PT":"Plasma"}, back_translations: {"es":"El componente líquido del sangre (cerca de 55% del volumen sanguíneo); transporta nutrientes, hormonas, proteínas y productos residuais por todo el cuerpo.","de":"Der flüssige Bestandteil des Blutes (ca. 55 % des Blutvolumens); er transportiert Nährstoffe, Hormone, Proteine und Abfallprodukte im gesamten Körper.","fr":"Le composant liquide du sang (environ 55 % du volume sanguin) ; il transporte les nutriments, les hormones, les protéines et les déchets dans tout le corps.","tr":"Kanın sıvı bileşeni (kan hacminin yaklaşık %55'i); besinleri, hormonları, proteinleri ve atık ürünleri vücut genelinde taşır.","nl":"Het vloeibare bestanddeel van bloed (ongeveer 55% van het bloedvolume); het transporteert voedingsstoffen, hormonen, eiwitten en afvalproducten door het hele lichaam.","ru":"Жидкая составляющая крови (около 55% объёма крови); транспортирует питательные вещества, гормоны, белки и продукты обмена по всему организму.","zh":"血液的液态成分（约占血液容量的55%）；将营养物质、激素、蛋白质和废物运输至全身。","pt_BR":"O componente líquido do sangue (cerca de 55% do volume sanguíneo); transporta nutrientes, hormônios, proteínas e produtos residuais por todo o corpo.","pt_PT":"O componente líquido do sangue (cerca de 55% do volume sanguíneo); transporta nutrientes, hormonas, proteínas e produtos residuais por todo o corpo."}},
  { id: 'dc-anatomy-0097', deck_id: 'deck-anatomy', front: 'Hip Joint', back: 'A ball-and-socket synovial joint formed between the femoral head and the acetabulum of the pelvis; allows flexion, extension, abduction, adduction, and rotation.', sort_order: 97 , front_translations: {"es":"Articulación del cadera","de":"Hüftgelenk","fr":"Articulation de la hanche","tr":"Kalça Eklemi","nl":"Heupgewricht","ru":"Тазобедренный сустав","zh":"髋关节","pt_BR":"Articulação do quadril","pt_PT":"Articulação da anca"}, back_translations: {"es":"Una articulación esférica sinovial formada entre a cabeza femoral y el acetábulo de la pelve; permite flexão, extensão, abdución, adución y rotación.","de":"Ein Kugelgelenk, das zwischen dem Femurkopf und der Hüftpfanne des Beckens gebildet wird; ermöglicht Flexion, Extension, Abduktion, Adduktion und Rotation.","fr":"Une articulation sphéroïde formée entre la tête du fémur et l'acétabulum du bassin ; elle permet la flexion, l'extension, l'abduction, l'adduction et la rotation.","tr":"Femur başı ile pelvisin asetabulumu arasında oluşan top-soket sinovyal eklem; fleksiyon, ekstansiyon, abduksiyon, adduksiyon ve rotasyona olanak tanır.","nl":"Een kogelgewricht gevormd tussen de femorale kop en het acetabulum van het bekken; maakt flexie, extensie, abductie, adductie en rotatie mogelijk.","ru":"Шаровидный синовиальный сустав, образованный головкой бедренной кости и вертлужной впадиной таза; обеспечивает сгибание, разгибание, отведение, приведение и вращение.","zh":"由股骨头与骨盆髋臼形成的球窝滑膜关节；允许屈曲、伸展、外展、内收和旋转运动。","pt_BR":"Uma articulação esférica sinovial formada entre a cabeça femoral e o acetábulo da pelve; permite flexão, extensão, abdução, adução e rotação.","pt_PT":"Uma articulação esférica sinovial formada entre a cabeça femoral e o acetábulo da pelve; permite flexão, extensão, abdução, adução e rotação."}},
  { id: 'dc-anatomy-0098', deck_id: 'deck-anatomy', front: 'Knee Joint', back: 'The largest and most complex synovial joint, formed between the femur, tibia, and patella; primarily allows flexion and extension.', sort_order: 98 , front_translations: {"es":"Articulación del rodilla","de":"Kniegelenk","fr":"Articulation du genou","tr":"Diz Eklemi","nl":"Kniegewricht","ru":"Коленный сустав","zh":"膝关节","pt_BR":"Articulação do joelho","pt_PT":"Articulação do joelho"}, back_translations: {"es":"La mayor y más complexa articulación sinovial, formada entre el fémur, a tíbia y a patela; permite principalmente flexão y extensão.","de":"Das größte und komplexeste Synovialgelenk, das zwischen Femur, Tibia und Patella gebildet wird; ermöglicht hauptsächlich Flexion und Extension.","fr":"La plus grande et plus complexe articulation synoviale, formée entre le fémur, le tibia et la patella ; elle permet principalement la flexion et l'extension.","tr":"Femur, tibia ve patella arasında oluşan en büyük ve en karmaşık sinovyal eklem; öncelikli olarak fleksiyona ve ekstansiyona izin verir.","nl":"Het grootste en meest complexe synoviale gewricht, gevormd tussen het dijbeen, scheenbeen en knieschijf; staat voornamelijk flexie en extensie toe.","ru":"Крупнейший и наиболее сложный синовиальный сустав, образованный бедренной, большеберцовой костями и надколенником; прежде всего обеспечивает сгибание и разгибание.","zh":"由股骨、胫骨和髌骨组成的最大、最复杂的滑膜关节；主要允许屈曲和伸展运动。","pt_BR":"A maior e mais complexa articulação sinovial, formada entre o fêmur, a tíbia e a patela; permite principalmente flexão e extensão.","pt_PT":"A maior e mais complexa articulação sinovial, formada entre o fémur, a tíbia e a rótula; permite principalmente flexão e extensão."}},
  { id: 'dc-anatomy-0099', deck_id: 'deck-anatomy', front: 'Shoulder Joint', back: 'A ball-and-socket joint between the humeral head and glenoid fossa of the scapula; the most mobile joint in the body, allowing wide range of motion.', sort_order: 99 , front_translations: {"es":"Articulación del hombro","de":"Schultergelenk","fr":"Articulation de l'épaule","tr":"Omuz Eklemi","nl":"Schoudergewricht","ru":"Плечевой сустав","zh":"肩关节","pt_BR":"Articulação do ombro","pt_PT":"Articulação do ombro"}, back_translations: {"es":"Una articulación esférica entre a cabeza del úmero y a fossa glenoidal de la escápula; a articulación más móvel del cuerpo, permitiendo ampla amplitude de movimiento.","de":"Ein Kugelgelenk zwischen dem Humeruskopf und der Glenoidgrube des Schulterblatts; das beweglichste Gelenk im Körper mit einem weiten Bewegungsumfang.","fr":"Une articulation sphéroïde entre la tête humérale et la cavité glénoïde de l'omoplate ; l'articulation la plus mobile du corps, permettant une large amplitude de mouvement.","tr":"Humerus başı ile skapulanın glenoid fossası arasındaki top-soket eklem; vücudun en hareketli eklemi olup geniş hareket açıklığına izin verir.","nl":"Een kogelgewricht tussen het humerushoofd en de glenoïde fossa van het schouderblad; het meest mobiele gewricht in het lichaam, met een ruim bewegingsbereik.","ru":"Шаровидный сустав между головкой плечевой кости и суставной ямкой лопатки; наиболее подвижный сустав тела, обеспечивающий широкий диапазон движений.","zh":"由肱骨头与肩胛骨关节盂构成的球窝关节；是人体活动范围最大的关节。","pt_BR":"Uma articulação esférica entre a cabeça do úmero e a fossa glenoidal da escápula; a articulação mais móvel do corpo, permitindo ampla amplitude de movimento.","pt_PT":"Uma articulação esférica entre a cabeça do úmero e a fossa glenoidal da escápula; a articulação mais móvel do corpo, permitindo uma ampla amplitude de movimento."}},
  { id: 'dc-anatomy-0100', deck_id: 'deck-anatomy', front: 'Elbow Joint', back: 'A hinge synovial joint between the humerus, radius, and ulna; primarily allows flexion and extension of the forearm.', sort_order: 100 , front_translations: {"es":"Articulación del codo","de":"Ellenbogengelenk","fr":"Articulation du coude","tr":"Dirsek Eklemi","nl":"Ellebooggewricht","ru":"Локтевой сустав","zh":"肘关节","pt_BR":"Articulação do cotovelo","pt_PT":"Articulação do cotovelo"}, back_translations: {"es":"Una articulación sinovial de dobradiça entre el úmero, el rádio y a ulna; permite principalmente a flexão y extensão del antebraço.","de":"Ein Scharnier-Synovialgelenk zwischen Humerus, Radius und Ulna; ermöglicht hauptsächlich Flexion und Extension des Unterarms.","fr":"Une articulation synoviale en charnière entre l'humérus, le radius et le cubitus ; elle permet principalement la flexion et l'extension de l'avant-bras.","tr":"Humerus, radius ve ulna arasındaki menteşe sinovyal eklem; öncelikli olarak önkolun fleksiyon ve ekstansiyonuna olanak tanır.","nl":"Een scharnier synoviaal gewricht tussen de humerus, radius en ulna; staat voornamelijk flexie en extensie van de onderarm toe.","ru":"Шарнирный синовиальный сустав между плечевой, лучевой и локтевой костями; прежде всего обеспечивает сгибание и разгибание предплечья.","zh":"由肱骨、桡骨和尺骨组成的铰链式滑膜关节；主要允许前臂的屈曲和伸展运动。","pt_BR":"Uma articulação sinovial de dobradiça entre o úmero, o rádio e a ulna; permite principalmente a flexão e extensão do antebraço.","pt_PT":"Uma articulação sinovial de dobradiça entre o úmero, o rádio e a ulna; permite principalmente a flexão e extensão do antebraço."}},
  { id: 'dc-anatomy-0101', deck_id: 'deck-anatomy', front: 'Intervertebral Disc', back: 'Fibrocartilaginous cushions between adjacent vertebrae; they absorb shock, allow spinal flexibility, and consist of a tough annulus fibrosus surrounding a gel-like nucleus pulposus.', sort_order: 101 , front_translations: {"es":"Disco intervertebral","de":"Bandscheibe","fr":"Disque intervertébral","tr":"Intervertebral Disk","nl":"Tussenwervelschijf","ru":"Межпозвоночный диск","zh":"椎间盘","pt_BR":"Disco intervertebral","pt_PT":"Disco intervertebral"}, back_translations: {"es":"Almofadas fibrocartilaginosas entre vértebras adjacentes; absorben impactos, permiten a flexibilidad de la columna y consistem en un resistente anel fibroso involucrando un núcleo pulposo gelatinoso.","de":"Faserknorpelige Kissen zwischen benachbarten Wirbeln; sie absorbieren Stöße, ermöglichen die Beweglichkeit der Wirbelsäule und bestehen aus einem harten Anulus fibrosus, der einen gelartigen Nucleus pulposus umschließt.","fr":"Coussins fibrocartilagineux situés entre les vertèbres adjacentes ; ils absorbent les chocs, permettent la flexibilité rachidienne et sont constitués d'un anneau fibreux résistant entourant un noyau pulpeux gélatineux.","tr":"Komşu vertebralar arasındaki fibrokartilajinöz yastıklar; şokları absorbe eder, omurga esnekliğine izin verir ve jel benzeri bir nucleus pulposus'u çevreleyen sert bir anulus fibrosus'tan oluşur.","nl":"Fibrokraakbeenachtige kussens tussen naburige wervels; ze absorberen schokken, laten wervelkolomflexibiliteit toe en bestaan uit een taai anulus fibrosus die een gelachtige nucleus pulposus omhult.","ru":"Волокнисто-хрящевые прокладки между соседними позвонками; они поглощают удары, обеспечивают гибкость позвоночника и состоят из жёсткого фиброзного кольца, окружающего гелеобразное пульпозное ядро.","zh":"位于相邻椎骨之间的纤维软骨垫；吸收冲击，允许脊柱弯曲，由坚韧的纤维环包围凝胶状的髓核构成。","pt_BR":"Almofadas fibrocartilaginosas entre vértebras adjacentes; absorvem impactos, permitem a flexibilidade da coluna e consistem em um resistente anel fibroso envolvendo um núcleo pulposo gelatinoso.","pt_PT":"Almofadas fibrocartilaginosas entre vértebras adjacentes; absorvem choques, permitem a flexibilidade da coluna vertebral e consistem num robusto anel fibroso que envolve um núcleo pulposo gelatinoso."}},
  { id: 'dc-anatomy-0102', deck_id: 'deck-anatomy', front: 'Synovial Joint', back: 'The most mobile type of joint; it is surrounded by a joint capsule lined with synovial membrane that produces fluid to lubricate the cartilage-covered bone ends.', sort_order: 102 , front_translations: {"es":"Articulación sinovial","de":"Synovialgelenk","fr":"Articulation synoviale","tr":"Sinovyal Eklem","nl":"Synoviaal gewricht","ru":"Синовиальный сустав","zh":"滑膜关节","pt_BR":"Articulação sinovial","pt_PT":"Articulação sinovial"}, back_translations: {"es":"El tipo de articulación más móvel; es circundado por una cápsula articular revestida por membrana sinovial que produce líquido para lubrificar las extremidades ósseas cobertas por cartílago.","de":"Der beweglichste Gelenktyp; er ist von einer Gelenkkapsel umgeben, die mit einer Synovialmembran ausgekleidet ist, welche Flüssigkeit produziert, um die mit Knorpel bedeckten Knochenenden zu schmieren.","fr":"Le type d'articulation le plus mobile ; il est entouré d'une capsule articulaire tapissée d'une membrane synoviale qui produit du liquide pour lubrifier les extrémités osseuses recouvertes de cartilage.","tr":"En hareketli eklem türü; sinovyal membranla kaplı bir eklem kapsülüyle çevrilidir ve kıkırdakla örtülü kemik uçlarını yağlamak için sıvı üretir.","nl":"Het meest beweeglijke type gewricht; het is omgeven door een gewrichtskapsel dat bekleed is met synoviaal membraan dat vloeistof produceert om de met kraakbeen bedekte botuiteindes te smeren.","ru":"Наиболее подвижный тип сустава; окружён суставной капсулой, выстланной синовиальной оболочкой, которая вырабатывает жидкость для смазки покрытых хрящом концов костей.","zh":"最灵活的关节类型；由关节囊包围，内衬滑膜，可分泌液体润滑覆有软骨的骨端。","pt_BR":"O tipo de articulação mais móvel; é circundado por uma cápsula articular revestida por membrana sinovial que produz líquido para lubrificar as extremidades ósseas cobertas por cartilagem.","pt_PT":"O tipo de articulação mais móvel; é rodeado por uma cápsula articular revestida por membrana sinovial que produz líquido para lubrificar as extremidades ósseas cobertas por cartilagem."}},
  { id: 'dc-anatomy-0103', deck_id: 'deck-anatomy', front: 'Ligament', back: 'A tough band of fibrous connective tissue that connects bone to bone, stabilizing joints and limiting excessive movement.', sort_order: 103 , front_translations: {"es":"Ligamento","de":"Band (Ligament)","fr":"Ligament","tr":"Bağ (Ligament)","nl":"Ligament","ru":"Связка","zh":"韧带","pt_BR":"Ligamento","pt_PT":"Ligamento"}, back_translations: {"es":"Una franja resistente de tejido conjuntivo fibroso que conecta hueso a hueso, estabilizando articulaciones y limitando movimientos excessivos.","de":"Ein zähes Band aus faserigem Bindegewebe, das Knochen mit Knochen verbindet, Gelenke stabilisiert und übermäßige Bewegungen einschränkt.","fr":"Une bande résistante de tissu conjonctif fibreux reliant les os entre eux, stabilisant les articulations et limitant les mouvements excessifs.","tr":"Kemiği kemiğe bağlayan, eklemleri stabilize eden ve aşırı hareketi sınırlayan sert bir fibröz bağ doku bandı.","nl":"Een taai band van vezelig bindweefsel dat bot met bot verbindt, gewrichten stabiliseert en overmatige beweging beperkt.","ru":"Прочная полоска волокнистой соединительной ткани, соединяющая кость с костью, стабилизирующая суставы и ограничивающая чрезмерные движения.","zh":"连接骨骼与骨骼的坚韧纤维结缔组织带，起到稳定关节和限制过度运动的作用。","pt_BR":"Uma faixa resistente de tecido conjuntivo fibroso que conecta osso a osso, estabilizando articulações e limitando movimentos excessivos.","pt_PT":"Uma banda resistente de tecido conjuntivo fibroso que liga osso a osso, estabilizando articulações e limitando movimentos excessivos."}},
  { id: 'dc-anatomy-0104', deck_id: 'deck-anatomy', front: 'Tendon', back: 'A fibrous connective tissue that connects muscle to bone, transmitting the force of muscular contraction to produce joint movement.', sort_order: 104 , front_translations: {"es":"Tendón","de":"Sehne","fr":"Tendon","tr":"Tendon","nl":"Pees","ru":"Сухожилие","zh":"肌腱","pt_BR":"Tendão","pt_PT":"Tendão"}, back_translations: {"es":"Tejido conjuntivo fibroso que conecta músculo al hueso, transmitindo a fuerza de la contración muscular para produzir movimiento articular.","de":"Ein faseriges Bindegewebe, das Muskeln mit Knochen verbindet und die Kraft der Muskelkontraktion überträgt, um Gelenkbewegungen zu erzeugen.","fr":"Un tissu conjonctif fibreux reliant les muscles aux os, transmettant la force de contraction musculaire pour produire des mouvements articulaires.","tr":"Kası kemiğe bağlayan, eklem hareketini üretmek için kas kasılma kuvvetini ileten fibröz bağ doku.","nl":"Een vezelig bindweefsel dat spier met bot verbindt en de kracht van spiercontractie overbrengt om gewrichtsbeweging te produceren.","ru":"Волокнистая соединительная ткань, соединяющая мышцу с костью и передающая силу мышечного сокращения для обеспечения движения в суставе.","zh":"连接肌肉与骨骼的纤维结缔组织，将肌肉收缩的力量传递给骨骼以产生关节运动。","pt_BR":"Tecido conjuntivo fibroso que conecta músculo ao osso, transmitindo a força da contração muscular para produzir movimento articular.","pt_PT":"Tecido conjuntivo fibroso que liga o músculo ao osso, transmitindo a força da contração muscular para produzir movimento articular."}},
  { id: 'dc-anatomy-0105', deck_id: 'deck-anatomy', front: 'Anterior Cruciate Ligament (ACL)', back: 'A ligament inside the knee joint that prevents forward movement of the tibia relative to the femur; a common sports injury site.', sort_order: 105 , front_translations: {"es":"Ligamento cruzado anterior (LCA)","de":"Vorderes Kreuzband (VKB)","fr":"Ligament croisé antérieur (LCA)","tr":"Ön Çapraz Bağ (ÖÇB)","nl":"Voorste kruisband (VKB)","ru":"Передняя крестообразная связка (ПКС)","zh":"前交叉韧带（ACL）","pt_BR":"Ligamento cruzado anterior (LCA)","pt_PT":"Ligamento cruzado anterior (LCA)"}, back_translations: {"es":"Un ligamento dentro de la articulación del rodilla que impide el movimiento anterior de la tíbia en relación con el fémur; local comum de lesão esportiva.","de":"Ein Band innerhalb des Kniegelenks, das eine Vorwärtsbewegung der Tibia gegenüber dem Femur verhindert; eine häufige Sportverletzungsstelle.","fr":"Un ligament à l'intérieur du genou qui empêche le mouvement vers l'avant du tibia par rapport au fémur ; site fréquent de blessure sportive.","tr":"Tibianın femura göre öne hareketini engelleyen diz eklemi içindeki bir bağ; yaygın bir spor yaralanması yeridir.","nl":"Een ligament in het kniegewricht dat voorwaartse beweging van het scheenbeen ten opzichte van het dijbeen voorkomt; een veelvoorkomende sportblessurelocatie.","ru":"Связка внутри коленного сустава, препятствующая передвижению большеберцовой кости вперёд относительно бедренной; частое место спортивных травм.","zh":"膝关节内的韧带，防止胫骨相对股骨向前移动；是常见的运动损伤部位。","pt_BR":"Um ligamento dentro da articulação do joelho que impede o movimento anterior da tíbia em relação ao fêmur; local comum de lesão esportiva.","pt_PT":"Um ligamento no interior da articulação do joelho que impede o movimento anterior da tíbia em relação ao fémur; local frequente de lesão desportiva."}},
  { id: 'dc-anatomy-0106', deck_id: 'deck-anatomy', front: 'Meniscus', back: 'Crescent-shaped fibrocartilage pads in the knee joint that distribute weight, absorb shock, and improve congruence between femur and tibia.', sort_order: 106 , front_translations: {"es":"Menisco","de":"Meniskus","fr":"Ménisque","tr":"Menisküs","nl":"Meniscus","ru":"Мениск","zh":"半月板","pt_BR":"Menisco","pt_PT":"Menisco"}, back_translations: {"es":"Almofadas fibrocartilaginosas en forma de crescente en el rodilla que distribuyen el peso, absorben impactos y melhoram a congruencia entre fémur y tíbia.","de":"Halbmondförmige Faserknorpelpolster im Kniegelenk, die das Gewicht verteilen, Stöße absorbieren und die Kongruenz zwischen Femur und Tibia verbessern.","fr":"Coussins fibrocartilagineux en forme de croissant dans le genou qui répartissent les charges, absorbent les chocs et améliorent la congruence entre le fémur et le tibia.","tr":"Diz ekleminde ağırlığı dağıtan, şokları absorbe eden ve femur ile tibia arasındaki uyumu geliştiren hilal şekilli fibrokartilaj yastıklar.","nl":"Halvemaan-vormige fibrokraakbeenachtige kussens in het kniegewricht die gewicht verdelen, schokken absorberen en de congruentie tussen dijbeen en scheenbeen verbeteren.","ru":"Серпообразные фиброхрящевые прокладки в коленном суставе, распределяющие нагрузку, поглощающие удары и улучшающие конгруэнтность между бедренной и большеберцовой костями.","zh":"膝关节内月牙形纤维软骨垫，负责分散体重、吸收冲击并改善股骨与胫骨之间的吻合度。","pt_BR":"Almofadas fibrocartilaginosas em forma de crescente no joelho que distribuem o peso, absorvem impactos e melhoram a congruência entre fêmur e tíbia.","pt_PT":"Almofadas fibrocartilaginosas em forma de crescente no joelho que distribuem o peso, absorvem choques e melhoram a congruência entre o fémur e a tíbia."}},
  { id: 'dc-anatomy-0107', deck_id: 'deck-anatomy', front: 'Rotator Cuff', back: 'A group of four muscles and their tendons (supraspinatus, infraspinatus, teres minor, subscapularis) that stabilize the shoulder joint and enable rotation.', sort_order: 107 , front_translations: {"es":"Manguito rotador","de":"Rotatorenmanschette","fr":"Coiffe des rotateurs","tr":"Rotator Manşet","nl":"Rotatormanchet","ru":"Вращательная манжета плеча","zh":"肩袖","pt_BR":"Manguito rotador","pt_PT":"Coifa dos rotadores"}, back_translations: {"es":"Un grupo de cuatro músculos y sus tendones (supraespinal, infraespinal, redondo menor, subescapular) que estabilizam a articulación del hombro y permiten a rotación.","de":"Eine Gruppe von vier Muskeln und ihren Sehnen (Supraspinatus, Infraspinatus, Teres minor, Subscapularis), die das Schultergelenk stabilisieren und die Rotation ermöglichen.","fr":"Un groupe de quatre muscles et leurs tendons (sus-épineux, sous-épineux, petit rond, sous-scapulaire) qui stabilisent l'articulation de l'épaule et permettent la rotation.","tr":"Omuz eklemini stabilize eden ve rotasyonu sağlayan dört kas ve tendonlarından (supraspinatus, infraspinatus, teres minor, subscapularis) oluşan bir grup.","nl":"Een groep van vier spieren en hun pezen (supraspinatus, infraspinatus, teres minor, subscapularis) die het schoudergewricht stabiliseren en rotatie mogelijk maken.","ru":"Группа из четырёх мышц и их сухожилий (надостная, подостная, малая круглая, подлопаточная), стабилизирующих плечевой сустав и обеспечивающих вращение.","zh":"由四块肌肉及其肌腱（冈上肌、冈下肌、小圆肌、肩胛下肌）组成的肌群，负责稳定肩关节并实现旋转运动。","pt_BR":"Um grupo de quatro músculos e seus tendões (supraespinal, infraespinal, redondo menor, subescapular) que estabilizam a articulação do ombro e permitem a rotação.","pt_PT":"Um grupo de quatro músculos e seus tendões (supraespinhoso, infraespinhoso, redondo menor, subescapular) que estabilizam a articulação do ombro e permitem a rotação."}},
  { id: 'dc-anatomy-0108', deck_id: 'deck-anatomy', front: 'Iliotibial (IT) Band', back: 'A thick band of fascia running from the iliac crest down the outside of the thigh to the tibia; it stabilizes the knee during movement.', sort_order: 108 , front_translations: {"es":"Trato iliotibial (banda IT)","de":"Iliotibialband (IT-Band)","fr":"Bandelette ilio-tibiale (bandelette de Maissiat)","tr":"İliotibial (IT) Bant","nl":"Iliotibiale band (IT-band)","ru":"Подвздошно-большеберцовый тракт (ИТ-бэнд)","zh":"髂胫束（IT束）","pt_BR":"Trato iliotibial (banda IT)","pt_PT":"Trato iliotibial (banda IT)"}, back_translations: {"es":"Una franja espessa de fáscia que vai de la crista ilíaca por la parte lateral de la muslo hasta a tíbia; estabiliza el rodilla durante el movimiento.","de":"Ein dickes Faszienbündel, das vom Beckenkamm an der Außenseite des Oberschenkels bis zur Tibia verläuft; es stabilisiert das Knie während der Bewegung.","fr":"Une épaisse bande de fascia allant de la crête iliaque le long du bord externe de la cuisse jusqu'au tibia ; elle stabilise le genou lors des mouvements.","tr":"İliak krestten uyluğun dış yüzü boyunca tibiaya uzanan kalın bir fasya bandı; hareket sırasında dizi stabilize eder.","nl":"Een dik band van fascia dat van de bekkenkam langs de buitenkant van de dij naar het scheenbeen loopt; het stabiliseert de knie tijdens beweging.","ru":"Толстая полоска фасции, проходящая от гребня подвздошной кости по внешней стороне бедра до большеберцовой кости; стабилизирует колено при движении.","zh":"从髂嵴沿大腿外侧延伸至胫骨的厚筋膜带；在运动时起到稳定膝关节的作用。","pt_BR":"Uma faixa espessa de fáscia que vai da crista ilíaca pela parte lateral da coxa até a tíbia; estabiliza o joelho durante o movimento.","pt_PT":"Uma faixa espessa de fáscia que vai da crista ilíaca ao longo da face lateral da coxa até à tíbia; estabiliza o joelho durante o movimento."}},
  { id: 'dc-anatomy-0109', deck_id: 'deck-anatomy', front: 'Lymph Nodes', back: 'Small bean-shaped glands distributed throughout the body that filter lymph fluid and house immune cells to fight infection.', sort_order: 109 , front_translations: {"es":"Linfonodos","de":"Lymphknoten","fr":"Ganglions lymphatiques","tr":"Lenf Düğümleri","nl":"Lymfeklieren","ru":"Лимфатические узлы","zh":"淋巴结","pt_BR":"Linfonodos","pt_PT":"Gânglios linfáticos"}, back_translations: {"es":"Pequeñas glándulas en forma de feijão distribuídas por todo el cuerpo que filtram el líquido linfático y abrigam células imunes para combater infecciones.","de":"Kleine bohnenförmige Drüsen, die im gesamten Körper verteilt sind; sie filtern die Lymphflüssigkeit und beherbergen Immunzellen zur Bekämpfung von Infektionen.","fr":"Petites glandes en forme de haricot réparties dans tout le corps qui filtrent la lymphe et abritent des cellules immunitaires pour combattre les infections.","tr":"Lenf sıvısını filtreleyen ve enfeksiyonla mücadele için bağışıklık hücrelerini barındıran, vücuda dağılmış küçük fasulye şekilli bezler.","nl":"Kleine boonvormige klieren verspreid over het hele lichaam die lymfevloeistof filteren en immuuncellen huisvesten om infecties te bestrijden.","ru":"Небольшие бобовидные железы, распределённые по всему телу; фильтруют лимфу и содержат иммунные клетки для борьбы с инфекциями.","zh":"分布于全身的小型豆形腺体，过滤淋巴液并容纳免疫细胞以抵御感染。","pt_BR":"Pequenas glândulas em forma de feijão distribuídas por todo o corpo que filtram o líquido linfático e abrigam células imunes para combater infecções.","pt_PT":"Pequenas glândulas em forma de feijão distribuídas por todo o corpo que filtram o líquido linfático e albergam células imunes para combater infeções."}},
  { id: 'dc-anatomy-0110', deck_id: 'deck-anatomy', front: 'Lymphatic System', back: 'A network of tissues, organs, and vessels that returns excess tissue fluid to the bloodstream and plays a central role in immune defense.', sort_order: 110 , front_translations: {"es":"Sistema linfático","de":"Lymphatisches System","fr":"Système lymphatique","tr":"Lenfatik Sistem","nl":"Lymfestelsel","ru":"Лимфатическая система","zh":"淋巴系统","pt_BR":"Sistema linfático","pt_PT":"Sistema linfático"}, back_translations: {"es":"Una red de tejidos, órganos y vasos que devolve el exceso de líquido tissular a la corrente sanguínea y desempenha un papel central en la defesa imunológica.","de":"Ein Netzwerk aus Geweben, Organen und Gefäßen, das überschüssige Gewebeflüssigkeit in den Blutkreislauf zurückführt und eine zentrale Rolle bei der Immunabwehr spielt.","fr":"Un réseau de tissus, d'organes et de vaisseaux qui renvoie l'excès de liquide tissulaire dans la circulation sanguine et joue un rôle central dans la défense immunitaire.","tr":"Fazla doku sıvısını kan dolaşımına geri döndüren ve bağışıklık savunmasında merkezi bir rol oynayan doku, organ ve damar ağı.","nl":"Een netwerk van weefsels, organen en vaten dat overtollig weefselvloeistof terugvoert naar de bloedbaan en een centrale rol speelt in de immuunverdediging.","ru":"Сеть тканей, органов и сосудов, возвращающая избыток тканевой жидкости в кровеносную систему и играющая ключевую роль в иммунной защите.","zh":"由组织、器官和血管组成的网络，将多余的组织液返回血液循环，并在免疫防御中发挥核心作用。","pt_BR":"Uma rede de tecidos, órgãos e vasos que devolve o excesso de líquido tissular à corrente sanguínea e desempenha um papel central na defesa imunológica.","pt_PT":"Uma rede de tecidos, órgãos e vasos que devolve o excesso de líquido tissular à corrente sanguínea e desempenha um papel central na defesa imunológica."}},
  { id: 'dc-anatomy-0111', deck_id: 'deck-anatomy', front: 'Capillaries', back: 'The smallest blood vessels in the body; their thin walls allow the exchange of oxygen, nutrients, and waste products between blood and tissues.', sort_order: 111 , front_translations: {"es":"Capilares","de":"Kapillaren","fr":"Capillaires","tr":"Kılcal Damarlar","nl":"Haarvaten (capillairen)","ru":"Капилляры","zh":"毛细血管","pt_BR":"Capilares","pt_PT":"Capilares"}, back_translations: {"es":"Los menores vasos sanguíneos del cuerpo; sus paredes delgadas permiten a troca de oxígeno, nutrientes y productos residuais entre el sangre y los tejidos.","de":"Die kleinsten Blutgefäße im Körper; ihre dünnen Wände ermöglichen den Austausch von Sauerstoff, Nährstoffen und Abfallprodukten zwischen Blut und Gewebe.","fr":"Les plus petits vaisseaux sanguins du corps ; leurs parois minces permettent l'échange d'oxygène, de nutriments et de déchets entre le sang et les tissus.","tr":"Vücuttaki en küçük kan damarları; ince duvarları kan ile dokular arasında oksijen, besin ve atık ürünlerin değişimine izin verir.","nl":"De kleinste bloedvaten in het lichaam; hun dunne wanden laten de uitwisseling toe van zuurstof, voedingsstoffen en afvalstoffen tussen bloed en weefsels.","ru":"Мельчайшие кровеносные сосуды в организме; их тонкие стенки обеспечивают обмен кислородом, питательными веществами и продуктами обмена между кровью и тканями.","zh":"人体内最细小的血管；其薄壁允许氧气、营养物质和代谢废物在血液与组织之间进行交换。","pt_BR":"Os menores vasos sanguíneos do corpo; suas paredes finas permitem a troca de oxigênio, nutrientes e produtos residuais entre o sangue e os tecidos.","pt_PT":"Os menores vasos sanguíneos do corpo; as suas paredes finas permitem a troca de oxigénio, nutrientes e produtos residuais entre o sangue e os tecidos."}},
  { id: 'dc-anatomy-0112', deck_id: 'deck-anatomy', front: 'Veins', back: 'Blood vessels that carry deoxygenated blood back to the heart; they have thinner walls than arteries and contain valves to prevent backflow.', sort_order: 112 , front_translations: {"es":"Venas","de":"Venen","fr":"Veines","tr":"Venler","nl":"Aders (venen)","ru":"Вены","zh":"静脉","pt_BR":"Veias","pt_PT":"Veias"}, back_translations: {"es":"Vasos sanguíneos que transportan sangre desoxigenado de volta al corazón; tienen paredes más delgadas que las arterias y contem válvulas para evitar el refluxo.","de":"Blutgefäße, die sauerstoffarmes Blut zurück zum Herzen transportieren; sie haben dünnere Wände als Arterien und besitzen Klappen, um einen Rückfluss zu verhindern.","fr":"Vaisseaux sanguins qui ramènent le sang désoxygéné vers le cœur ; ils ont des parois plus minces que les artères et contiennent des valvules pour prévenir le reflux.","tr":"Oksijensiz kanı kalbe geri taşıyan kan damarları; arterlere göre daha ince duvarlara sahiptir ve geri akışı önlemek için kapakçıklar içerir.","nl":"Bloedvaten die zuurstofarm bloed terugvoeren naar het hart; ze hebben dunnere wanden dan slagaders en bevatten kleppen om terugstroom te voorkomen.","ru":"Кровеносные сосуды, несущие дезоксигенированную кровь обратно к сердцу; их стенки тоньше, чем у артерий, а клапаны препятствуют обратному току крови.","zh":"将脱氧血液输送回心脏的血管；其管壁比动脉薄，并含有防止血液回流的瓣膜。","pt_BR":"Vasos sanguíneos que transportam sangue desoxigenado de volta ao coração; têm paredes mais finas que as artérias e contêm válvulas para evitar o refluxo.","pt_PT":"Vasos sanguíneos que transportam sangue desoxigenado de volta ao coração; têm paredes mais finas que as artérias e contêm válvulas para impedir o refluxo."}},
  { id: 'dc-anatomy-0113', deck_id: 'deck-anatomy', front: 'Arteries', back: 'Blood vessels that carry oxygenated blood away from the heart; they have thick muscular walls to withstand high pressure.', sort_order: 113 , front_translations: {"es":"Arterias","de":"Arterien","fr":"Artères","tr":"Arterler","nl":"Slagaders (arteriën)","ru":"Артерии","zh":"动脉","pt_BR":"Artérias","pt_PT":"Artérias"}, back_translations: {"es":"Vasos sanguíneos que transportan sangre oxigenado del corazón; tienen paredes espessas y musculosas para suportar alta presión.","de":"Blutgefäße, die sauerstoffreiches Blut vom Herzen wegleiten; sie haben dicke, muskulöse Wände, um dem hohen Druck standzuhalten.","fr":"Vaisseaux sanguins qui transportent le sang oxygéné depuis le cœur ; ils ont des parois épaisses et musclées pour résister à la haute pression.","tr":"Oksijenli kanı kalpten uzağa taşıyan kan damarları; yüksek basınca dayanmak için kalın kas duvarlarına sahiptir.","nl":"Bloedvaten die zuurstofrijk bloed van het hart wegvoeren; ze hebben dikke gespierde wanden om hoge druk te weerstaan.","ru":"Кровеносные сосуды, несущие оксигенированную кровь от сердца; имеют толстые мышечные стенки, выдерживающие высокое давление.","zh":"将含氧血液从心脏输送至全身的血管；管壁厚而有力，能够承受高压。","pt_BR":"Vasos sanguíneos que transportam sangue oxigenado do coração; têm paredes espessas e musculosas para suportar alta pressão.","pt_PT":"Vasos sanguíneos que transportam sangue oxigenado a partir do coração; têm paredes espessas e musculosas para suportar alta pressão."}},
  { id: 'dc-anatomy-0114', deck_id: 'deck-anatomy', front: 'Sinoatrial (SA) Node', back: 'The heart\'s natural pacemaker located in the right atrium; it generates electrical impulses that initiate each heartbeat.', sort_order: 114 , front_translations: {"es":"Nó sinoatrial (nó SA)","de":"Sinuatrialer Knoten (SA-Knoten)","fr":"Nœud sinusal (nœud sino-auriculaire, NSA)","tr":"Sinoatriyal (SA) Düğüm","nl":"Sinusknoop (SA-knoop)","ru":"Синоатриальный узел (СА-узел)","zh":"窦房结（SA结）","pt_BR":"Nó sinoatrial (nó SA)","pt_PT":"Nó sinoatrial (nó SA)"}, back_translations: {"es":"El marca-passo natural del corazón, localizado en el átrio derecho; genera impulsos elétricos que iniciam cada batimento cardíaco.","de":"Der natürliche Schrittmacher des Herzens im rechten Vorhof; er erzeugt elektrische Impulse, die jeden Herzschlag einleiten.","fr":"Le pacemaker naturel du cœur, situé dans l'oreillette droite ; il génère des impulsions électriques qui initient chaque battement cardiaque.","tr":"Sağ atriyumda bulunan kalbin doğal pili; her kalp atışını başlatan elektriksel uyarılar üretir.","nl":"De natuurlijke pacemaker van het hart in de rechterboezem; het genereert elektrische impulsen die elke hartslag initiëren.","ru":"Естественный водитель ритма сердца, расположенный в правом предсердии; генерирует электрические импульсы, инициирующие каждое сердечное сокращение.","zh":"位于右心房的心脏天然起搏点；产生电脉冲以启动每次心跳。","pt_BR":"O marca-passo natural do coração, localizado no átrio direito; gera impulsos elétricos que iniciam cada batimento cardíaco.","pt_PT":"O pacemaker natural do coração, localizado no átrio direito; gera impulsos elétricos que iniciam cada batimento cardíaco."}},
  { id: 'dc-anatomy-0115', deck_id: 'deck-anatomy', front: 'Pharynx', back: 'The throat; a muscular tube serving as a common pathway for food to the esophagus and air to the larynx; divided into naso-, oro-, and laryngopharynx.', sort_order: 115 , front_translations: {"es":"Faringe","de":"Pharynx (Rachen)","fr":"Pharynx","tr":"Farinks (Yutak)","nl":"Keelholte (pharynx)","ru":"Глотка (фаринкс)","zh":"咽","pt_BR":"Faringe","pt_PT":"Faringe"}, back_translations: {"es":"La garganta; un tubo muscular que serve de via comum para el alimento rumo al esofago y el aire rumo a la laringe; dividida en naso-, oro- y laringofaringe.","de":"Der Rachen; ein Muskelschlauch, der als gemeinsamer Weg für Nahrung zur Speiseröhre und Luft zum Kehlkopf dient; unterteilt in Naso-, Oro- und Laryngopharynx.","fr":"Le pharynx ; un tube musculaire servant de voie commune pour les aliments vers l'œsophage et l'air vers le larynx ; divisé en naso-, oro- et laryngopharynx.","tr":"Boğaz; özofagusa giden yiyecek ve larinkse giden hava için ortak bir yol görevi gören kas tüpü; naso-, oro- ve laringopharynx olarak bölünür.","nl":"De keel; een gespierd kanaal dat dient als gemeenschappelijke doorgang voor voedsel naar de slokdarm en lucht naar het strottenhoofd; onderverdeeld in naso-, oro- en laryngopharynx.","ru":"Глотка; мышечная трубка, служащая общим путём для пищи к пищеводу и воздуха к гортани; делится на носоглотку, ротоглотку и гортаноглотку.","zh":"咽喉；肌肉管道，是食物通往食管和空气通往喉部的共同通道；分为鼻咽、口咽和喉咽三部分。","pt_BR":"A garganta; um tubo muscular que serve de via comum para o alimento rumo ao esôfago e o ar rumo à laringe; dividida em naso-, oro- e laringofaringe.","pt_PT":"A garganta; um tubo muscular que serve de via comum para os alimentos em direção ao esófago e o ar em direção à laringe; dividida em naso-, oro- e laringofaringe."}},
  { id: 'dc-anatomy-0116', deck_id: 'deck-anatomy', front: 'Larynx', back: 'The voice box; a cartilaginous structure connecting the pharynx to the trachea that houses the vocal cords and guards the airway during swallowing.', sort_order: 116 , front_translations: {"es":"Laringe","de":"Kehlkopf (Larynx)","fr":"Larynx","tr":"Gırtlak (Larinks)","nl":"Strottenhoofd (larynx)","ru":"Гортань (ларинкс)","zh":"喉","pt_BR":"Laringe","pt_PT":"Laringe"}, back_translations: {"es":"La caixa de voz; una estructura cartilaginosa que conecta a faringe a la traqueia, abriga las cordas vocais y protege a via aérea durante a deglutición.","de":"Die Stimmbox; eine knorpelige Struktur, die den Rachen mit der Luftröhre verbindet, die Stimmbänder beherbergt und die Atemwege beim Schlucken schützt.","fr":"Le larynx (organe de la phonation) ; une structure cartilagineuse reliant le pharynx à la trachée, qui abrite les cordes vocales et protège les voies respiratoires lors de la déglutition.","tr":"Ses kutusu; farinksi trakeaya bağlayan, ses tellerini barındıran ve yutma sırasında hava yolunu koruyan kıkırdak bir yapı.","nl":"Het strottenhoofd; een kraakbeenachtige structuur die de keelholte met de luchtpijp verbindt, de stembanden huisvest en de luchtweg beschermt tijdens het slikken.","ru":"Голосовой ящик; хрящевая структура, соединяющая глотку с трахеей, содержит голосовые связки и защищает дыхательные пути при глотании.","zh":"喉（声匣）；连接咽部与气管的软骨结构，内含声带，吞咽时可保护气道。","pt_BR":"A caixa de voz; uma estrutura cartilaginosa que conecta a faringe à traqueia, abriga as cordas vocais e protege a via aérea durante a deglutição.","pt_PT":"A caixa de voz; uma estrutura cartilaginosa que liga a faringe à traqueia, alberga as cordas vocais e protege a via aérea durante a deglutição."}},
  { id: 'dc-anatomy-0117', deck_id: 'deck-anatomy', front: 'Epiglottis', back: 'A leaf-shaped cartilage flap at the base of the tongue that folds over the larynx during swallowing to prevent food from entering the airway.', sort_order: 117 , front_translations: {"es":"Epiglote","de":"Epiglottis","fr":"Épiglotte","tr":"Epiglottis","nl":"Strotklepje (epiglottis)","ru":"Надгортанник (эпиглоттис)","zh":"会厌","pt_BR":"Epiglote","pt_PT":"Epiglote"}, back_translations: {"es":"Una aba cartilaginosa en forma de hoja en la base de la língua que se dobra sobre a laringe durante a deglutición para impedir que alimentos entrem en la via aérea.","de":"Ein blattförmiger Knorpellappen an der Zungenwurzel, der sich beim Schlucken über den Kehlkopf faltet, um zu verhindern, dass Nahrung in die Atemwege gelangt.","fr":"Un lambeau cartilagineux en forme de feuille à la base de la langue qui se replie sur le larynx lors de la déglutition pour empêcher les aliments de pénétrer dans les voies aériennes.","tr":"Yutma sırasında yiyeceğin hava yoluna girmesini önlemek için larinks üzerine katlanan, dilin tabanındaki yaprak şekilli kıkırdak kapak.","nl":"Een bladachtige kraakbeenklep aan de basis van de tong die tijdens het slikken over het strottenhoofd vouwt om te voorkomen dat voedsel de luchtweg binnenkomt.","ru":"Листовидный хрящевой лоскут у основания языка, закрывающий гортань при глотании, чтобы пища не попала в дыхательные пути.","zh":"位于舌根的叶形软骨瓣，吞咽时向下覆盖喉部，防止食物进入气道。","pt_BR":"Uma aba cartilaginosa em forma de folha na base da língua que se dobra sobre a laringe durante a deglutição para impedir que alimentos entrem na via aérea.","pt_PT":"Uma aba cartilaginosa em forma de folha na base da língua que se dobra sobre a laringe durante a deglutição para impedir que os alimentos entrem na via aérea."}},
  { id: 'dc-anatomy-0118', deck_id: 'deck-anatomy', front: 'Pleura', back: 'The double-layered membrane surrounding each lung; the inner visceral pleura covers the lung and the outer parietal pleura lines the chest wall, with fluid in between to reduce friction.', sort_order: 118 , front_translations: {"es":"Pleura","de":"Pleura","fr":"Plèvre","tr":"Plevra","nl":"Longvlies (pleura)","ru":"Плевра","zh":"胸膜","pt_BR":"Pleura","pt_PT":"Pleura"}, back_translations: {"es":"La membrana de dupla capa que involucra cada pulmón; a pleura visceral interna cobre el pulmón y a pleura parietal externa reveste a pared torácica, con líquido entre elas para reduzir el atrito.","de":"Die doppelschichtige Membran, die jede Lunge umgibt; die innere Viszeralpleura bedeckt die Lunge, die äußere Parietalpleura kleidet die Brustwand aus, mit Flüssigkeit dazwischen zur Reibungsreduzierung.","fr":"La membrane à deux couches entourant chaque poumon ; la plèvre viscérale interne recouvre le poumon et la plèvre pariétale externe tapisse la paroi thoracique, avec du liquide entre les deux pour réduire les frottements.","tr":"Her akciğeri çevreleyen çift katmanlı zar; iç viseral plevra akciğeri örter, dış parietal plevra göğüs duvarını kaplar ve aralarında sürtünmeyi azaltmak için sıvı bulunur.","nl":"Het dubbellaagse membraan dat elke long omhult; de innerlijke viscerale pleura bedekt de long en de buitenste pariëtale pleura bekleedt de borstwand, met vloeistof ertussen om wrijving te verminderen.","ru":"Двуслойная оболочка, окружающая каждое лёгкое; внутренний висцеральный листок покрывает лёгкое, внешний париетальный листок выстилает грудную стенку, а между ними — жидкость, уменьшающая трение.","zh":"包裹每侧肺的双层膜；内层脏胸膜覆盖肺表面，外层壁胸膜衬于胸壁，两层之间含有液体以减少摩擦。","pt_BR":"A membrana de dupla camada que envolve cada pulmão; a pleura visceral interna cobre o pulmão e a pleura parietal externa reveste a parede torácica, com líquido entre elas para reduzir o atrito.","pt_PT":"A membrana de dupla camada que envolve cada pulmão; a pleura visceral interna cobre o pulmão e a pleura parietal externa reveste a parede torácica, com líquido entre elas para reduzir o atrito."}},
  { id: 'dc-anatomy-0119', deck_id: 'deck-anatomy', front: 'Peritoneum', back: 'The serous membrane lining the abdominal cavity and covering abdominal organs; it supports organs and provides a pathway for nerves and blood vessels.', sort_order: 119 , front_translations: {"es":"Peritonio","de":"Peritoneum (Bauchfell)","fr":"Péritoine","tr":"Periton","nl":"Buikvlies (peritoneum)","ru":"Брюшина (перитонеум)","zh":"腹膜","pt_BR":"Peritônio","pt_PT":"Peritoneu"}, back_translations: {"es":"La membrana serosa que reveste a cavidad abdominal y cobre los órganos abdominais; suporta los órganos y proporciona passaje para nervios y vasos sanguíneos.","de":"Die seröse Membran, die die Bauchhöhle auskleidet und die Bauchorgane bedeckt; sie stützt die Organe und bildet einen Weg für Nerven und Blutgefäße.","fr":"La membrane séreuse tapissant la cavité abdominale et recouvrant les organes abdominaux ; elle soutient les organes et fournit un passage pour les nerfs et les vaisseaux sanguins.","tr":"Karın boşluğunu döşeyen ve karın organlarını örten seröz zar; organları destekler ve sinirler ile kan damarları için bir yol sağlar.","nl":"Het sereuze membraan dat de buikholte bekleedt en buikorganen bedekt; het ondersteunt organen en biedt een doorgang voor zenuwen en bloedvaten.","ru":"Серозная оболочка, выстилающая брюшную полость и покрывающая органы брюшной полости; поддерживает органы и служит путём для нервов и кровеносных сосудов.","zh":"衬覆腹腔并覆盖腹腔器官的浆膜；支撑器官并为神经和血管提供通道。","pt_BR":"A membrana serosa que reveste a cavidade abdominal e cobre os órgãos abdominais; suporta os órgãos e fornece passagem para nervos e vasos sanguíneos.","pt_PT":"A membrana serosa que reveste a cavidade abdominal e cobre os órgãos abdominais; suporta os órgãos e fornece passagem para nervos e vasos sanguíneos."}},
  { id: 'dc-anatomy-0120', deck_id: 'deck-anatomy', front: 'Meninges', back: 'The three protective membranes (dura mater, arachnoid mater, pia mater) surrounding the brain and spinal cord; they cushion the CNS in cerebrospinal fluid.', sort_order: 120 , front_translations: {"es":"Meninges","de":"Hirnhäute (Meningen)","fr":"Méninges","tr":"Beyin Zarları (Meninksler)","nl":"Hersenvliezen (meningen)","ru":"Мозговые оболочки (менингес)","zh":"脑膜","pt_BR":"Meninges","pt_PT":"Meninges"}, back_translations: {"es":"As tres membranas protetoras (dura-máter, aracnoide, pia-máter) que involucran el encéfalo y a medula espinal; amortecem el SNC en el líquido cerebroespinal.","de":"Die drei Schutzmembranen (Dura mater, Arachnoidea, Pia mater), die Gehirn und Rückenmark umgeben; sie polstern das ZNS in Liquor cerebrospinalis.","fr":"Les trois membranes protectrices (dure-mère, arachnoïde, pie-mère) entourant le cerveau et la moelle épinière ; elles amortissent le SNC dans le liquide cérébrospinal.","tr":"Beyin ve omurilik çevresini saran üç koruyucu zar (dura mater, araknoid mater, pia mater); beyin omurilik sıvısında MSS'yi yastıklar.","nl":"De drie beschermende membranen (dura mater, arachnoïdea, pia mater) die de hersenen en het ruggenmerg omhullen; ze kussen het CZS in hersenvloeistof.","ru":"Три защитные оболочки (твёрдая, паутинная и мягкая мозговые оболочки), окружающие головной и спинной мозг; амортизируют ЦНС в спинномозговой жидкости.","zh":"包裹大脑和脊髓的三层保护膜（硬脑膜、蛛网膜、软脑膜）；在脑脊液中对中枢神经系统起缓冲保护作用。","pt_BR":"As três membranas protetoras (dura-máter, aracnoide, pia-máter) que envolvem o encéfalo e a medula espinal; amortecem o SNC no líquido cerebroespinal.","pt_PT":"As três membranas protetoras (dura-máter, aracnoide, pia-máter) que envolvem o encéfalo e a medula espinal; amortecem o SNC no líquido cefalorraquidiano."}},
  { id: 'dc-anatomy-0121', deck_id: 'deck-anatomy', front: 'Cerebrospinal Fluid (CSF)', back: 'A clear fluid produced by the choroid plexus that circulates around the brain and spinal cord, providing cushioning and removing waste products.', sort_order: 121 , front_translations: {"es":"Líquido cefalorraquidiano (LCR)","de":"Liquor cerebrospinalis (Gehirn-Rückenmarks-Flüssigkeit)","fr":"Liquide cérébrospinal (LCS)","tr":"Beyin Omurilik Sıvısı (BOS)","nl":"Hersenvocht (liquor cerebrospinalis, CSF)","ru":"Спинномозговая жидкость (ликвор, СМЖ)","zh":"脑脊液（CSF）","pt_BR":"Líquido cefalorraquidiano (LCR)","pt_PT":"Líquido cefalorraquidiano (LCR)"}, back_translations: {"es":"Un líquido transparente producido por el plexo coroide que circula alrededor del encéfalo y de la medula espinal, proporcionando amortecimento y removendo productos residuais.","de":"Eine klare Flüssigkeit, die vom Plexus choroideus produziert wird und um das Gehirn und das Rückenmark zirkuliert; sie bietet Stoßdämpfung und entfernt Abfallprodukte.","fr":"Un liquide clair produit par le plexus choroïde qui circule autour du cerveau et de la moelle épinière, fournissant un amorti et éliminant les déchets.","tr":"Koroid pleksus tarafından üretilen ve beyin ile omurilik etrafında dolaşan, tamponlama sağlayan ve atık ürünleri uzaklaştıran berrak sıvı.","nl":"Een helder vocht geproduceerd door de plexus choroideus dat rondom de hersenen en het ruggenmerg circuleert, demping biedt en afvalstoffen verwijdert.","ru":"Прозрачная жидкость, вырабатываемая сосудистым сплетением; циркулирует вокруг головного и спинного мозга, обеспечивая амортизацию и удаление продуктов обмена.","zh":"由脉络丛产生的透明液体，循环于大脑和脊髓周围，起缓冲作用并清除代谢废物。","pt_BR":"Um líquido transparente produzido pelo plexo coroide que circula ao redor do encéfalo e da medula espinal, fornecendo amortecimento e removendo produtos residuais.","pt_PT":"Um líquido transparente produzido pelo plexo coróide que circula em torno do encéfalo e da medula espinal, proporcionando amortecimento e removendo produtos residuais."}},
  { id: 'dc-anatomy-0122', deck_id: 'deck-anatomy', front: 'Spinal Cord', back: 'A cylindrical bundle of nerve fibers extending from the brain stem to the lumbar vertebrae; it transmits signals between the brain and body and mediates reflexes.', sort_order: 122 , front_translations: {"es":"Medula espinal","de":"Rückenmark","fr":"Moelle épinière","tr":"Omurilik","nl":"Ruggenmerg","ru":"Спинной мозг","zh":"脊髓","pt_BR":"Medula espinal","pt_PT":"Medula espinal"}, back_translations: {"es":"Un feixe cilíndrico de fibras nervosas que se estende del tronco encefálico hasta las vértebras lombares; transmite señales entre el encéfalo y el cuerpo y medeia reflexos.","de":"Ein zylindrisches Nervenfaserbündel, das vom Hirnstamm bis zu den Lendenwirbeln reicht; es überträgt Signale zwischen Gehirn und Körper und vermittelt Reflexe.","fr":"Un faisceau cylindrique de fibres nerveuses s'étendant du tronc cérébral aux vertèbres lombaires ; il transmet les signaux entre le cerveau et le corps et médie les réflexes.","tr":"Beyin sapından lomber vertebralara uzanan silindirik sinir lifi demeti; beyin ile vücut arasında sinyalleri iletir ve reflekslere aracılık eder.","nl":"Een cilindrische bundel zenuwvezels die zich uitstrekt van de hersenstam tot de lendenwervels; het verzendt signalen tussen de hersenen en het lichaam en bemiddelt reflexen.","ru":"Цилиндрический пучок нервных волокон, проходящий от ствола мозга до поясничных позвонков; передаёт сигналы между мозгом и телом, обеспечивает рефлексы.","zh":"从脑干延伸至腰椎的圆柱形神经纤维束；在大脑与身体之间传递信号并介导反射。","pt_BR":"Um feixe cilíndrico de fibras nervosas que se estende do tronco encefálico até as vértebras lombares; transmite sinais entre o encéfalo e o corpo e medeia reflexos.","pt_PT":"Um feixe cilíndrico de fibras nervosas que se estende do tronco encefálico até às vértebras lombares; transmite sinais entre o encéfalo e o corpo e medeia reflexos."}},
  { id: 'dc-anatomy-0123', deck_id: 'deck-anatomy', front: 'Brachial Plexus', back: 'A network of nerves from C5–T1 that supplies the arm and hand; injuries can cause weakness or paralysis of the arm.', sort_order: 123 , front_translations: {"es":"Plexo braquial","de":"Plexus brachialis","fr":"Plexus brachial","tr":"Brakiyal Pleksus","nl":"Plexus brachialis","ru":"Плечевое сплетение","zh":"臂丛","pt_BR":"Plexo braquial","pt_PT":"Plexo braquial"}, back_translations: {"es":"Una red de nervios de C5–T1 que supre el brazo y a mano; lesões pueden causar fraqueza o paralisia del brazo.","de":"Ein Nervennetzwerk von C5–T1, das Arm und Hand versorgt; Verletzungen können Schwäche oder Lähmung des Arms verursachen.","fr":"Un réseau de nerfs de C5 à T1 qui innerve le bras et la main ; les lésions peuvent provoquer une faiblesse ou une paralysie du bras.","tr":"Kol ve eli innerve eden C5–T1 sinir ağı; yaralanmalar kolda zayıflık veya felce neden olabilir.","nl":"Een netwerk van zenuwen van C5–T1 dat de arm en hand innerveert; letsels kunnen zwakte of verlamming van de arm veroorzaken.","ru":"Нервное сплетение из корешков C5–T1, иннервирующее руку и кисть; травмы могут вызвать слабость или паралич руки.","zh":"由C5–T1神经根构成的神经网络，支配手臂和手部；损伤可导致手臂无力或瘫痪。","pt_BR":"Uma rede de nervos de C5–T1 que supre o braço e a mão; lesões podem causar fraqueza ou paralisia do braço.","pt_PT":"Uma rede de nervos de C5–T1 que inerva o braço e a mão; as lesões podem causar fraqueza ou paralisia do braço."}},
  { id: 'dc-anatomy-0124', deck_id: 'deck-anatomy', front: 'Sciatic Nerve', back: 'The longest and thickest nerve in the body; it originates from the lumbar and sacral plexus and supplies the back of the thigh and the entire lower leg.', sort_order: 124 , front_translations: {"es":"Nervio ciático","de":"Ischiasnerv","fr":"Nerf sciatique","tr":"Siyatik Sinir","nl":"Heupzenuw (nervus ischiadicus)","ru":"Седалищный нерв","zh":"坐骨神经","pt_BR":"Nervo ciático","pt_PT":"Nervo ciático"}, back_translations: {"es":"El nervio más ancho y espesso del cuerpo; se origina del plexo lombar y sacral y inerva a parte posterior de la muslo y toda a pierna.","de":"Der längste und dickste Nerv im Körper; er entspringt dem Lumbal- und Sakralplexus und versorgt die Rückseite des Oberschenkels sowie das gesamte Unterschenkel.","fr":"Le nerf le plus long et le plus épais du corps ; il est issu du plexus lombo-sacré et innerve la face postérieure de la cuisse et l'ensemble de la jambe.","tr":"Vücuttaki en uzun ve en kalın sinir; lomber ve sakral pleksustan kaynaklanır ve uyluğun arka yüzü ile tüm alt bacağı innerve eder.","nl":"De langste en dikste zenuw in het lichaam; hij ontspringt uit de lumbale en sacrale plexus en innerveert de achterkant van de dij en het gehele onderbeen.","ru":"Самый длинный и толстый нерв в теле; берёт начало от поясничного и крестцового сплетений, иннервирует заднюю поверхность бедра и всю нижнюю конечность.","zh":"人体内最长、最粗的神经；起自腰骶丛，支配大腿后侧和整个小腿。","pt_BR":"O nervo mais longo e espesso do corpo; origina-se do plexo lombar e sacral e inerva a parte posterior da coxa e toda a perna.","pt_PT":"O nervo mais longo e espesso do corpo; origina-se do plexo lombar e sagrado e inerva a face posterior da coxa e toda a perna."}},
  { id: 'dc-anatomy-0125', deck_id: 'deck-anatomy', front: 'Vagus Nerve (CN X)', back: 'The longest cranial nerve; it innervates organs of the thorax and abdomen, regulating heart rate, digestion, and is the main parasympathetic nerve.', sort_order: 125 , front_translations: {"es":"Nervio vago (NC X)","de":"Nervus vagus (N. X)","fr":"Nerf vague (nerf X)","tr":"Vagus Siniri (CN X)","nl":"Nervus vagus (CN X)","ru":"Блуждающий нерв (X черепной нерв)","zh":"迷走神经（第X对脑神经）","pt_BR":"Nervo vago (NC X)","pt_PT":"Nervo vago (NC X)"}, back_translations: {"es":"El nervio craneal más ancho; inerva órganos del tórax y del abdome, regulando a frecuencia cardíaca, a digestión, y es el principal nervio parassimpático.","de":"Der längste Hirnnerv; er innerviert die Organe des Brustkorbs und des Bauchs, reguliert Herzfrequenz und Verdauung und ist der wichtigste parasympathische Nerv.","fr":"Le plus long nerf crânien ; il innerve les organes du thorax et de l'abdomen, régulant la fréquence cardiaque, la digestion, et est le principal nerf parasympathique.","tr":"En uzun kranyal sinir; göğüs ve karın organlarını innerve eder, kalp hızını ve sindirimi düzenler ve ana parasempatik sinirdir.","nl":"De langste hersenzenuw; hij innerveert organen van de borst en buik, reguleert hartslag en spijsvertering en is de belangrijkste parasympathische zenuw.","ru":"Самый длинный черепной нерв; иннервирует органы грудной клетки и брюшной полости, регулирует частоту сердечных сокращений, пищеварение и является основным парасимпатическим нервом.","zh":"最长的脑神经；支配胸腹腔器官，调节心率和消化功能，是主要的副交感神经。","pt_BR":"O nervo craniano mais longo; inerva órgãos do tórax e do abdome, regulando a frequência cardíaca, a digestão, e é o principal nervo parassimpático.","pt_PT":"O nervo craniano mais longo; inerva órgãos do tórax e do abdómen, regulando a frequência cardíaca, a digestão, e é o principal nervo parassimpático."}},
  { id: 'dc-anatomy-0126', deck_id: 'deck-anatomy', front: 'Optic Nerve (CN II)', back: 'The cranial nerve carrying visual information from the retina to the brain; it is technically an extension of the brain, not a true peripheral nerve.', sort_order: 126 , front_translations: {"es":"Nervio óptico (NC II)","de":"Sehnerv (N. II)","fr":"Nerf optique (nerf II)","tr":"Optik Sinir (CN II)","nl":"Oogzenuw (nervus opticus, CN II)","ru":"Зрительный нерв (II черепной нерв)","zh":"视神经（第II对脑神经）","pt_BR":"Nervo óptico (NC II)","pt_PT":"Nervo óptico (NC II)"}, back_translations: {"es":"El nervio craneal que transporta informaciones visuais de la retina al encéfalo; tecnicamente es una extensão del encéfalo, no un verdadero nervio periférico.","de":"Der Hirnnerv, der visuelle Informationen von der Netzhaut zum Gehirn überträgt; er ist technisch gesehen eine Verlängerung des Gehirns und kein echter peripherer Nerv.","fr":"Le nerf crânien transportant les informations visuelles de la rétine vers le cerveau ; il est techniquement une extension du cerveau et non un vrai nerf périphérique.","tr":"Görsel bilgiyi retinadan beyne taşıyan kranyal sinir; teknik olarak gerçek bir periferik sinir değil, beynin bir uzantısıdır.","nl":"De hersenzenuw die visuele informatie van de retina naar de hersenen stuurt; het is technisch gezien een verlengstuk van de hersenen, geen echte perifere zenuw.","ru":"Черепной нерв, передающий зрительную информацию от сетчатки к мозгу; технически является продолжением мозга, а не настоящим периферическим нервом.","zh":"将视觉信息从视网膜传递到大脑的脑神经；从技术上讲，它是大脑的延伸，而非真正的周围神经。","pt_BR":"O nervo craniano que transporta informações visuais da retina ao encéfalo; tecnicamente é uma extensão do encéfalo, não um verdadeiro nervo periférico.","pt_PT":"O nervo craniano que transporta informações visuais da retina para o encéfalo; tecnicamente é uma extensão do encéfalo, não um verdadeiro nervo periférico."}},
  { id: 'dc-anatomy-0127', deck_id: 'deck-anatomy', front: 'Retina', back: 'The light-sensitive layer at the back of the eye containing photoreceptors (rods and cones) that convert light into electrical signals sent to the brain.', sort_order: 127 , front_translations: {"es":"Retina","de":"Netzhaut (Retina)","fr":"Rétine","tr":"Retina","nl":"Netvlies (retina)","ru":"Сетчатка (ретина)","zh":"视网膜","pt_BR":"Retina","pt_PT":"Retina"}, back_translations: {"es":"La capa fotossensible en la parte posterior del ojo, conteniendo fotorreceptores (bastonetes y cones) que convierten luz en señales elétricos enviados al encéfalo.","de":"Die lichtempfindliche Schicht im hinteren Teil des Auges, die Fotorezeptoren (Stäbchen und Zapfen) enthält, die Licht in elektrische Signale umwandeln, die zum Gehirn gesendet werden.","fr":"La couche photosensible à l'arrière de l'œil contenant des photorécepteurs (bâtonnets et cônes) qui convertissent la lumière en signaux électriques envoyés au cerveau.","tr":"Işığı beyne gönderilen elektriksel sinyallere dönüştüren fotoreseptörler (çubuklar ve koniler) içeren, gözün arka kısmındaki ışığa duyarlı tabaka.","nl":"De lichtgevoelige laag aan de achterkant van het oog die fotoreceptoren (staafjes en kegeltjes) bevat die licht omzetten in elektrische signalen die naar de hersenen worden gestuurd.","ru":"Светочувствительный слой на задней части глаза, содержащий фоторецепторы (палочки и колбочки), преобразующие свет в электрические сигналы, передаваемые в мозг.","zh":"位于眼球后部的感光层，含有将光线转化为电信号并传送至大脑的感光细胞（视杆细胞和视锥细胞）。","pt_BR":"A camada fotossensível na parte posterior do olho, contendo fotorreceptores (bastonetes e cones) que convertem luz em sinais elétricos enviados ao encéfalo.","pt_PT":"A camada fotossensível na parte posterior do olho, contendo fotorreceptores (bastonetes e cones) que convertem a luz em sinais elétricos enviados ao encéfalo."}},
  { id: 'dc-anatomy-0128', deck_id: 'deck-anatomy', front: 'Cochlea', back: 'A snail-shaped fluid-filled structure in the inner ear that contains hair cells to convert sound vibrations into nerve impulses for hearing.', sort_order: 128 , front_translations: {"es":"Cóclea","de":"Cochlea (Hörschnecke)","fr":"Cochlée","tr":"Koklea (Salyangoz)","nl":"Slakkenhuis (cochlea)","ru":"Улитка (кохлея)","zh":"耳蜗","pt_BR":"Cóclea","pt_PT":"Cóclea"}, back_translations: {"es":"Una estructura en forma de caracol preenchida con líquido en el ouvido interno que contiene células ciliadas para converter vibraciones sonoras en impulsos nervosos para a audición.","de":"Eine schneckenförmige, flüssigkeitsgefüllte Struktur im Innenohr, die Haarzellen enthält, die Schallschwingungen in Nervenimpulse für das Hören umwandeln.","fr":"Une structure en forme d'escargot remplie de liquide dans l'oreille interne, contenant des cellules ciliées qui convertissent les vibrations sonores en impulsions nerveuses pour l'audition.","tr":"İç kulakta, ses titreşimlerini işitme için sinir uyarılarına dönüştüren tüy hücrelerini içeren salyangoz şeklinde, sıvı dolu yapı.","nl":"Een slakkenhuisvormige, vloeistofgevulde structuur in het binnenoor met haarcellen die geluidsvibraties omzetten in zenuwimpulsen voor het gehoor.","ru":"Спиралевидная заполненная жидкостью структура во внутреннем ухе, содержащая волосковые клетки, преобразующие звуковые колебания в нервные импульсы для слуха.","zh":"内耳中充满液体的蜗牛形结构，含有将声波振动转化为听觉神经冲动的毛细胞。","pt_BR":"Uma estrutura em forma de caracol preenchida com líquido no ouvido interno que contém células ciliadas para converter vibrações sonoras em impulsos nervosos para a audição.","pt_PT":"Uma estrutura em forma de caracol preenchida com líquido no ouvido interno que contém células ciliadas para converter vibrações sonoras em impulsos nervosos para a audição."}},
  { id: 'dc-anatomy-0129', deck_id: 'deck-anatomy', front: 'Semicircular Canals', back: 'Three fluid-filled loops in the inner ear oriented in different planes; they detect rotational head movements and contribute to balance.', sort_order: 129 , front_translations: {"es":"Canais semicirculares","de":"Bogengänge","fr":"Canaux semi-circulaires","tr":"Yarım Daire Kanalları","nl":"Halfcirkelvormige kanalen","ru":"Полукружные каналы","zh":"半规管","pt_BR":"Canais semicirculares","pt_PT":"Canais semicirculares"}, back_translations: {"es":"Tres alças cheias de líquido en el ouvido interno orientadas en diferentes planos; detectam movimientos rotatórios de la cabeza y contribuyen para el equilíbrio.","de":"Drei flüssigkeitsgefüllte Schleifen im Innenohr, die in verschiedenen Ebenen ausgerichtet sind; sie erkennen Rotationsbewegungen des Kopfes und tragen zum Gleichgewicht bei.","fr":"Trois boucles remplies de liquide dans l'oreille interne orientées dans différents plans ; elles détectent les mouvements rotatoires de la tête et contribuent à l'équilibre.","tr":"Farklı düzlemlerde yönlendirilmiş, iç kulaktaki üç sıvı dolu halka; başın dönme hareketlerini algılar ve dengeye katkıda bulunur.","nl":"Drie vloeistofgevulde lussen in het binnenoor georiënteerd in verschillende vlakken; ze detecteren roterende hoofdbewegingen en dragen bij aan het evenwicht.","ru":"Три заполненные жидкостью полукруговые трубки во внутреннем ухе, ориентированные в разных плоскостях; определяют вращательные движения головы и участвуют в поддержании равновесия.","zh":"内耳中三个充满液体的环状管道，各自位于不同平面；感知头部旋转运动，参与维持平衡。","pt_BR":"Três alças cheias de líquido no ouvido interno orientadas em diferentes planos; detectam movimentos rotatórios da cabeça e contribuem para o equilíbrio.","pt_PT":"Três alças cheias de líquido no ouvido interno orientadas em diferentes planos; detetam movimentos rotatórios da cabeça e contribuem para o equilíbrio."}},
  { id: 'dc-anatomy-0130', deck_id: 'deck-anatomy', front: 'Bone Marrow', back: 'Soft tissue inside bones; red marrow produces blood cells (hematopoiesis) while yellow marrow stores fat. Red marrow is primarily in flat bones and vertebrae.', sort_order: 130 , front_translations: {"es":"Médula ósea","de":"Knochenmark","fr":"Moelle osseuse","tr":"Kemik İliği","nl":"Beenmerg","ru":"Костный мозг","zh":"骨髓","pt_BR":"Medula óssea","pt_PT":"Medula óssea"}, back_translations: {"es":"Tejido mole dentro de los huesos; a medula roja produce células sanguíneas (hematopoiese) mientras a medula amarela almacena gordura. La medula roja está principalmente en los huesos planos y vértebras.","de":"Weiches Gewebe im Inneren der Knochen; rotes Mark produziert Blutzellen (Hämatopoese), während gelbes Mark Fett speichert. Rotes Mark befindet sich vor allem in flachen Knochen und Wirbeln.","fr":"Tissu mou à l'intérieur des os ; la moelle rouge produit des cellules sanguines (hématopoïèse) tandis que la moelle jaune stocke les graisses. La moelle rouge se trouve principalement dans les os plats et les vertèbres.","tr":"Kemiklerin içindeki yumuşak doku; kırmızı ilik kan hücrelerini üretir (hematopoez), sarı ilik ise yağ depolar. Kırmızı ilik öncelikle düz kemikler ve vertebralarda bulunur.","nl":"Zacht weefsel in de botten; rood merg produceert bloedcellen (hematopoëse) terwijl geel merg vet opslaat. Rood merg bevindt zich voornamelijk in platte botten en wervels.","ru":"Мягкая ткань внутри костей; красный костный мозг производит клетки крови (гемопоэз), жёлтый — хранит жир. Красный мозг находится преимущественно в плоских костях и позвонках.","zh":"骨骼内部的软组织；红骨髓负责造血（产生血细胞），黄骨髓储存脂肪。红骨髓主要存在于扁骨和椎骨中。","pt_BR":"Tecido mole dentro dos ossos; a medula vermelha produz células sanguíneas (hematopoiese) enquanto a medula amarela armazena gordura. A medula vermelha está principalmente nos ossos planos e vértebras.","pt_PT":"Tecido mole no interior dos ossos; a medula vermelha produz células sanguíneas (hematopoiese) enquanto a medula amarela armazena gordura. A medula vermelha encontra-se principalmente nos ossos planos e vértebras."}},
  { id: 'dc-anatomy-0131', deck_id: 'deck-anatomy', front: 'Periosteum', back: 'The dense fibrous membrane covering the outer surface of bones (except articular surfaces); it contains osteoblasts for bone growth and repair.', sort_order: 131 , front_translations: {"es":"Periósteo","de":"Periost","fr":"Périoste","tr":"Periost","nl":"Beenvlies (periost)","ru":"Надкостница (периост)","zh":"骨膜","pt_BR":"Periósteo","pt_PT":"Periósteo"}, back_translations: {"es":"La membrana fibrosa densa que cobre a superficie externa de los huesos (excepto las superfícies articulares); contiene osteoblastos para el crecimiento y reparación ósea.","de":"Die dichte Fasermembran, die die Außenfläche der Knochen bedeckt (mit Ausnahme der Gelenkflächen); sie enthält Osteoblasten für das Knochenwachstum und die Knochenreparatur.","fr":"La membrane fibreuse dense recouvrant la surface externe des os (sauf les surfaces articulaires) ; elle contient des ostéoblastes pour la croissance et la réparation osseuses.","tr":"Kemiklerin dış yüzeyini (eklem yüzeyleri hariç) örten yoğun lifli zar; kemik büyümesi ve onarımı için osteoblastlar içerir.","nl":"Het dichte vezelige membraan dat de buitenoppervlakte van botten bedekt (behalve gewrichtsoppervlakken); het bevat osteoblasten voor botgroei en herstel.","ru":"Плотная волокнистая оболочка, покрывающая внешнюю поверхность костей (кроме суставных поверхностей); содержит остеобласты, обеспечивающие рост и регенерацию кости.","zh":"覆盖骨骼外表面（关节面除外）的致密纤维膜；含有破骨细胞，参与骨骼生长和修复。","pt_BR":"A membrana fibrosa densa que cobre a superfície externa dos ossos (exceto as superfícies articulares); contém osteoblastos para o crescimento e reparação óssea.","pt_PT":"A membrana fibrosa densa que cobre a superfície externa dos ossos (exceto as superfícies articulares); contém osteoblastos para o crescimento e reparação óssea."}},
  { id: 'dc-anatomy-0132', deck_id: 'deck-anatomy', front: 'Cartilage', back: 'A flexible connective tissue lacking blood vessels; hyaline cartilage covers joint surfaces, fibrocartilage forms discs, and elastic cartilage forms the ear.', sort_order: 132 , front_translations: {"es":"Cartílago","de":"Knorpel","fr":"Cartilage","tr":"Kıkırdak","nl":"Kraakbeen","ru":"Хрящ","zh":"软骨","pt_BR":"Cartilagem","pt_PT":"Cartilagem"}, back_translations: {"es":"Un tejido conjuntivo flexible desprovido de vasos sanguíneos; cartílago hialina cobre superfícies articulares, fibrocartilaje forma discos y cartílago elástica forma el ouvido.","de":"Ein flexibles Bindegewebe ohne Blutgefäße; hyaliner Knorpel bedeckt Gelenkflächen, Faserknorpel bildet Bandscheiben und elastischer Knorpel bildet das Ohr.","fr":"Un tissu conjonctif flexible dépourvu de vaisseaux sanguins ; le cartilage hyalin recouvre les surfaces articulaires, le fibrocartilage forme les disques et le cartilage élastique forme l'oreille.","tr":"Kan damarı içermeyen esnek bağ doku; hyalin kıkırdak eklem yüzeylerini örter, fibrokartilaj diskler oluşturur ve elastik kıkırdak kulağı oluşturur.","nl":"Een flexibel bindweefsel zonder bloedvaten; hyalien kraakbeen bedekt gewrichtsoppervlakken, fibrokraakbeen vormt schijven en elastisch kraakbeen vormt het oor.","ru":"Гибкая соединительная ткань без кровеносных сосудов; гиалиновый хрящ покрывает суставные поверхности, волокнистый — образует диски, эластический — ухо.","zh":"不含血管的弹性结缔组织；透明软骨覆盖关节面，纤维软骨构成椎间盘，弹性软骨构成耳廓。","pt_BR":"Um tecido conjuntivo flexível desprovido de vasos sanguíneos; cartilagem hialina cobre superfícies articulares, fibrocartilagem forma discos e cartilagem elástica forma o ouvido.","pt_PT":"Um tecido conjuntivo flexível sem vasos sanguíneos; cartilagem hialina cobre superfícies articulares, fibrocartilagem forma discos e cartilagem elástica forma o ouvido."}},
  { id: 'dc-anatomy-0133', deck_id: 'deck-anatomy', front: 'Osteoblast', back: 'A bone-forming cell that synthesizes and secretes the organic matrix of bone and promotes its mineralization.', sort_order: 133 , front_translations: {"es":"Osteoblasto","de":"Osteoblast","fr":"Ostéoblaste","tr":"Osteoblast","nl":"Osteoblast","ru":"Остеобласт","zh":"成骨细胞","pt_BR":"Osteoblasto","pt_PT":"Osteoblasto"}, back_translations: {"es":"Una célula formadora de hueso que sintetiza y secreta a matriz orgánica del hueso y promueve su mineralización.","de":"Eine knochenbildende Zelle, die die organische Matrix des Knochens synthetisiert und ausschüttet und deren Mineralisierung fördert.","fr":"Une cellule ostéoformatrice qui synthétise et sécrète la matrice organique de l'os et favorise sa minéralisation.","tr":"Kemiğin organik matriksini sentezleyip salgılayan ve mineralizasyonunu destekleyen kemik yapıcı hücre.","nl":"Een botaanmakende cel die de organische matrix van bot synthetiseert en uitscheidt en de mineralisatie ervan bevordert.","ru":"Костеобразующая клетка, синтезирующая и секретирующая органическую матрицу кости и способствующая её минерализации.","zh":"合成和分泌骨有机基质并促进矿化的成骨细胞。","pt_BR":"Uma célula formadora de osso que sintetiza e secreta a matriz orgânica do osso e promove sua mineralização.","pt_PT":"Uma célula formadora de osso que sintetiza e secreta a matriz orgânica do osso e promove a sua mineralização."}},
  { id: 'dc-anatomy-0134', deck_id: 'deck-anatomy', front: 'Osteoclast', back: 'A large multi-nucleated cell that resorbs bone tissue by secreting acids and enzymes; essential for bone remodeling and calcium regulation.', sort_order: 134 , front_translations: {"es":"Osteoclasto","de":"Osteoklast","fr":"Ostéoclaste","tr":"Osteoklast","nl":"Osteoclast","ru":"Остеокласт","zh":"破骨细胞","pt_BR":"Osteoclasto","pt_PT":"Osteoclasto"}, back_translations: {"es":"Una grande célula multinucleada que reabsorve el tejido óseo secretando ácidos y enzimas; esencial para a remodelación ósea y a regulación del cálcio.","de":"Eine große mehrkernige Zelle, die Knochengewebe durch Ausschüttung von Säuren und Enzymen resorbiert; sie ist wesentlich für den Knochenumbau und die Kalziumregulation.","fr":"Une grande cellule multinucléée qui résorbe le tissu osseux en sécrétant des acides et des enzymes ; essentielle pour le remodelage osseux et la régulation du calcium.","tr":"Asitler ve enzimler salgılayarak kemik dokusunu rezorbe eden büyük çok çekirdekli hücre; kemik yeniden şekillenmesi ve kalsiyum düzenlemesi için gereklidir.","nl":"Een grote meerkernige cel die botweefsel resorbiert door zuren en enzymen af te scheiden; essentieel voor botombouw en calciumregulatie.","ru":"Крупная многоядерная клетка, резорбирующая костную ткань путём секреции кислот и ферментов; необходима для ремоделирования кости и регуляции уровня кальция.","zh":"通过分泌酸和酶来吸收骨组织的大型多核细胞；对骨重塑和钙调节至关重要。","pt_BR":"Uma grande célula multinucleada que reabsorve o tecido ósseo secretando ácidos e enzimas; essencial para a remodelação óssea e a regulação do cálcio.","pt_PT":"Uma grande célula multinucleada que reabsorve o tecido ósseo secretando ácidos e enzimas; essencial para a remodelação óssea e a regulação do cálcio."}},
  { id: 'dc-anatomy-0135', deck_id: 'deck-anatomy', front: 'Duodenum', back: 'The first and shortest segment of the small intestine; it receives chyme from the stomach and digestive secretions from the pancreas and bile duct.', sort_order: 135 , front_translations: {"es":"Duodeno","de":"Zwölffingerdarm (Duodenum)","fr":"Duodénum","tr":"Duedonum (Onikiparmak Bağırsağı)","nl":"Twaalfvingerige darm (duodenum)","ru":"Двенадцатиперстная кишка (дуоденум)","zh":"十二指肠","pt_BR":"Duodeno","pt_PT":"Duodeno"}, back_translations: {"es":"El primero y más corto segmento del intestino delgado; recibe el quimo del estomago y las secreciones digestivas del pancreas y del ducto biliar.","de":"Das erste und kürzeste Segment des Dünndarms; es empfängt Speisebrei aus dem Magen sowie Verdauungssekrete aus der Bauchspeicheldrüse und dem Gallengang.","fr":"Le premier et le plus court segment de l'intestin grêle ; il reçoit le chyme de l'estomac ainsi que les sécrétions digestives du pancréas et du canal cholédoque.","tr":"İnce bağırsağın ilk ve en kısa bölümü; mideden kimus ve pankreas ile safra kanalından sindirim salgılarını alır.","nl":"Het eerste en kortste segment van de dunne darm; het ontvangt chyme van de maag en spijsverteringssecreties van de alvleesklier en galgang.","ru":"Первый и самый короткий отдел тонкой кишки; принимает химус из желудка и пищеварительные секреты из поджелудочной железы и жёлчного протока.","zh":"小肠的第一段也是最短的一段；接收来自胃的食糜以及来自胰腺和胆管的消化液。","pt_BR":"O primeiro e mais curto segmento do intestino delgado; recebe o quimo do estômago e as secreções digestivas do pâncreas e do ducto biliar.","pt_PT":"O primeiro e mais curto segmento do intestino delgado; recebe o quimo do estômago e as secreções digestivas do pâncreas e do ducto biliar."}},
  { id: 'dc-anatomy-0136', deck_id: 'deck-anatomy', front: 'Jejunum', back: 'The middle segment of the small intestine (~2.5 m); lined with villi and microvilli for maximum nutrient absorption.', sort_order: 136 , front_translations: {"es":"Jejuno","de":"Jejunum (Leerdarm)","fr":"Jéjunum","tr":"Jejunum (Boş Bağırsak)","nl":"Nuchtere darm (jejunum)","ru":"Тощая кишка (jejunum)","zh":"空肠","pt_BR":"Jejuno","pt_PT":"Jejuno"}, back_translations: {"es":"El segmento intermediário del intestino delgado (~2,5 m); revestido con vilosidades y microvilosidades para absorción máxima de nutrientes.","de":"Das mittlere Segment des Dünndarms (~2,5 m); mit Zotten und Mikrovilli ausgekleidet für maximale Nährstoffaufnahme.","fr":"Le segment intermédiaire de l'intestin grêle (~2,5 m) ; tapissé de villosités et de microvillosités pour une absorption maximale des nutriments.","tr":"İnce bağırsağın orta bölümü (~2,5 m); maksimum besin emilimi için villüsler ve mikrovilli ile kaplıdır.","nl":"Het middelste segment van de dunne darm (~2,5 m); bekleed met villi en microvilli voor maximale voedingsstofabsorptie.","ru":"Средний отдел тонкой кишки (~2,5 м); выстлан ворсинками и микроворсинками для максимального всасывания питательных веществ.","zh":"小肠中间段（约2.5米）；内衬绒毛和微绒毛，以实现最大化的营养物质吸收。","pt_BR":"O segmento intermediário do intestino delgado (~2,5 m); revestido com vilosidades e microvilosidades para absorção máxima de nutrientes.","pt_PT":"O segmento intermédio do intestino delgado (~2,5 m); revestido com vilosidades e microvilosidades para absorção máxima de nutrientes."}},
  { id: 'dc-anatomy-0137', deck_id: 'deck-anatomy', front: 'Ileum', back: 'The final segment of the small intestine (~3.5 m); it absorbs vitamin B12 and bile salts and empties into the cecum of the large intestine.', sort_order: 137 , front_translations: {"es":"Íleo","de":"Ileum (Hüftdarm)","fr":"Iléon","tr":"İleum (Kıvrım Bağırsak)","nl":"Kronkeldarm (ileum)","ru":"Подвздошная кишка (ileum)","zh":"回肠","pt_BR":"Íleo","pt_PT":"Íleo"}, back_translations: {"es":"El segmento final del intestino delgado (~3,5 m); absorbe vitamina B12 y sais biliares y desemboca en el ceco del intestino grueso.","de":"Das letzte Segment des Dünndarms (~3,5 m); es absorbiert Vitamin B12 und Gallensalze und mündet in das Zäkum des Dickdarms.","fr":"Le dernier segment de l'intestin grêle (~3,5 m) ; il absorbe la vitamine B12 et les sels biliaires et débouche dans le cæcum du gros intestin.","tr":"İnce bağırsağın son bölümü (~3,5 m); B12 vitamini ve safra tuzlarını emer ve büyük bağırsağın çekumuna boşalır.","nl":"Het laatste segment van de dunne darm (~3,5 m); het absorbeert vitamine B12 en galzouten en mondt uit in het caecum van de dikke darm.","ru":"Конечный отдел тонкой кишки (~3,5 м); всасывает витамин B12 и жёлчные соли, открывается в слепую кишку толстого кишечника.","zh":"小肠最后一段（约3.5米）；负责吸收维生素B12和胆汁盐，并开口于大肠的盲肠。","pt_BR":"O segmento final do intestino delgado (~3,5 m); absorve vitamina B12 e sais biliares e desemboca no ceco do intestino grosso.","pt_PT":"O segmento final do intestino delgado (~3,5 m); absorve vitamina B12 e sais biliares e desemboca no ceco do intestino grosso."}},
  { id: 'dc-anatomy-0138', deck_id: 'deck-anatomy', front: 'Cecum', back: 'The pouch-like beginning of the large intestine where the ileum joins; the appendix is attached to it.', sort_order: 138 , front_translations: {"es":"Ceco","de":"Blinddarm (Zäkum)","fr":"Cæcum","tr":"Çekum (Kör Bağırsak)","nl":"Blindedarm (caecum)","ru":"Слепая кишка (цекум)","zh":"盲肠","pt_BR":"Ceco","pt_PT":"Cego"}, back_translations: {"es":"El início en forma de bolsa del intestino grueso donde el íleo se une; el apéndice está ligado a ele.","de":"Der beutelartige Beginn des Dickdarms, an dem das Ileum einmündet; der Blinddarm (Appendix) ist daran befestigt.","fr":"Le début en forme de poche du gros intestin où l'iléon le rejoint ; l'appendice y est attaché.","tr":"İleumun katıldığı büyük bağırsağın kese benzeri başlangıcı; apendiks buna bağlıdır.","nl":"Het zakachtige begin van de dikke darm waar het ileum aansluit; de appendix is hieraan bevestigd.","ru":"Мешкообразное начало толстой кишки, где к ней присоединяется подвздошная кишка; к ней прикрепляется червеобразный отросток (аппендикс).","zh":"大肠起始处的袋状结构，是回肠汇入处；阑尾附着于此。","pt_BR":"O início em forma de bolsa do intestino grosso onde o íleo se une; o apêndice está ligado a ele.","pt_PT":"O início em forma de bolsa do intestino grosso onde o íleo se une; o apêndice está ligado a este."}},
  { id: 'dc-anatomy-0139', deck_id: 'deck-anatomy', front: 'Sigmoid Colon', back: 'The S-shaped final portion of the colon before the rectum; it holds feces prior to defecation.', sort_order: 139 , front_translations: {"es":"Colo sigmoide","de":"Sigmoid (Sigmoideum)","fr":"Côlon sigmoïde","tr":"Sigmoid Kolon","nl":"Sigmakolon (colon sigmoideum)","ru":"Сигмовидная кишка","zh":"乙状结肠","pt_BR":"Colo sigmoide","pt_PT":"Cólon sigmoide"}, back_translations: {"es":"La porción final en forma de S del cólon antes del reto; retém fezes antes de la defecación.","de":"Der S-förmige letzte Teil des Dickdarms vor dem Rektum; er hält Kot vor der Defäkation zurück.","fr":"La partie finale en forme de S du côlon avant le rectum ; elle retient les selles avant la défécation.","tr":"Rektumdan önce kolonun S şekilli son kısmı; dışkılamadan önce dışkıyı tutar.","nl":"Het S-vormige laatste deel van de dikke darm vóór het rectum; het houdt feces vast vóór defecatie.","ru":"S-образный конечный отдел ободочной кишки перед прямой кишкой; удерживает каловые массы до дефекации.","zh":"直肠前方结肠的S形末端部分；在排便前储存粪便。","pt_BR":"A porção final em forma de S do cólon antes do reto; retém fezes antes da defecação.","pt_PT":"A porção final em forma de S do cólon antes do reto; retém fezes antes da defecação."}},
  { id: 'dc-anatomy-0140', deck_id: 'deck-anatomy', front: 'Rectum', back: 'The final 15 cm of the large intestine; it stores feces until elimination through the anal canal.', sort_order: 140 , front_translations: {"es":"Reto","de":"Mastdarm (Rektum)","fr":"Rectum","tr":"Rektum (Düz Bağırsak)","nl":"Endeldarm (rectum)","ru":"Прямая кишка (ректум)","zh":"直肠","pt_BR":"Reto","pt_PT":"Reto"}, back_translations: {"es":"Los últimos 15 cm del intestino grueso; almacena fezes hasta a eliminación por el canal anal.","de":"Die letzten 15 cm des Dickdarms; er speichert Kot bis zur Ausscheidung durch den Analkanal.","fr":"Les 15 derniers centimètres du gros intestin ; il stocke les selles jusqu'à leur élimination par le canal anal.","tr":"Büyük bağırsağın son 15 cm'si; dışkıyı anal kanal yoluyla atılana kadar depolar.","nl":"De laatste 15 cm van de dikke darm; het slaat feces op tot uitscheiding via het anaalkanaal.","ru":"Последние 15 см толстой кишки; накапливает каловые массы до их выведения через анальный канал.","zh":"大肠最后15厘米；储存粪便直至通过肛管排出。","pt_BR":"Os últimos 15 cm do intestino grosso; armazena fezes até a eliminação pelo canal anal.","pt_PT":"Os últimos 15 cm do intestino grosso; armazena fezes até à eliminação pelo canal anal."}},
  { id: 'dc-anatomy-0141', deck_id: 'deck-anatomy', front: 'Urinary Bladder', back: 'A muscular sac in the pelvis that stores urine produced by the kidneys until it is expelled through the urethra.', sort_order: 141 , front_translations: {"es":"Bexiga urinária","de":"Harnblase","fr":"Vessie urinaire","tr":"İdrar Kesesi (Mesane)","nl":"Urineblaas","ru":"Мочевой пузырь","zh":"膀胱","pt_BR":"Bexiga urinária","pt_PT":"Bexiga urinária"}, back_translations: {"es":"Un saco muscular en la pelve que almacena urina producida por los riñones hasta ser expelida por la uretra.","de":"Ein Muskelsack im Becken, der den von den Nieren produzierten Urin speichert, bis er durch die Harnröhre ausgeschieden wird.","fr":"Un sac musculaire situé dans le pelvis qui stocke l'urine produite par les reins jusqu'à son expulsion par l'urètre.","tr":"Böbreklerin ürettiği idrarı üretra yoluyla dışarı atılana kadar depolayan, pelviste bulunan kassal kese.","nl":"Een gespierde zak in het bekken die urine opslaat die door de nieren is geproduceerd totdat het via de urethra wordt uitgescheiden.","ru":"Мышечный мешок в полости малого таза, накапливающий мочу, вырабатываемую почками, до её выведения через мочеиспускательный канал.","zh":"位于骨盆内的肌性囊，储存肾脏产生的尿液，直至通过尿道排出。","pt_BR":"Um saco muscular na pelve que armazena urina produzida pelos rins até ser expelida pela uretra.","pt_PT":"Um saco muscular na bacia que armazena a urina produzida pelos rins até ser expelida pela uretra."}},
  { id: 'dc-anatomy-0142', deck_id: 'deck-anatomy', front: 'Urethra', back: 'The tube that conveys urine from the bladder to the outside; in males it also carries semen and is longer than in females.', sort_order: 142 , front_translations: {"es":"Uretra","de":"Harnröhre (Urethra)","fr":"Urètre","tr":"Üretra","nl":"Urinebuis (urethra)","ru":"Мочеиспускательный канал (уретра)","zh":"尿道","pt_BR":"Uretra","pt_PT":"Uretra"}, back_translations: {"es":"El tubo que conduce a urina de la bexiga para el exterior; en los hombres también transporta semen y es más ancho del que en las mujeres.","de":"Der Kanal, der Urin von der Blase nach außen leitet; beim Mann leitet er auch Sperma und ist länger als bei der Frau.","fr":"Le tube qui conduit l'urine de la vessie vers l'extérieur ; chez l'homme, il transporte également le sperme et est plus long que chez la femme.","tr":"İdrarı mesaneden dışarıya taşıyan tüp; erkeklerde aynı zamanda semen taşır ve kadınlardakinden daha uzundur.","nl":"De buis die urine van de blaas naar buiten vervoert; bij mannen vervoert het ook semen en is het langer dan bij vrouwen.","ru":"Трубка, выводящая мочу из мочевого пузыря наружу; у мужчин также проводит семенную жидкость и длиннее, чем у женщин.","zh":"将尿液从膀胱输送到体外的管道；男性尿道还负责输送精液，且比女性尿道长。","pt_BR":"O tubo que conduz a urina da bexiga para o exterior; nos homens também transporta sêmen e é mais longo do que nas mulheres.","pt_PT":"O tubo que conduz a urina da bexiga para o exterior; nos homens também transporta sémen e é mais longo do que nas mulheres."}},
  { id: 'dc-anatomy-0143', deck_id: 'deck-anatomy', front: 'Ovaries', back: 'The female gonads that produce eggs (ova) and secrete the hormones estrogen and progesterone.', sort_order: 143 , front_translations: {"es":"Ovários","de":"Eierstöcke (Ovarien)","fr":"Ovaires","tr":"Yumurtalıklar (Overler)","nl":"Eierstokken (ovaria)","ru":"Яичники","zh":"卵巢","pt_BR":"Ovários","pt_PT":"Ovários"}, back_translations: {"es":"As gonadas femininas que producen ovos (óvulos) y secretam los hormonas estrogenio y progesterona.","de":"Die weiblichen Keimdrüsen, die Eizellen (Ova) produzieren und die Hormone Östrogen und Progesteron ausschütten.","fr":"Les gonades féminines qui produisent des ovules et sécrètent les hormones œstrogène et progestérone.","tr":"Yumurta (ovum) üreten ve östrojen ile progesteron hormonlarını salgılayan dişi gonadlar.","nl":"De vrouwelijke geslachtsklieren die eicellen (ova) produceren en de hormonen oestrogeen en progesteron afscheiden.","ru":"Женские половые железы, вырабатывающие яйцеклетки (ова) и секретирующие гормоны эстроген и прогестерон.","zh":"产生卵子（卵细胞）并分泌雌激素和孕激素的女性性腺。","pt_BR":"As gônadas femininas que produzem ovos (óvulos) e secretam os hormônios estrogênio e progesterona.","pt_PT":"As gónadas femininas que produzem óvulos e secretam as hormonas estrogénio e progesterona."}},
  { id: 'dc-anatomy-0144', deck_id: 'deck-anatomy', front: 'Fallopian Tubes', back: 'Two muscular tubes connecting the ovaries to the uterus; they transport the ovum from the ovary and are the usual site of fertilization.', sort_order: 144 , front_translations: {"es":"Tubas uterinas (trompas de Falópio)","de":"Eileiter (Tuben)","fr":"Trompes de Fallope","tr":"Fallop Tüpleri","nl":"Eileiders (tubae uterinae)","ru":"Маточные трубы (фаллопиевы трубы)","zh":"输卵管","pt_BR":"Tubas uterinas (trompas de Falópio)","pt_PT":"Trompas de Falópio"}, back_translations: {"es":"Dos tubos musculares que conectan los ovários al útero; transportan el óvulo del ovário y son el local usual de fertilización.","de":"Zwei Muskelröhren, die die Eierstöcke mit der Gebärmutter verbinden; sie transportieren die Eizelle vom Eierstock und sind der übliche Ort der Befruchtung.","fr":"Deux tubes musculaires reliant les ovaires à l'utérus ; ils transportent l'ovule depuis l'ovaire et sont le site habituel de la fécondation.","tr":"Yumurtalıkları rahme bağlayan iki kassal tüp; yumurtayı yumurtalıktan taşır ve genellikle döllenme yeridir.","nl":"Twee gespierde buizen die de eierstokken met de baarmoeder verbinden; ze vervoeren de eicel van de eierstok en zijn de gebruikelijke plaats van bevruchting.","ru":"Две мышечные трубки, соединяющие яичники с маткой; транспортируют яйцеклетку от яичника и являются обычным местом оплодотворения.","zh":"连接卵巢与子宫的两条肌性管道；将卵子从卵巢输送至子宫，通常也是受精的发生部位。","pt_BR":"Dois tubos musculares que conectam os ovários ao útero; transportam o óvulo do ovário e são o local usual de fertilização.","pt_PT":"Dois tubos musculares que ligam os ovários ao útero; transportam o óvulo do ovário e são o local habitual de fertilização."}},
  { id: 'dc-anatomy-0145', deck_id: 'deck-anatomy', front: 'Uterus', back: 'The hollow muscular organ in the female pelvis where a fertilized egg implants and develops into a fetus during pregnancy.', sort_order: 145 , front_translations: {"es":"Útero","de":"Gebärmutter (Uterus)","fr":"Utérus","tr":"Rahim (Uterus)","nl":"Baarmoeder (uterus)","ru":"Матка (утерус)","zh":"子宫","pt_BR":"Útero","pt_PT":"Útero"}, back_translations: {"es":"El órgano muscular oco en la pelve feminina donde un ovo fertilizado se implanta y se desenvolve en feto durante a gravidez.","de":"Das hohle Muskelorgan im weiblichen Becken, in dem sich eine befruchtete Eizelle einnistet und sich während der Schwangerschaft zu einem Fötus entwickelt.","fr":"L'organe musculaire creux du bassin féminin où un œuf fécondé s'implante et se développe en fœtus pendant la grossesse.","tr":"Döllenmiş yumurtanın yerleştiği ve gebelik süresince fetüse geliştiği kadın pelvisindeki içi boş kassal organ.","nl":"Het holle gespierde orgaan in het vrouwelijke bekken waar een bevruchte eicel inplenteert en zich ontwikkelt tot een foetus tijdens de zwangerschap.","ru":"Полый мышечный орган в женском тазу, где оплодотворённая яйцеклетка имплантируется и развивается в плод во время беременности.","zh":"女性骨盆内的空心肌性器官，受精卵在此着床并在妊娠期间发育为胎儿。","pt_BR":"O órgão muscular oco na pelve feminina onde um ovo fertilizado se implanta e se desenvolve em feto durante a gravidez.","pt_PT":"O órgão muscular oco na bacia feminina onde um óvulo fertilizado se implanta e se desenvolve num feto durante a gravidez."}},
  { id: 'dc-anatomy-0146', deck_id: 'deck-anatomy', front: 'Testes', back: 'The male gonads in the scrotum that produce sperm and secrete testosterone.', sort_order: 146 , front_translations: {"es":"Testículos","de":"Hoden (Testes)","fr":"Testicules","tr":"Testisler","nl":"Teelballen (testes)","ru":"Яички (тестикулы)","zh":"睾丸","pt_BR":"Testículos","pt_PT":"Testículos"}, back_translations: {"es":"As gonadas masculinas en el escroto que producen espermatozoides y secretam testosterona.","de":"Die männlichen Keimdrüsen im Hodensack, die Spermien produzieren und Testosteron ausschütten.","fr":"Les gonades masculines situées dans le scrotum qui produisent des spermatozoïdes et sécrètent la testostérone.","tr":"Skrotumda sperm üreten ve testosteron salgılayan erkek gonadlar.","nl":"De mannelijke geslachtsklieren in het scrotum die sperma produceren en testosteron afscheiden.","ru":"Мужские половые железы в мошонке, вырабатывающие сперматозоиды и секретирующие тестостерон.","zh":"位于阴囊中的男性性腺，负责产生精子并分泌睾酮。","pt_BR":"As gônadas masculinas no escroto que produzem espermatozoides e secretam testosterona.","pt_PT":"As gónadas masculinas no escroto que produzem espermatozoides e secretam testosterona."}},
  { id: 'dc-anatomy-0147', deck_id: 'deck-anatomy', front: 'Prostate Gland', back: 'A walnut-sized gland in males that surrounds the urethra and produces fluid that nourishes and transports sperm.', sort_order: 147 , front_translations: {"es":"Glándula prostática","de":"Prostata (Vorsteherdrüse)","fr":"Glande prostatique","tr":"Prostat Bezi","nl":"Prostaat (prostaaklier)","ru":"Предстательная железа (простата)","zh":"前列腺","pt_BR":"Glândula prostática","pt_PT":"Glândula prostática"}, back_translations: {"es":"Una glándula del tamaño de una noz en los hombres que involucra a uretra y produce fluido que nutre y transporta los espermatozoides.","de":"Eine walnussgroße Drüse beim Mann, die die Harnröhre umgibt und eine Flüssigkeit produziert, die Spermien nährt und transportiert.","fr":"Une glande de la taille d'une noix chez l'homme qui entoure l'urètre et produit un liquide qui nourrit et transporte les spermatozoïdes.","tr":"Üretrayı çevreleyen ve spermi besleyen ve taşıyan sıvı üreten, erkeklerde ceviz büyüklüğünde bez.","nl":"Een walnootgrote klier bij mannen die de urethra omringt en vocht produceert dat sperma voedt en transporteert.","ru":"Железа размером с грецкий орех у мужчин, окружающая мочеиспускательный канал и вырабатывающая жидкость, питающую и транспортирующую сперматозоиды.","zh":"男性体内包绕尿道的栗子大小的腺体，产生滋养和输送精子的液体。","pt_BR":"Uma glândula do tamanho de uma noz nos homens que envolve a uretra e produz fluido que nutre e transporta os espermatozoides.","pt_PT":"Uma glândula do tamanho de uma noz nos homens que envolve a uretra e produz fluido que nutre e transporta os espermatozoides."}},
  { id: 'dc-anatomy-0148', deck_id: 'deck-anatomy', front: 'Skin (Integument)', back: 'The body\'s largest organ; it protects against pathogens and physical injury, regulates temperature, senses stimuli, and synthesizes vitamin D.', sort_order: 148 , front_translations: {"es":"Piel (tegumento)","de":"Haut (Integument)","fr":"Peau (tégument)","tr":"Deri (İntegüman)","nl":"Huid (integument)","ru":"Кожа (интегумент)","zh":"皮肤（体被）","pt_BR":"Pele (tegumento)","pt_PT":"Pele (tegumento)"}, back_translations: {"es":"El mayor órgano del cuerpo; protege contra patógenos y lesões físicas, regula a temperatura, percebe estímulos y sintetiza vitamina D.","de":"Das größte Organ des Körpers; es schützt vor Krankheitserregern und physischen Verletzungen, reguliert die Temperatur, empfängt Reize und synthetisiert Vitamin D.","fr":"Le plus grand organe du corps ; il protège contre les agents pathogènes et les blessures physiques, régule la température, perçoit les stimuli et synthétise la vitamine D.","tr":"Vücudun en büyük organı; patojenlere ve fiziksel yaralanmalara karşı korur, sıcaklığı düzenler, uyarıları algılar ve D vitamini sentezler.","nl":"Het grootste orgaan van het lichaam; het beschermt tegen pathogenen en lichamelijk letsel, reguleert de temperatuur, ervaart prikkels en synthetiseert vitamine D.","ru":"Самый большой орган тела; защищает от патогенов и физических повреждений, регулирует температуру, воспринимает раздражители и синтезирует витамин D.","zh":"人体最大的器官；抵御病原体和物理损伤，调节体温，感知刺激，并合成维生素D。","pt_BR":"O maior órgão do corpo; protege contra patógenos e lesões físicas, regula a temperatura, percebe estímulos e sintetiza vitamina D.","pt_PT":"O maior órgão do corpo; protege contra agentes patogénicos e lesões físicas, regula a temperatura, perceciona estímulos e sintetiza vitamina D."}},
  { id: 'dc-anatomy-0149', deck_id: 'deck-anatomy', front: 'Dermis', back: 'The middle layer of skin beneath the epidermis; it contains collagen, hair follicles, sweat glands, blood vessels, and nerve endings.', sort_order: 149 , front_translations: {"es":"Derme","de":"Dermis (Lederhaut)","fr":"Derme","tr":"Dermis","nl":"Lederhuid (dermis)","ru":"Дерма","zh":"真皮","pt_BR":"Derme","pt_PT":"Derme"}, back_translations: {"es":"La capa intermediária de la piel debajo de la epiderme; contiene colágeno, folículos pilosos, glándulas sudoríparas, vasos sanguíneos y terminaciones nervosas.","de":"Die mittlere Hautschicht unter der Epidermis; sie enthält Kollagen, Haarfollikel, Schweißdrüsen, Blutgefäße und Nervenenden.","fr":"La couche intermédiaire de la peau sous l'épiderme ; elle contient du collagène, des follicules pileux, des glandes sudoripares, des vaisseaux sanguins et des terminaisons nerveuses.","tr":"Epidermistin altında derinin orta katmanı; kolajen, saç folikülleri, ter bezleri, kan damarları ve sinir uçları içerir.","nl":"De middelste laag huid onder de epidermis; het bevat collageen, haarfollikels, zweetklieren, bloedvaten en zenuwuiteinden.","ru":"Средний слой кожи под эпидермисом; содержит коллаген, волосяные фолликулы, потовые железы, кровеносные сосуды и нервные окончания.","zh":"位于表皮下方的皮肤中间层；含有胶原蛋白、毛囊、汗腺、血管和神经末梢。","pt_BR":"A camada intermediária da pele abaixo da epiderme; contém colágeno, folículos pilosos, glândulas sudoríparas, vasos sanguíneos e terminações nervosas.","pt_PT":"A camada intermédia da pele abaixo da epiderme; contém colagénio, folículos pilosos, glândulas sudoríparas, vasos sanguíneos e terminações nervosas."}},
  { id: 'dc-anatomy-0150', deck_id: 'deck-anatomy', front: 'Epidermis', back: 'The outermost layer of skin composed mainly of keratinocytes; it forms a waterproof barrier and contains melanocytes that produce pigment.', sort_order: 150 , front_translations: {"es":"Epiderme","de":"Epidermis (Oberhaut)","fr":"Épiderme","tr":"Epidermis (Üst Deri)","nl":"Opperhuid (epidermis)","ru":"Эпидермис","zh":"表皮","pt_BR":"Epiderme","pt_PT":"Epiderme"}, back_translations: {"es":"La capa más externa de la piel compuesta principalmente por queratinócitos; forma una barrera impermeable y contiene melanócitos que producen pigmento.","de":"Die äußerste Hautschicht, die hauptsächlich aus Keratinozyten besteht; sie bildet eine wasserabweisende Barriere und enthält Melanozyten, die Pigment produzieren.","fr":"La couche la plus externe de la peau composée principalement de kératinocytes ; elle forme une barrière imperméable et contient des mélanocytes qui produisent le pigment.","tr":"Ağırlıklı olarak keratinosytlerden oluşan derinin en dış tabakası; su geçirmez bir bariyer oluşturur ve pigment üreten melanositler içerir.","nl":"De buitenste laag huid die voornamelijk bestaat uit keratinocyten; het vormt een waterdichte barrière en bevat melanocyten die pigment produceren.","ru":"Самый наружный слой кожи, состоящий преимущественно из кератиноцитов; образует водонепроницаемый барьер и содержит меланоциты, вырабатывающие пигмент.","zh":"皮肤最外层，主要由角质形成细胞构成；形成防水屏障，含有产生色素的黑色素细胞。","pt_BR":"A camada mais externa da pele composta principalmente por queratinócitos; forma uma barreira impermeável e contém melanócitos que produzem pigmento.","pt_PT":"A camada mais externa da pele composta principalmente por queratinócitos; forma uma barreira impermeável e contém melanócitos que produzem pigmento."}},
];
